function scheduler_is_internal_mechanic_job(string $jobKey): bool
{
    $normalizedKey = trim(strtolower($jobKey));
    if ($normalizedKey === '') {
        return false;
    }

    if (in_array($normalizedKey, scheduler_internal_mechanic_job_keys(), true)) {
        return true;
    }

    foreach (['db_sync_schedule_', 'scheduler_', 'sync_runner_'] as $prefix) {
        if (str_starts_with($normalizedKey, $prefix)) {
            return true;
        }
    }

    foreach (['_claim_', '_ensure_', '_dispatch_', '_execute_', '_dataset_key_', '_backfill_start_', '_should_defer_', '_defer_'] as $needle) {
        if (str_contains($normalizedKey, $needle)) {
            return true;
        }
    }

    return false;
}

function scheduler_is_protected_job(string $jobKey): bool
{
    return in_array(trim($jobKey), scheduler_protected_job_keys(), true);
}

function scheduler_reserved_protected_offsets(int $offsetHorizonMinutes = 60, ?string $excludeJobKey = null): array
{
    $reserved = [];
    $horizon = max(1, min(1440, $offsetHorizonMinutes));

    foreach (scheduler_registry_definitions() as $jobKey => $definition) {
        if (!scheduler_is_protected_job($jobKey) || $jobKey === $excludeJobKey) {
            continue;
        }

        $offset = max(0, (int) ($definition['default_offset_minutes'] ?? 0)) % $horizon;
        $reserved[$offset] = true;
    }

    ksort($reserved);

    return array_map('intval', array_keys($reserved));
}

function scheduler_discovery_offset_horizon_minutes(): int
{
    return 60;
}

function scheduler_offset_load_map(int $offsetHorizonMinutes = 60, array $options = []): array
{
    $horizon = max(1, min(1440, $offsetHorizonMinutes));
    $counts = array_fill(0, $horizon, 0);
    $excludeJobKey = trim((string) ($options['exclude_job_key'] ?? ''));
    $rows = $options['rows'] ?? null;
    if (!is_array($rows)) {
        try {
            $rows = db_sync_schedule_fetch_all();
        } catch (Throwable) {
            $rows = [];
        }
    }

    foreach ($rows as $row) {
        $jobKey = trim((string) ($row['job_key'] ?? ''));
        if ($jobKey === '' || $jobKey === $excludeJobKey) {
            continue;
        }

        $offset = max(0, (int) ($row['offset_minutes'] ?? 0)) % $horizon;
        $counts[$offset] = (int) ($counts[$offset] ?? 0) + 1;
    }

    $reserveProtectedOffsets = !array_key_exists('reserve_protected_offsets', $options) || !empty($options['reserve_protected_offsets']);
    if ($reserveProtectedOffsets) {
        $reserveWeight = max(1, (int) ($options['reserved_weight'] ?? 3));
        foreach (scheduler_reserved_protected_offsets($horizon, $excludeJobKey) as $offset) {
            $counts[$offset] = (int) ($counts[$offset] ?? 0) + $reserveWeight;
        }
    }

    return $counts;
}

function scheduler_least_congested_offset_minutes(int $offsetHorizonMinutes = 60, array $options = []): int
{
    $counts = scheduler_offset_load_map($offsetHorizonMinutes, $options);
    $reservedOffsets = [];
    if (!empty($options['avoid_protected_offsets'])) {
        foreach (scheduler_reserved_protected_offsets(count($counts), trim((string) ($options['exclude_job_key'] ?? ''))) as $offset) {
            $reservedOffsets[$offset] = true;
        }
    }

    $bestOffset = 0;
    $bestScore = null;

    foreach ($counts as $offset => $count) {
        $score = [
            isset($reservedOffsets[$offset]) ? 1 : 0,
            (int) $count,
            (int) $offset,
        ];
        if ($bestScore === null || $score < $bestScore) {
            $bestScore = $score;
            $bestOffset = (int) $offset;
        }
    }

    return $bestOffset;
}

function scheduler_extract_php_function_names(string $contents): array
{
    $names = [];
    $tokens = token_get_all($contents);
    $tokenCount = count($tokens);

    for ($index = 0; $index < $tokenCount; $index++) {
        $token = $tokens[$index];
        if (!is_array($token) || $token[0] !== T_FUNCTION) {
            continue;
        }

        for ($lookahead = $index + 1; $lookahead < $tokenCount; $lookahead++) {
            $candidate = $tokens[$lookahead];
            if (is_array($candidate) && $candidate[0] === T_STRING) {
                $names[] = strtolower(trim((string) $candidate[1]));
                break;
            }

            if ($candidate === '(') {
                break;
            }
        }
    }

    return array_values(array_unique(array_filter($names, static fn (string $name): bool => $name !== '')));
}

function scheduler_pressure_label(array $summary): string
{
    $lockConflicts = (int) ($summary['lock_conflicts'] ?? 0);
    $lateJobs = (int) ($summary['late_jobs'] ?? 0);
    $degradedJobs = (int) ($summary['degraded_jobs'] ?? 0);
    $timeoutRate = (float) ($summary['timeout_rate'] ?? 0.0);
    $failureRate = (float) ($summary['failure_rate'] ?? 0.0);
    $cpuRatio = (float) ($summary['cpu_budget_ratio'] ?? 0.0);
    $memoryRatio = (float) ($summary['memory_budget_ratio'] ?? 0.0);

    if ($cpuRatio >= 1.0 || $memoryRatio >= 1.0 || $timeoutRate >= 0.25 || $failureRate >= 0.3 || $lockConflicts >= 6 || $lateJobs >= 6 || $degradedJobs >= 4) {
        return 'overload_protection';
    }

    if ($cpuRatio >= 0.82 || $memoryRatio >= 0.82 || $timeoutRate >= 0.12 || $failureRate >= 0.16 || $lockConflicts >= 4 || $lateJobs >= 4 || $degradedJobs >= 3) {
        return 'congested';
    }

    if ($cpuRatio >= 0.62 || $memoryRatio >= 0.62 || $lockConflicts >= 2 || $lateJobs >= 2 || $degradedJobs >= 1) {
        return 'busy';
    }

    return 'healthy';
}

function scheduler_metric_percentile(array $values, float $percentile): ?float
{
    $filtered = array_values(array_filter(array_map(static fn (mixed $value): float => (float) $value, $values), static fn (float $value): bool => $value >= 0.0));
    if ($filtered === []) {
        return null;
    }

    sort($filtered, SORT_NUMERIC);
    $index = (int) max(0, ceil(count($filtered) * $percentile) - 1);

    return (float) ($filtered[$index] ?? $filtered[count($filtered) - 1]);
}

function scheduler_format_bytes(?int $bytes): string
{
    if ($bytes === null || $bytes <= 0) {
        return '—';
    }

    $units = ['B', 'KB', 'MB', 'GB', 'TB'];
    $value = (float) $bytes;
    $index = 0;
    while ($value >= 1024 && $index < count($units) - 1) {
        $value /= 1024;
        $index++;
    }

    return number_format($value, $index === 0 ? 0 : 1, '.', ',') . ' ' . $units[$index];
}

function scheduler_parse_memory_limit_bytes(string $value): ?int
{
    $normalized = trim(strtolower($value));
    if ($normalized === '' || $normalized === '-1') {
        return null;
    }

    if (!preg_match('/^([0-9]+)([kmgt]?)/', $normalized, $matches)) {
        return null;
    }

    $amount = (int) ($matches[1] ?? 0);
    $suffix = (string) ($matches[2] ?? '');
    $multiplier = match ($suffix) {
        'g' => 1024 ** 3,
        'm' => 1024 ** 2,
        'k' => 1024,
        't' => 1024 ** 4,
        default => 1,
    };

    return $amount > 0 ? $amount * $multiplier : null;
}

function scheduler_cpu_core_count(): int
{
    static $cached = null;
    if ($cached !== null) {
        return $cached;
    }

    $configured = (int) config('scheduler.cpu_core_count', (int) getenv('SCHEDULER_CPU_CORE_COUNT'));
    if ($configured > 0) {
        $cached = $configured;
        return $cached;
    }

    $detected = trim((string) @shell_exec('getconf _NPROCESSORS_ONLN 2>/dev/null'));
    $cached = max(1, (int) $detected);

    return $cached;
}

function scheduler_capacity_model(): array
{
    static $cached = null;
    if (is_array($cached)) {
        return $cached;
    }

    $cores = scheduler_cpu_core_count();
    $profile = scheduler_operational_profile_matrix(scheduler_selected_operational_profile());
    $runtimeProfile = (array) ($profile['runtime'] ?? []);
    $memoryLimit = scheduler_parse_memory_limit_bytes((string) ini_get('memory_limit'));
    $cpuBudget = (float) config('scheduler.cpu_budget_percent', (float) getenv('SCHEDULER_CPU_BUDGET_PERCENT'));
    if ($cpuBudget <= 0) {
        $profileCpuBudget = (float) ($runtimeProfile['cpu_budget_percent'] ?? 0.0);
        $cpuBudget = $profileCpuBudget > 0 ? $profileCpuBudget : min(400.0, max(100.0, $cores * 70.0));
    }
    $memoryBudget = (int) config('scheduler.memory_budget_bytes', (int) getenv('SCHEDULER_MEMORY_BUDGET_BYTES'));
    if ($memoryBudget <= 0) {
        $memoryFraction = (float) ($runtimeProfile['memory_budget_fraction'] ?? 0.6);
        $memoryBudget = $memoryLimit !== null ? (int) round($memoryLimit * min(0.85, max(0.30, $memoryFraction))) : (512 * 1024 * 1024);
    }
    $maxConcurrent = (int) config('scheduler.max_concurrent_jobs', (int) getenv('SCHEDULER_MAX_CONCURRENT_JOBS'));
    if ($maxConcurrent <= 0) {
        $profileConcurrent = (int) ($runtimeProfile['max_concurrent_jobs'] ?? 0);
        $maxConcurrent = $profileConcurrent > 0 ? $profileConcurrent : max(1, min(6, $cores + 1));
    }

    $reservedCpu = (float) config('scheduler.reserved_critical_cpu_percent', (float) getenv('SCHEDULER_RESERVED_CRITICAL_CPU_PERCENT'));
    if ($reservedCpu <= 0) {
        $reservedCpu = min(120.0, max(35.0, $cpuBudget * 0.22));
    }
    $reservedMemory = (int) config('scheduler.reserved_critical_memory_bytes', (int) getenv('SCHEDULER_RESERVED_CRITICAL_MEMORY_BYTES'));
    if ($reservedMemory <= 0) {
        $reservedMemory = max(64 * 1024 * 1024, (int) round($memoryBudget * 0.18));
    }

    $cached = [
        'cpu_budget_percent' => round($cpuBudget, 2),
        'memory_budget_bytes' => $memoryBudget,
        'max_concurrent_jobs' => $maxConcurrent,
        'reserved_critical_cpu_percent' => round($reservedCpu, 2),
        'reserved_critical_memory_bytes' => $reservedMemory,
        'detected_cpu_cores' => $cores,
        'memory_limit_bytes' => $memoryLimit,
    ];

    return $cached;
}

function scheduler_priority_rank(string $priority): int
{
    return match ($priority) {
        'highest' => 4,
        'high' => 3,
        'medium' => 2,
        default => 1,
    };
}

function scheduler_latest_allowed_start_at(array $job): ?string
{
    $existing = trim((string) ($job['latest_allowed_start_at'] ?? ''));
    if ($existing !== '') {
        return $existing;
    }

    $nextDueAt = trim((string) ($job['next_due_at'] ?? $job['next_run_at'] ?? ''));
    if ($nextDueAt === '') {
        return null;
    }

    $intervalMinutes = max(1, (int) ($job['interval_minutes'] ?? 5));
    return gmdate('Y-m-d H:i:s', strtotime($nextDueAt) + ($intervalMinutes * 60));
}

function scheduler_resource_usage_snapshot(): array
{
    $usage = function_exists('getrusage') ? @getrusage() : null;

    return [
        'usage' => is_array($usage) ? $usage : [],
        'memory_usage' => function_exists('memory_get_usage') ? memory_get_usage(true) : null,
        'memory_peak_usage' => function_exists('memory_get_peak_usage') ? memory_get_peak_usage(true) : null,
        'wall_time' => microtime(true),
    ];
}

function scheduler_php_memory_limit(): string
{
    return '512M';
}

function scheduler_memory_abort_threshold_bytes(): int
{
    return 400 * 1024 * 1024;
}

function scheduler_enforce_php_runtime_limits(): void
{
    if (function_exists('ini_set')) {
        @ini_set('memory_limit', scheduler_php_memory_limit());
    }

    if (function_exists('gc_enable')) {
        @gc_enable();
    }
}

function scheduler_runtime_guard(float $startedAtUnix, int $timeoutSeconds, string $context = ''): void
{
    $safeTimeout = max(1, $timeoutSeconds);
    $memoryUsage = function_exists('memory_get_usage') ? (int) memory_get_usage(true) : 0;
    $memoryPeak = function_exists('memory_get_peak_usage') ? (int) memory_get_peak_usage(true) : $memoryUsage;
    $threshold = scheduler_memory_abort_threshold_bytes();
    $elapsed = max(0.0, microtime(true) - $startedAtUnix);

    if ($memoryUsage > $threshold || $memoryPeak > $threshold) {
        throw new RuntimeException(sprintf(
            'Job exceeded scheduler memory guard%s (usage=%d bytes, peak=%d bytes, threshold=%d bytes).',
            $context !== '' ? ' during ' . $context : '',
            $memoryUsage,
            $memoryPeak,
            $threshold
        ));
    }

    if ($elapsed > $safeTimeout) {
        throw new RuntimeException(sprintf(
            'Job exceeded scheduler timeout guard%s (elapsed=%.2fs, timeout=%ds).',
            $context !== '' ? ' during ' . $context : '',
            $elapsed,
            $safeTimeout
        ));
    }
}

function scheduler_python_heavy_jobs_enabled(): bool
{
    return (bool) config('scheduler.python_heavy_jobs_enabled', true);
}

function scheduler_python_php_fallback_enabled(): bool
{
    return (bool) config('scheduler.python_php_fallback_enabled', true);
}

function scheduler_job_execution_mode(array $job, ?array $definition = null): string
{
    $resolvedDefinition = is_array($definition) ? $definition : (scheduler_registry_definitions()[(string) ($job['job_key'] ?? '')] ?? []);
    $configured = strtolower(trim((string) ($job['execution_mode'] ?? $resolvedDefinition['execution_mode'] ?? 'php')));

    if ($configured === 'python' && !scheduler_python_heavy_jobs_enabled()) {
        return 'php';
    }

    return $configured === 'python' ? 'python' : 'php';
}

function scheduler_job_workload_profile(string $jobKey): array
{
    $definition = scheduler_registry_definitions()[$jobKey] ?? [];
    $class = (string) ($definition['workload_class'] ?? 'lightweight');

    $reason = match ($jobKey) {
        'market_comparison_summary_sync' => 'heavy market aggregation over large current-order projections; prefer SQL plus Python batch execution',
        'current_state_refresh_sync' => 'heavy snapshot generation that assembles multiple materialized summary layers',
        'market_hub_local_history_sync', 'alliance_historical_sync', 'market_hub_historical_sync' => 'heavy snapshot/history rebuild over large market windows; prefer batched execution outside PHP request memory',
        'killmail_r2z2_sync', 'activity_priority_summary_sync' => 'heavy killmail ingestion and derived activity recomputation with large append-only tables',
        default => 'lightweight control-plane or summary job that is safe to keep in PHP',
    };

    return [
        'workload_class' => $class === 'heavy' ? 'heavy' : 'lightweight',
        'recommended_execution_mode' => $class === 'heavy' ? 'python' : 'php',
        'reason' => $reason,
    ];
}

function scheduler_resource_usage_delta_seconds(array $usage, string $prefix): float
{
    $sec = (float) ($usage[$prefix . '.tv_sec'] ?? 0.0);
    $usec = (float) ($usage[$prefix . '.tv_usec'] ?? 0.0);

    return $sec + ($usec / 1000000);
}

function scheduler_resource_usage_delta(array $started, array $finished): array
{
    $startUsage = is_array($started['usage'] ?? null) ? $started['usage'] : [];
    $endUsage = is_array($finished['usage'] ?? null) ? $finished['usage'] : [];
    $wallSeconds = max(0.001, (float) (($finished['wall_time'] ?? microtime(true)) - ($started['wall_time'] ?? microtime(true))));
    $cpuUser = max(0.0, scheduler_resource_usage_delta_seconds($endUsage, 'ru_utime') - scheduler_resource_usage_delta_seconds($startUsage, 'ru_utime'));
    $cpuSystem = max(0.0, scheduler_resource_usage_delta_seconds($endUsage, 'ru_stime') - scheduler_resource_usage_delta_seconds($startUsage, 'ru_stime'));
    $cpuPercent = (($cpuUser + $cpuSystem) / $wallSeconds) * 100.0;
    $startPeak = (int) ($started['memory_peak_usage'] ?? 0);
    $endPeak = (int) ($finished['memory_peak_usage'] ?? 0);
    $startMem = (int) ($started['memory_usage'] ?? 0);
    $endMem = (int) ($finished['memory_usage'] ?? 0);

    return [
        'wall_duration_seconds' => round($wallSeconds, 2),
        'cpu_user_seconds' => round($cpuUser, 4),
        'cpu_system_seconds' => round($cpuSystem, 4),
        'cpu_percent' => round($cpuPercent, 2),
        'memory_start_bytes' => $startMem,
        'memory_end_bytes' => $endMem,
        'memory_peak_bytes' => max($endPeak, $endMem, $startMem),
        'memory_peak_delta_bytes' => max(0, max($endPeak - $startPeak, $endMem - $startMem)),
    ];
}

function scheduler_job_safety_rules(): array
{
    return [
        'alliance_historical_sync' => ['must_run_alone' => true, 'forbidden_with' => ['alliance_current_sync', 'current_state_refresh_sync']],
        'market_hub_historical_sync' => ['must_run_alone' => true, 'forbidden_with' => ['market_hub_current_sync', 'deal_alerts_sync']],
        'market_hub_local_history_sync' => ['must_run_alone' => true, 'forbidden_with' => ['market_hub_current_sync', 'rebuild_ai_briefings']],
        'rebuild_ai_briefings' => ['forbidden_with' => scheduler_ai_briefing_blocking_job_keys()],
        'forecasting_ai_sync' => ['forbidden_with' => ['rebuild_ai_briefings']],
        'killmail_r2z2_sync' => ['allowed_groups' => ['light', 'medium']],
        'deal_alerts_sync' => ['allowed_groups' => ['light', 'medium', 'heavy']],
    ];
}

function scheduler_job_recent_resource_profile(string $jobKey, ?array $row = null): array
{
    $currentStatus = is_array($row['status_projection'] ?? null)
        ? $row['status_projection']
        : (db_scheduler_job_current_status_fetch_map([$jobKey])[$jobKey] ?? []);
    $currentSummary = is_array($currentStatus['last_resource_metrics_summary'] ?? null) ? $currentStatus['last_resource_metrics_summary'] : [];

    if ($currentSummary !== []) {
        $derivedProfile = [
            'sample_count' => max(0, (int) ($row['telemetry_sample_count'] ?? 0)),
            'learning_mode' => !empty($row['learning_mode']) || ((int) ($row['telemetry_sample_count'] ?? 0) < 3),
            'resource_class' => (string) ($row['resource_class'] ?? 'medium'),
            'resource_class_confidence' => isset($row['resource_class_confidence']) ? round((float) $row['resource_class_confidence'], 4) : 0.0,
            'average_cpu_percent' => isset($row['average_cpu_percent']) ? round((float) $row['average_cpu_percent'], 2) : null,
            'p95_cpu_percent' => isset($row['p95_cpu_percent']) ? round((float) $row['p95_cpu_percent'], 2) : null,
            'average_memory_peak_bytes' => isset($row['average_memory_peak_bytes']) ? (int) $row['average_memory_peak_bytes'] : null,
            'p95_memory_peak_bytes' => isset($row['p95_memory_peak_bytes']) ? (int) $row['p95_memory_peak_bytes'] : null,
            'average_duration_seconds' => isset($row['average_duration_seconds']) ? round((float) $row['average_duration_seconds'], 2) : null,
            'p95_duration_seconds' => isset($row['p95_duration_seconds']) ? round((float) $row['p95_duration_seconds'], 2) : null,
            'average_lock_wait_seconds' => isset($row['average_lock_wait_seconds']) ? round((float) $row['average_lock_wait_seconds'], 2) : null,
            'recent_failure_rate' => isset($row['recent_failure_rate']) ? round((float) $row['recent_failure_rate'], 4) : (!empty($currentSummary['failed']) ? 1.0 : 0.0),
            'recent_timeout_rate' => isset($row['recent_timeout_rate']) ? round((float) $row['recent_timeout_rate'], 4) : (!empty($currentSummary['timed_out']) ? 1.0 : 0.0),
            'last_cpu_percent' => isset($currentSummary['cpu_percent']) ? round((float) $currentSummary['cpu_percent'], 2) : null,
            'last_memory_peak_bytes' => isset($currentSummary['memory_peak_delta_bytes']) && $currentSummary['memory_peak_delta_bytes'] !== null
                ? (int) $currentSummary['memory_peak_delta_bytes']
                : (isset($currentSummary['memory_peak_bytes']) ? (int) $currentSummary['memory_peak_bytes'] : null),
            'last_queue_wait_seconds' => isset($currentSummary['queue_wait_seconds']) ? round((float) $currentSummary['queue_wait_seconds'], 2) : null,
            'last_lock_wait_seconds' => isset($currentSummary['lock_wait_seconds']) ? round((float) $currentSummary['lock_wait_seconds'], 2) : null,
            'last_overlap_count' => max(0, (int) ($currentSummary['overlap_count'] ?? 0)),
            'last_overlapped' => !empty($currentSummary['overlapped']),
            'allow_parallel' => !empty($row['allow_parallel']),
            'prefers_solo' => !empty($row['prefers_solo']),
            'must_run_alone' => !empty($row['must_run_alone']),
            'preferred_max_parallelism' => max(1, (int) ($row['preferred_max_parallelism'] ?? 1)),
            'projection_cpu_percent' => isset($currentSummary['projected_cpu_percent']) ? round((float) $currentSummary['projected_cpu_percent'], 2) : (isset($row['current_projected_cpu_percent']) ? round((float) $row['current_projected_cpu_percent'], 2) : null),
            'projection_memory_bytes' => isset($currentSummary['projected_memory_bytes']) ? (int) $currentSummary['projected_memory_bytes'] : (isset($row['current_projected_memory_bytes']) ? (int) $row['current_projected_memory_bytes'] : null),
            'allowed_groups' => array_values((array) (scheduler_job_safety_rules()[$jobKey]['allowed_groups'] ?? ['light', 'medium', 'heavy'])),
            'forbidden_with' => array_values(array_unique(array_filter((array) (scheduler_job_safety_rules()[$jobKey]['forbidden_with'] ?? [])))),
        ];

        return $derivedProfile;
    }

    $metrics = db_scheduler_resource_metrics_recent($jobKey, 40);
    $capacity = scheduler_capacity_model();
    $samples = count($metrics);
    $cpuValues = array_map(static fn (array $metric): float => (float) ($metric['cpu_percent'] ?? 0.0), $metrics);
    $memoryValues = array_map(static fn (array $metric): float => (float) ($metric['memory_peak_delta_bytes'] ?? $metric['memory_peak_bytes'] ?? 0.0), $metrics);
    $durationValues = array_map(static fn (array $metric): float => (float) ($metric['wall_duration_seconds'] ?? 0.0), $metrics);
    $lockWaitValues = array_map(static fn (array $metric): float => (float) ($metric['lock_wait_seconds'] ?? 0.0), $metrics);
    $failureCount = count(array_filter($metrics, static fn (array $metric): bool => !empty($metric['failed'])));
    $timeoutCount = count(array_filter($metrics, static fn (array $metric): bool => !empty($metric['timed_out'])));
    $lastMetric = $metrics[0] ?? [];

    $avgCpu = $samples > 0 ? array_sum($cpuValues) / $samples : null;
    $p95Cpu = scheduler_metric_percentile($cpuValues, 0.95);
    $avgMemory = $samples > 0 ? array_sum($memoryValues) / $samples : null;
    $p95Memory = scheduler_metric_percentile($memoryValues, 0.95);
    $avgDuration = $samples > 0 ? array_sum($durationValues) / $samples : null;
    $p95Duration = scheduler_metric_percentile($durationValues, 0.95);
    $avgLockWait = $samples > 0 ? array_sum($lockWaitValues) / $samples : null;
    $failureRate = $samples > 0 ? $failureCount / $samples : 0.0;
    $timeoutRate = $samples > 0 ? $timeoutCount / $samples : 0.0;
    $cpuRatio = $capacity['cpu_budget_percent'] > 0 ? (float) ($p95Cpu ?? $avgCpu ?? 45.0) / $capacity['cpu_budget_percent'] : 0.0;
    $memoryRatio = $capacity['memory_budget_bytes'] > 0 ? (float) ($p95Memory ?? $avgMemory ?? (128 * 1024 * 1024)) / $capacity['memory_budget_bytes'] : 0.0;
    $timeoutReference = max(60.0, (float) ($row['timeout_seconds'] ?? 300));
    $durationRatio = (float) ($p95Duration ?? $avgDuration ?? ($timeoutReference * 0.4)) / $timeoutReference;
    $lockRatio = min(1.0, (float) ($avgLockWait ?? 0.0) / 15.0);
    $pressureScore = ($cpuRatio * 0.35) + ($memoryRatio * 0.35) + ($durationRatio * 0.15) + ($timeoutRate * 0.1) + ($failureRate * 0.03) + ($lockRatio * 0.02);
    $derivedClass = $pressureScore >= 0.9 ? 'heavy' : ($pressureScore >= 0.45 ? 'medium' : 'light');
    $existingClass = trim((string) ($row['resource_class'] ?? ''));
    if ($samples < 3) {
        $derivedClass = 'medium';
    } elseif ($existingClass !== '' && in_array($existingClass, ['light', 'medium', 'heavy'], true) && abs($pressureScore - ($existingClass === 'heavy' ? 0.9 : ($existingClass === 'medium' ? 0.45 : 0.0))) < 0.08) {
        $derivedClass = $existingClass;
    }

    $rules = scheduler_job_safety_rules()[$jobKey] ?? [];
    $mustRunAlone = !empty($rules['must_run_alone']) || $derivedClass === 'heavy' || $cpuRatio >= 0.52 || $memoryRatio >= 0.52 || $timeoutRate >= 0.25;
    $prefersSolo = $mustRunAlone || $cpuRatio >= 0.38 || $memoryRatio >= 0.38 || $failureRate >= 0.18 || $lockRatio >= 0.4;
    $allowParallel = !$mustRunAlone && $failureRate < 0.45;
    $preferredMaxParallelism = $mustRunAlone ? 1 : ($derivedClass === 'light' ? 3 : 2);
    if ($prefersSolo && $preferredMaxParallelism > 2) {
        $preferredMaxParallelism = 2;
    }

    return [
        'sample_count' => $samples,
        'learning_mode' => $samples < 3,
        'resource_class' => $derivedClass,
        'resource_class_confidence' => round(min(1.0, $samples / 8), 4),
        'average_cpu_percent' => $avgCpu !== null ? round($avgCpu, 2) : null,
        'p95_cpu_percent' => $p95Cpu !== null ? round($p95Cpu, 2) : null,
        'average_memory_peak_bytes' => $avgMemory !== null ? (int) round($avgMemory) : null,
        'p95_memory_peak_bytes' => $p95Memory !== null ? (int) round($p95Memory) : null,
        'average_duration_seconds' => $avgDuration !== null ? round($avgDuration, 2) : null,
        'p95_duration_seconds' => $p95Duration !== null ? round($p95Duration, 2) : null,
        'average_lock_wait_seconds' => $avgLockWait !== null ? round($avgLockWait, 2) : null,
        'recent_failure_rate' => round($failureRate, 4),
        'recent_timeout_rate' => round($timeoutRate, 4),
        'last_cpu_percent' => isset($lastMetric['cpu_percent']) ? round((float) $lastMetric['cpu_percent'], 2) : null,
        'last_memory_peak_bytes' => isset($lastMetric['memory_peak_delta_bytes']) ? (int) $lastMetric['memory_peak_delta_bytes'] : (isset($lastMetric['memory_peak_bytes']) ? (int) $lastMetric['memory_peak_bytes'] : null),
        'last_queue_wait_seconds' => isset($lastMetric['queue_wait_seconds']) ? round((float) $lastMetric['queue_wait_seconds'], 2) : null,
        'last_lock_wait_seconds' => isset($lastMetric['lock_wait_seconds']) ? round((float) $lastMetric['lock_wait_seconds'], 2) : null,
        'last_overlap_count' => (int) ($lastMetric['overlap_count'] ?? 0),
        'last_overlapped' => !empty($lastMetric['overlapped']),
        'allow_parallel' => $allowParallel,
        'prefers_solo' => $prefersSolo,
        'must_run_alone' => $mustRunAlone,
        'preferred_max_parallelism' => $preferredMaxParallelism,
        'projection_cpu_percent' => round((float) ($p95Cpu ?? $avgCpu ?? 45.0) * ($samples < 3 ? 1.15 : 1.0) * (($failureRate > 0.1 || $timeoutRate > 0.1) ? 1.15 : 1.0), 2),
        'projection_memory_bytes' => (int) round((float) ($p95Memory ?? $avgMemory ?? (128 * 1024 * 1024)) * ($samples < 3 ? 1.2 : 1.0) * (($failureRate > 0.1 || $timeoutRate > 0.1) ? 1.15 : 1.0)),
        'allowed_groups' => (array) ($rules['allowed_groups'] ?? ['light', 'medium', 'heavy']),
        'forbidden_with' => array_values(array_unique(array_filter((array) ($rules['forbidden_with'] ?? [])))),
    ];
}

function scheduler_starvation_deferral_threshold(array $job): int
{
    if (!empty($job['latency_sensitive']) || scheduler_is_protected_job((string) ($job['job_key'] ?? ''))) {
        return 2;
    }

    return 4;
}

function scheduler_job_force_execution(array $job): bool
{
    $consecutiveDeferrals = (int) ($job['consecutive_deferrals'] ?? 0);
    if ($consecutiveDeferrals >= scheduler_starvation_deferral_threshold($job)) {
        return true;
    }

    if ((string) ($job['job_key'] ?? '') === 'deal_alerts_sync' && !deal_alert_has_successful_materialization()) {
        return true;
    }

    $latestAllowed = scheduler_latest_allowed_start_at($job);
    if ($latestAllowed !== null && strtotime($latestAllowed) !== false && strtotime($latestAllowed) <= time()) {
        return true;
    }

    return false;
}

function scheduler_job_urgency_snapshot(array $job, array $recentDecisionCounts = []): array
{
    $priority = (string) ($job['priority'] ?? 'normal');
    $scheduledFor = trim((string) ($job['next_due_at'] ?? $job['next_run_at'] ?? ''));
    $latestAllowed = scheduler_latest_allowed_start_at($job);
    $now = time();
    $queueWait = $scheduledFor !== '' ? max(0, $now - (int) strtotime($scheduledFor)) : 0;
    $latestAllowedTs = $latestAllowed !== null ? (int) strtotime($latestAllowed) : 0;
    $secondsToLatest = $latestAllowedTs > 0 ? $latestAllowedTs - $now : PHP_INT_MAX;
    $intervalSeconds = max(60, (int) ($job['interval_minutes'] ?? 5) * 60);
    $latenessRatio = min(3.0, $queueWait / max(60, (int) round($intervalSeconds * 0.5)));
    $criticalWindowRatio = $latestAllowedTs > 0 ? max(0.0, 1.0 - ($secondsToLatest / max(60, $intervalSeconds))) : 0.0;
    $starvationCount = max(
        (int) ($job['consecutive_deferrals'] ?? 0),
        (int) ($recentDecisionCounts[(string) ($job['job_key'] ?? '')]['deferred_capacity'] ?? 0)
            + (int) ($recentDecisionCounts[(string) ($job['job_key'] ?? '')]['deferred_memory'] ?? 0)
            + (int) ($recentDecisionCounts[(string) ($job['job_key'] ?? '')]['deferred_cpu'] ?? 0)
    );
    $starvationBoost = min(2.0, $starvationCount * 0.35);
    $criticalBoost = scheduler_is_protected_job((string) ($job['job_key'] ?? '')) ? 0.75 : 0.0;
    $bootstrapBoost = ((string) ($job['job_key'] ?? '') === 'deal_alerts_sync' && !deal_alert_has_successful_materialization()) ? 2.2 : 0.0;
    $latencyBoost = !empty($job['latency_sensitive']) ? 0.9 : 0.0;
    $score = (scheduler_priority_rank($priority) * 1.7) + ($latenessRatio * 1.5) + ($criticalWindowRatio * 3.4) + $starvationBoost + $criticalBoost + $bootstrapBoost + $latencyBoost;

    return [
        'queue_wait_seconds' => $queueWait,
        'latest_allowed_start_at' => $latestAllowed,
        'seconds_to_latest_allowed_start' => $secondsToLatest === PHP_INT_MAX ? null : $secondsToLatest,
        'latest_window_ratio' => round($criticalWindowRatio, 4),
        'starvation_count' => $starvationCount,
        'force_execution' => scheduler_job_force_execution($job),
        'bootstrap_boost_active' => $bootstrapBoost > 0,
        'urgency_score' => round($score, 3),
        'starvation_indicator' => $starvationCount >= scheduler_starvation_deferral_threshold($job) || $criticalWindowRatio >= 0.75,
    ];
}

function scheduler_recent_planner_decision_counts(int $limit = 120): array
{
    $rows = db_scheduler_job_current_status_fetch_map();
    $summary = [];
    foreach ($rows as $row) {
        $jobKey = (string) ($row['job_key'] ?? '');
        if ($jobKey === '') {
            continue;
        }

        $type = (string) ($row['last_planner_decision_type'] ?? '');
        $deferredCount = max(0, (int) ($row['recent_deferral_count'] ?? 0));
        if ($deferredCount <= 0) {
            continue;
        }

        if ($type === '' || !str_contains($type, 'deferred')) {
            $type = 'deferred_capacity';
        }

        $summary[$jobKey][$type] = $deferredCount;
    }

    return $summary;
}

function scheduler_live_capacity_snapshot(?array $runningJobs = null): array
{
    $capacity = scheduler_capacity_model();
    $running = is_array($runningJobs) ? $runningJobs : db_sync_schedule_fetch_running_jobs();
    $cpuUsed = 0.0;
    $memoryUsed = 0;
    $timeoutRates = [];
    $failureRates = [];

    foreach ($running as $job) {
        $cpuUsed += (float) ($job['current_projected_cpu_percent'] ?? $job['p95_cpu_percent'] ?? $job['average_cpu_percent'] ?? 0.0);
        $memoryUsed += (int) ($job['current_projected_memory_bytes'] ?? $job['p95_memory_peak_bytes'] ?? $job['average_memory_peak_bytes'] ?? 0);
        if (isset($job['recent_timeout_rate'])) {
            $timeoutRates[] = (float) $job['recent_timeout_rate'];
        }
        if (isset($job['recent_failure_rate'])) {
            $failureRates[] = (float) $job['recent_failure_rate'];
        }
    }

    $summary = [
        'running_jobs' => count($running),
        'cpu_budget_percent' => (float) $capacity['cpu_budget_percent'],
        'memory_budget_bytes' => (int) $capacity['memory_budget_bytes'],
        'reserved_critical_cpu_percent' => (float) $capacity['reserved_critical_cpu_percent'],
        'reserved_critical_memory_bytes' => (int) $capacity['reserved_critical_memory_bytes'],
        'max_concurrent_jobs' => (int) $capacity['max_concurrent_jobs'],
        'current_cpu_used_percent' => round($cpuUsed, 2),
        'current_memory_used_bytes' => $memoryUsed,
        'cpu_budget_ratio' => $capacity['cpu_budget_percent'] > 0 ? round($cpuUsed / $capacity['cpu_budget_percent'], 4) : 0.0,
        'memory_budget_ratio' => $capacity['memory_budget_bytes'] > 0 ? round($memoryUsed / $capacity['memory_budget_bytes'], 4) : 0.0,
        'timeout_rate' => $timeoutRates !== [] ? round(array_sum($timeoutRates) / count($timeoutRates), 4) : 0.0,
        'failure_rate' => $failureRates !== [] ? round(array_sum($failureRates) / count($failureRates), 4) : 0.0,
        'running_jobs_detail' => array_map(static function (array $job): array {
            return [
                'job_key' => (string) ($job['job_key'] ?? ''),
                'label' => ucwords(str_replace('_', ' ', (string) ($job['job_key'] ?? ''))),
                'resource_class' => (string) ($job['resource_class'] ?? 'medium'),
                'projected_cpu_percent' => isset($job['current_projected_cpu_percent']) ? (float) $job['current_projected_cpu_percent'] : null,
                'projected_memory_bytes' => isset($job['current_projected_memory_bytes']) ? (int) $job['current_projected_memory_bytes'] : null,
                'started_at' => $job['last_started_at'] ?? null,
                'latest_allowed_start_at' => $job['latest_allowed_start_at'] ?? null,
            ];
        }, $running),
    ];
    $summary['pressure'] = scheduler_pressure_label($summary);

    return $summary;
}

function scheduler_jobs_are_compatible(array $candidate, array $running, int $totalConcurrency = 2): bool
{
    if ((string) ($candidate['job_key'] ?? '') === (string) ($running['job_key'] ?? '')) {
        return false;
    }

    $candidateForbidden = array_fill_keys((array) ($candidate['forbidden_with'] ?? []), true);
    $runningForbidden = array_fill_keys((array) ($running['forbidden_with'] ?? []), true);
    if (isset($candidateForbidden[(string) ($running['job_key'] ?? '')]) || isset($runningForbidden[(string) ($candidate['job_key'] ?? '')])) {
        return false;
    }

    foreach (db_scheduler_pairing_rules_fetch_active() as $rule) {
        $primary = (string) ($rule['primary_job_key'] ?? '');
        $secondary = (string) ($rule['secondary_job_key'] ?? '');
        $matches = ($primary === (string) ($candidate['job_key'] ?? '') && $secondary === (string) ($running['job_key'] ?? ''))
            || ($secondary === (string) ($candidate['job_key'] ?? '') && $primary === (string) ($running['job_key'] ?? ''));
        if ($matches && (string) ($rule['rule_type'] ?? '') === 'avoid') {
            return false;
        }
    }

    if (!empty($candidate['must_run_alone']) || !empty($running['must_run_alone'])) {
        return false;
    }

    $candidateParallelism = max(1, (int) ($candidate['preferred_max_parallelism'] ?? 1));
    $runningParallelism = max(1, (int) ($running['preferred_max_parallelism'] ?? 1));
    if ($totalConcurrency > $candidateParallelism || $totalConcurrency > $runningParallelism) {
        return false;
    }

    $allowedGroups = array_fill_keys((array) ($candidate['allowed_groups'] ?? ['light', 'medium', 'heavy']), true);
    if (!isset($allowedGroups[(string) ($running['resource_class'] ?? 'medium')])) {
        return false;
    }

    return true;
}

function scheduler_plan_due_jobs(array $jobs): array
{
    $claimedIds = array_values(array_filter(array_map(static fn (array $job): int => (int) ($job['id'] ?? 0), $jobs), static fn (int $id): bool => $id > 0));
    $running = db_sync_schedule_fetch_running_jobs($claimedIds);
    $liveCapacity = scheduler_live_capacity_snapshot($running);
    $recentDecisionCounts = scheduler_recent_planner_decision_counts();
    $prepared = [];

    foreach ($jobs as $job) {
        $jobKey = (string) ($job['job_key'] ?? '');
        $profile = scheduler_job_recent_resource_profile($jobKey, $job);
        $urgency = scheduler_job_urgency_snapshot($job, $recentDecisionCounts);
        $preparedJob = $job + $profile + $urgency + [
            'projected_cpu_percent' => $profile['projection_cpu_percent'],
            'projected_memory_bytes' => $profile['projection_memory_bytes'],
            'job_key' => $jobKey,
        ];
        usort($running, static fn (array $a, array $b): int => strcmp((string) ($a['job_key'] ?? ''), (string) ($b['job_key'] ?? '')));
        db_sync_schedule_mark_planner_state((int) ($job['id'] ?? 0), [
            'current_projected_cpu_percent' => $preparedJob['projected_cpu_percent'],
            'current_projected_memory_bytes' => $preparedJob['projected_memory_bytes'],
            'current_pressure_state' => $liveCapacity['pressure'],
            'latest_allowed_start_at' => $preparedJob['latest_allowed_start_at'],
            'must_run_alone' => $preparedJob['must_run_alone'],
            'prefers_solo' => $preparedJob['prefers_solo'],
            'allow_parallel' => $preparedJob['allow_parallel'],
        ]);
        $prepared[] = $preparedJob;
    }

    usort($prepared, static function (array $a, array $b): int {
        return (($b['urgency_score'] ?? 0) <=> ($a['urgency_score'] ?? 0)) ?: (((int) ($a['id'] ?? 0)) <=> ((int) ($b['id'] ?? 0)));
    });

    $allowed = [];
    $deferred = [];
    $state = $liveCapacity;
    $runningProfiles = [];
    foreach ($running as $job) {
        $runningProfiles[] = $job + scheduler_job_recent_resource_profile((string) ($job['job_key'] ?? ''), $job) + [
            'projected_cpu_percent' => (float) ($job['current_projected_cpu_percent'] ?? $job['p95_cpu_percent'] ?? $job['average_cpu_percent'] ?? 0.0),
            'projected_memory_bytes' => (int) ($job['current_projected_memory_bytes'] ?? $job['p95_memory_peak_bytes'] ?? $job['average_memory_peak_bytes'] ?? 0),
            'forbidden_with' => (array) (scheduler_job_recent_resource_profile((string) ($job['job_key'] ?? ''), $job)['forbidden_with'] ?? []),
        ];
    }

    foreach ($prepared as $candidate) {
        $reasons = [];
        $projectedCpu = $state['current_cpu_used_percent'] + (float) ($candidate['projected_cpu_percent'] ?? 0.0);
        $projectedMemory = $state['current_memory_used_bytes'] + (int) ($candidate['projected_memory_bytes'] ?? 0);
        $budgetCpu = (float) $state['cpu_budget_percent'];
        $budgetMemory = (int) $state['memory_budget_bytes'];
        $jobKey = (string) ($candidate['job_key'] ?? '');
        $isCritical = scheduler_is_protected_job($jobKey);
        $forceExecution = !empty($candidate['force_execution']);
        $availableCpu = $budgetCpu - $projectedCpu;
        $availableMemory = $budgetMemory - $projectedMemory;

        if (count($runningProfiles) + count($allowed) >= (int) $state['max_concurrent_jobs']) {
            $reasons[] = 'concurrency_ceiling';
        }
        if ($projectedCpu > $budgetCpu) {
            $reasons[] = 'cpu_budget';
        }
        if ($projectedMemory > $budgetMemory) {
            $reasons[] = 'memory_budget';
        }
        if (!$isCritical && $availableCpu < (float) $state['reserved_critical_cpu_percent']) {
            $reasons[] = 'reserved_critical_cpu';
        }
        if (!$isCritical && $availableMemory < (int) $state['reserved_critical_memory_bytes']) {
            $reasons[] = 'reserved_critical_memory';
        }
        foreach (array_merge($runningProfiles, $allowed) as $other) {
            if (!scheduler_jobs_are_compatible($candidate, $other, count($runningProfiles) + count($allowed) + 1)) {
                $reasons[] = 'incompatible:' . (string) ($other['job_key'] ?? '');
                break;
            }
        }
        if (($state['pressure'] ?? 'healthy') === 'overload_protection' && !$isCritical) {
            $reasons[] = 'overload_guard';
        }
        if (($state['pressure'] ?? 'healthy') === 'congested' && (string) ($candidate['resource_class'] ?? 'medium') === 'heavy' && count($allowed) > 0) {
            $reasons[] = 'heavy_under_congestion';
        }

        if ($forceExecution) {
            $reasons = array_values(array_filter($reasons, static fn (string $reason): bool => !in_array($reason, [
                'reserved_critical_cpu',
                'reserved_critical_memory',
                'heavy_under_congestion',
                'concurrency_ceiling',
            ], true)));
        }

        $decisionPayload = [
            'projected_cpu_percent' => $candidate['projected_cpu_percent'] ?? null,
            'projected_memory_bytes' => $candidate['projected_memory_bytes'] ?? null,
            'current_capacity' => $state,
            'running_jobs' => array_map(static fn (array $job): string => (string) ($job['job_key'] ?? ''), array_merge($runningProfiles, $allowed)),
            'urgency_score' => $candidate['urgency_score'] ?? 0,
            'latest_allowed_start_at' => $candidate['latest_allowed_start_at'] ?? null,
            'starvation_indicator' => !empty($candidate['starvation_indicator']),
            'force_execution' => $forceExecution,
        ];

        if ($reasons === []) {
            $reasonText = 'Allowed now because projected CPU/memory fit the active budget, overlap rules were satisfied, and urgency justified parallel capacity use.';
            if (!empty($candidate['starvation_indicator']) || $forceExecution) {
                $reasonText = 'Allowed now because starvation prevention or latest-allowed-start pressure elevated this overdue job into available capacity.';
                $decisionPayload['starvation_prevention_triggered'] = true;
            }
            db_scheduler_planner_decision_insert((int) ($candidate['id'] ?? 0), $jobKey, 'allowed', (string) $state['pressure'], $reasonText, $decisionPayload);
            $allowed[] = $candidate;
            $state['current_cpu_used_percent'] = round($projectedCpu, 2);
            $state['current_memory_used_bytes'] = $projectedMemory;
            $state['cpu_budget_ratio'] = $budgetCpu > 0 ? round($state['current_cpu_used_percent'] / $budgetCpu, 4) : 0.0;
            $state['memory_budget_ratio'] = $budgetMemory > 0 ? round($state['current_memory_used_bytes'] / $budgetMemory, 4) : 0.0;
            $state['running_jobs'] = count($runningProfiles) + count($allowed);
            $state['pressure'] = scheduler_pressure_label($state);
            continue;
        }

        $primaryReason = str_starts_with($reasons[0], 'incompatible:') ? 'incompatibility' : $reasons[0];
        $decisionType = match ($primaryReason) {
            'cpu_budget', 'reserved_critical_cpu' => 'deferred_cpu',
            'memory_budget', 'reserved_critical_memory' => 'deferred_memory',
            default => 'deferred_capacity',
        };
        $reasonText = match ($primaryReason) {
            'cpu_budget' => 'Deferred because projected CPU demand would exceed the scheduler CPU budget.',
            'memory_budget' => 'Deferred because projected memory demand would exceed the scheduler memory budget.',
            'reserved_critical_cpu', 'reserved_critical_memory' => 'Deferred to preserve reserved headroom for critical jobs nearing their run windows.',
            'incompatibility' => 'Deferred because an explicit incompatibility or solo-execution rule blocks this job alongside current work.',
            'concurrency_ceiling' => 'Deferred because the dynamic concurrency ceiling is already full for the current pressure state.',
            'overload_guard' => 'Deferred because overload protection is active and only critical work should claim more capacity.',
            'heavy_under_congestion' => 'Deferred because congested pressure keeps heavy work isolated until lighter or overdue work clears.',
            default => 'Deferred because current scheduler pressure and budget state make the combination unsafe right now.',
        };
        $decisionPayload['defer_reasons'] = $reasons;
        db_scheduler_planner_decision_insert((int) ($candidate['id'] ?? 0), $jobKey, $decisionType, (string) $state['pressure'], $reasonText, $decisionPayload);
        db_sync_schedule_release_claim((int) ($candidate['id'] ?? 0), gmdate('Y-m-d H:i:s', time() + 60), $decisionType);
        if ($jobKey === 'deal_alerts_sync') {
            deal_alert_record_scheduler_deferral($reasonText, $candidate);
        }
        $deferred[] = $candidate + ['defer_reasons' => $reasons, 'decision_type' => $decisionType];
    }

    return [
        'allowed' => $allowed,
        'deferred' => $deferred,
        'state' => $state,
        'running' => $runningProfiles,
    ];
}


function scheduler_json_decode_assoc(mixed $value): array
{
    if (!is_string($value) || trim($value) === '') {
        return [];
    }

    $decoded = json_decode($value, true);

    return is_array($decoded) ? $decoded : [];
}

function scheduler_operator_identity_label(): string
{
    try {
        $token = db_latest_esi_oauth_token();
        $name = trim((string) ($token['character_name'] ?? ''));
        if ($name !== '') {
            return $name;
        }
    } catch (Throwable) {
    }

    $remote = trim((string) ($_SERVER['REMOTE_ADDR'] ?? ''));

    return $remote !== '' ? 'settings-admin@' . $remote : 'settings-admin';
}

function scheduler_profiling_decode_run(?array $row): ?array
{
    if (!is_array($row) || $row === []) {
        return null;
    }

    foreach (['scope_json' => 'scope', 'options_json' => 'options', 'selected_job_keys_json' => 'selected_job_keys', 'progress_json' => 'progress', 'recommendations_json' => 'recommendations', 'summary_json' => 'summary'] as $source => $target) {
        $row[$target] = scheduler_json_decode_assoc($row[$source] ?? null);
    }

    return $row;
}

function scheduler_profiling_active_run(): ?array
{
    return scheduler_profiling_decode_run(db_scheduler_profiling_active_run());
}

function scheduler_profiling_latest_runs(int $limit = 6): array
{
    return array_values(array_filter(array_map('scheduler_profiling_decode_run', db_scheduler_profiling_latest_runs($limit))));
}

function scheduler_profiling_is_unsafe_or_heavy(array $job): bool
{
    $jobKey = (string) ($job['job_key'] ?? '');
    $rules = scheduler_job_safety_rules()[$jobKey] ?? [];

    return !empty($job['must_run_alone'])
        || (string) ($job['resource_class'] ?? '') === 'heavy'
        || !empty($rules['must_run_alone'])
        || (float) ($job['p95_cpu_percent'] ?? 0) >= (float) (scheduler_capacity_model()['cpu_budget_percent'] * 0.55)
        || (float) ($job['recent_timeout_rate'] ?? 0) >= 0.25;
}

function scheduler_profiling_request_options(array $request): array
{
    $scope = trim((string) ($request['profiling_scope'] ?? 'all_operational'));
    if (!in_array($scope, ['all_operational', 'selected_operational'], true)) {
        $scope = 'all_operational';
    }

    $mode = trim((string) ($request['profiling_mode'] ?? 'isolated_plus_compatibility'));
    if (!in_array($mode, ['isolated_only', 'isolated_plus_compatibility'], true)) {
        $mode = 'isolated_plus_compatibility';
    }

    $selectedJobKeys = array_values(array_unique(array_filter(array_map(
        static fn (mixed $jobKey): string => trim((string) $jobKey),
        (array) ($request['profiling_job_keys'] ?? [])
    ), static fn (string $jobKey): bool => $jobKey !== '')));

    return [
        'scope' => $scope,
        'include_discovered_jobs' => !empty($request['profiling_include_discovered']),
        'exclude_unsafe_heavy' => !array_key_exists('profiling_exclude_unsafe_heavy', $request) || !empty($request['profiling_exclude_unsafe_heavy']),
        'mode' => $mode,
        'isolated_sample_count' => max(1, min(3, (int) ($request['profiling_isolated_sample_count'] ?? 1))),
        'selected_job_keys' => $selectedJobKeys,
        'reason_text' => mb_substr(trim((string) ($request['profiling_reason_text'] ?? 'Baseline refresh requested from Settings → Data Sync.')), 0, 500),
    ];
}

function scheduler_profiling_target_jobs(array $run): array
{
    $options = is_array($run['options'] ?? null) ? $run['options'] : [];
    $scope = (string) ($options['scope'] ?? 'all_operational');
    $selectedKeys = array_fill_keys((array) ($run['selected_job_keys'] ?? $options['selected_job_keys'] ?? []), true);
    $includeDiscovered = !empty($options['include_discovered_jobs']);
    $excludeUnsafeHeavy = !array_key_exists('exclude_unsafe_heavy', $options) || !empty($options['exclude_unsafe_heavy']);
    $rows = db_sync_schedule_fetch_all();
    $targets = [];

    foreach ($rows as $row) {
        $jobKey = trim((string) ($row['job_key'] ?? ''));
        if ($jobKey === '' || scheduler_is_internal_mechanic_job($jobKey)) {
            continue;
        }
        $explicit = !empty($row['explicitly_configured']);
        if (!$explicit && !$includeDiscovered) {
            continue;
        }
        if ($scope === 'selected_operational' && !isset($selectedKeys[$jobKey])) {
            continue;
        }
        if ($excludeUnsafeHeavy && scheduler_profiling_is_unsafe_or_heavy($row)) {
            continue;
        }
        $targets[$jobKey] = $row;
    }

    ksort($targets);

    return $targets;
}

function scheduler_profiling_start(array $request): array
{
    $active = scheduler_profiling_active_run();
    if ($active !== null) {
        return ['ok' => false, 'message' => 'A Performance Monitoring Run is already active.'];
    }

    $options = scheduler_profiling_request_options($request);
    $actor = scheduler_operator_identity_label();
    $scopeSummary = [
        'scope' => $options['scope'],
        'include_discovered_jobs' => $options['include_discovered_jobs'],
        'exclude_unsafe_heavy' => $options['exclude_unsafe_heavy'],
        'mode' => $options['mode'],
        'isolated_sample_count' => $options['isolated_sample_count'],
        'reason_text' => $options['reason_text'],
    ];
    $selectedRows = scheduler_profiling_target_jobs([
        'options' => $options,
        'selected_job_keys' => $options['selected_job_keys'],
    ]);
    if ($selectedRows === []) {
        return ['ok' => false, 'message' => 'No operational jobs matched the selected Performance Monitoring scope.'];
    }

    $runId = db_transaction(static function () use ($actor, $scopeSummary, $options, $selectedRows): int {
        $runId = db_scheduler_profiling_run_insert([
            'run_status' => 'waiting',
            'current_phase' => 'waiting_for_active_jobs',
            'execution_mode' => $options['mode'],
            'started_by' => $actor,
            'scope_json' => json_encode($scopeSummary, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'options_json' => json_encode($options, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'selected_job_keys_json' => json_encode(array_keys($selectedRows), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'progress_json' => json_encode([
                'total_jobs' => count($selectedRows),
                'isolated_completed_jobs' => 0,
                'compatibility_completed_pairs' => 0,
                'message' => 'Waiting for active scheduler work to drain before starting isolated baseline profiling.',
            ], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            'started_at' => gmdate('Y-m-d H:i:s'),
        ]);
        $snapshotId = db_scheduler_schedule_snapshot_insert($runId, 'profiling_start_snapshot', $actor, 'Captured scheduler configuration before Performance Monitoring started.', db_sync_schedule_fetch_all());
        db_scheduler_profiling_run_update($runId, ['summary_json' => json_encode(['start_snapshot_id' => $snapshotId], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE)]);
        return $runId;
    });

    return ['ok' => $runId > 0, 'message' => $runId > 0 ? 'Performance Monitoring Run started.' : 'Could not start Performance Monitoring Run.'];
}

function scheduler_profiling_cancel_active(): array
{
    $active = scheduler_profiling_active_run();
    if ($active === null) {
        return ['ok' => false, 'message' => 'No active Performance Monitoring Run was found.'];
    }

    db_scheduler_profiling_run_update((int) $active['id'], [
        'run_status' => 'cancelled',
        'current_phase' => 'cancelled',
        'cancelled_at' => gmdate('Y-m-d H:i:s'),
        'finished_at' => gmdate('Y-m-d H:i:s'),
        'progress_json' => json_encode(array_merge((array) ($active['progress'] ?? []), ['message' => 'Cancelled by admin from the sync control panel.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);

    return ['ok' => true, 'message' => 'Performance Monitoring Run cancelled and normal scheduling will resume on the next tick.'];
}

function scheduler_profiling_sample_summary(array $samples): array
{
    $grouped = [];
    foreach ($samples as $sample) {
        $jobKey = (string) ($sample['job_key'] ?? '');
        if ($jobKey === '') {
            continue;
        }
        $grouped[$jobKey][] = $sample;
    }

    $summary = [];
    foreach ($grouped as $jobKey => $rows) {
        $durations = array_map(static fn (array $row): float => (float) ($row['wall_duration_seconds'] ?? 0.0), $rows);
        $cpu = array_map(static fn (array $row): float => (float) ($row['cpu_percent'] ?? 0.0), $rows);
        $memory = array_map(static fn (array $row): float => (float) ($row['memory_peak_bytes'] ?? 0.0), $rows);
        $lockWait = array_map(static fn (array $row): float => (float) ($row['lock_wait_seconds'] ?? 0.0), $rows);
        $queueWait = array_map(static fn (array $row): float => (float) ($row['queue_wait_seconds'] ?? 0.0), $rows);
        $failures = count(array_filter($rows, static fn (array $row): bool => !empty($row['failed'])));
        $timeouts = count(array_filter($rows, static fn (array $row): bool => !empty($row['timed_out'])));
        $summary[$jobKey] = [
            'job_key' => $jobKey,
            'sample_count' => count($rows),
            'median_wall_seconds' => scheduler_metric_percentile($durations, 0.5),
            'average_wall_seconds' => count($durations) > 0 ? array_sum($durations) / count($durations) : null,
            'p95_wall_seconds' => scheduler_metric_percentile($durations, 0.95),
            'median_cpu_percent' => scheduler_metric_percentile($cpu, 0.5),
            'p95_cpu_percent' => scheduler_metric_percentile($cpu, 0.95),
            'median_memory_peak_bytes' => scheduler_metric_percentile($memory, 0.5),
            'p95_memory_peak_bytes' => scheduler_metric_percentile($memory, 0.95),
            'median_lock_wait_seconds' => scheduler_metric_percentile($lockWait, 0.5),
            'median_queue_wait_seconds' => scheduler_metric_percentile($queueWait, 0.5),
            'failure_rate' => count($rows) > 0 ? $failures / count($rows) : 0.0,
            'timeout_rate' => count($rows) > 0 ? $timeouts / count($rows) : 0.0,
            'resource_class' => 'medium',
            'preferred_max_parallelism' => 2,
        ];
        $capacity = scheduler_capacity_model();
        $cpuRatio = $capacity['cpu_budget_percent'] > 0 ? (float) ($summary[$jobKey]['p95_cpu_percent'] ?? 0.0) / $capacity['cpu_budget_percent'] : 0.0;
        $memoryRatio = $capacity['memory_budget_bytes'] > 0 ? (float) ($summary[$jobKey]['p95_memory_peak_bytes'] ?? 0.0) / $capacity['memory_budget_bytes'] : 0.0;
        if ($cpuRatio >= 0.45 || $memoryRatio >= 0.45 || $summary[$jobKey]['timeout_rate'] >= 0.2) {
            $summary[$jobKey]['resource_class'] = 'heavy';
            $summary[$jobKey]['preferred_max_parallelism'] = 1;
        } elseif ($cpuRatio >= 0.18 || $memoryRatio >= 0.18) {
            $summary[$jobKey]['resource_class'] = 'medium';
            $summary[$jobKey]['preferred_max_parallelism'] = 2;
        } else {
            $summary[$jobKey]['resource_class'] = 'light';
            $summary[$jobKey]['preferred_max_parallelism'] = 3;
        }
    }

    return $summary;
}

function scheduler_profiling_next_isolated_job(array $run, array $targets, array $samples): ?array
{
    $options = (array) ($run['options'] ?? []);
    $targetSampleCount = max(1, (int) ($options['isolated_sample_count'] ?? 1));
    $counts = [];
    foreach ($samples as $sample) {
        $jobKey = (string) ($sample['job_key'] ?? '');
        if ($jobKey === '') {
            continue;
        }
        $counts[$jobKey] = (int) ($counts[$jobKey] ?? 0) + 1;
    }

    foreach ($targets as $jobKey => $job) {
        if ((int) ($counts[$jobKey] ?? 0) < $targetSampleCount) {
            return array_merge($job, ['profiling_sample_index' => (int) ($counts[$jobKey] ?? 0) + 1]);
        }
    }

    return null;
}

function scheduler_profiling_latest_metric_for_job(string $jobKey): array
{
    $metrics = db_scheduler_resource_metrics_recent($jobKey, 1);

    return $metrics[0] ?? [];
}

function scheduler_profiling_insert_sample(int $runId, array $job, string $phase, int $sampleIndex, ?string $partnerJobKey, array $result, ?array $metric = null): void
{
    $resourceUsage = is_array($result['meta']['resource_usage'] ?? null) ? $result['meta']['resource_usage'] : [];
    $runtimeMetric = is_array($metric) ? $metric : scheduler_profiling_latest_metric_for_job((string) ($job['job_key'] ?? ''));
    $workload = [
        'rows_seen' => (int) ($result['rows_seen'] ?? 0),
        'rows_written' => (int) ($result['rows_written'] ?? 0),
        'warnings' => array_values((array) ($result['warnings'] ?? [])),
        'summary' => (string) ($result['summary'] ?? ''),
    ];

    db_scheduler_profiling_sample_insert([
        'profiling_run_id' => $runId,
        'schedule_id' => (int) ($job['id'] ?? 0),
        'job_key' => (string) ($job['job_key'] ?? ''),
        'phase' => $phase,
        'sample_key' => $phase . ':' . (string) ($job['job_key'] ?? '') . ':' . $sampleIndex . ($partnerJobKey !== null ? ':' . $partnerJobKey : ''),
        'partner_job_key' => $partnerJobKey,
        'sample_index' => $sampleIndex,
        'run_status' => (string) ($result['status'] ?? 'failed'),
        'wall_duration_seconds' => isset($resourceUsage['cpu_percent']) ? (float) (($runtimeMetric['wall_duration_seconds'] ?? null) ?? (($result['duration_ms'] ?? 0) / 1000)) : (($result['duration_ms'] ?? 0) / 1000),
        'cpu_percent' => $runtimeMetric['cpu_percent'] ?? $resourceUsage['cpu_percent'] ?? null,
        'memory_peak_bytes' => $runtimeMetric['memory_peak_delta_bytes'] ?? $runtimeMetric['memory_peak_bytes'] ?? $resourceUsage['memory_peak_delta_bytes'] ?? $resourceUsage['memory_peak_bytes'] ?? null,
        'lock_wait_seconds' => $runtimeMetric['lock_wait_seconds'] ?? $resourceUsage['lock_wait_seconds'] ?? null,
        'queue_wait_seconds' => $runtimeMetric['queue_wait_seconds'] ?? $resourceUsage['queue_wait_seconds'] ?? null,
        'overlap_count' => $runtimeMetric['overlap_count'] ?? $resourceUsage['overlap_count'] ?? 0,
        'timed_out' => !empty($runtimeMetric['timed_out']) || str_contains(strtolower((string) ($result['error'] ?? '')), 'timeout'),
        'failed' => ($result['status'] ?? '') === 'failed',
        'workload_json' => json_encode($workload, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
        'result_json' => json_encode($result, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
        'started_at' => isset($result['started_at']) ? gmdate('Y-m-d H:i:s', strtotime((string) $result['started_at'])) : null,
        'finished_at' => isset($result['finished_at']) && $result['finished_at'] !== null ? gmdate('Y-m-d H:i:s', strtotime((string) $result['finished_at'])) : null,
    ]);
}

function scheduler_profiling_run_isolated_sample(array $run, array $job): array
{
    $jobKey = (string) ($job['job_key'] ?? '');
    $definitions = scheduler_job_definitions();
    $timeoutResolution = scheduler_resolve_job_timeout($jobKey, $job, $definitions[$jobKey] ?? null);
    $timeoutSeconds = (int) ($timeoutResolution['enforced_timeout_seconds'] ?? 300);
    $lockTtl = scheduler_job_lock_ttl_seconds($timeoutSeconds + 120, $timeoutSeconds);
    $claimed = db_sync_schedule_claim_job_forced((int) ($job['id'] ?? 0), $lockTtl);
    if ($claimed === null) {
        throw new RuntimeException('Could not claim ' . $jobKey . ' for isolated profiling.');
    }

    $sampleIndex = (int) ($job['profiling_sample_index'] ?? 1);
    $result = scheduler_run_job($claimed);
    scheduler_profiling_insert_sample((int) $run['id'], $claimed, 'isolated', $sampleIndex, null, $result);

    return $result;
}

function scheduler_profiling_wait_for_job_finish(int $scheduleId, int $timeoutSeconds): ?array
{
    $deadline = microtime(true) + max(10, $timeoutSeconds);
    do {
        usleep(250000);
        $row = db_sync_schedule_fetch_by_id($scheduleId);
        if ($row === null) {
            return null;
        }
        if ((string) ($row['current_state'] ?? '') !== 'running' && empty($row['locked_until'])) {
            return $row;
        }
    } while (microtime(true) < $deadline);

    return db_sync_schedule_fetch_by_id($scheduleId);
}

function scheduler_profiling_pair_candidates(array $targets, array $isolatedSummary): array
{
    $candidates = [];
    $keys = array_keys($targets);
    sort($keys);
    foreach ($keys as $index => $jobKey) {
        for ($otherIndex = $index + 1; $otherIndex < count($keys); $otherIndex++) {
            $otherKey = $keys[$otherIndex];
            $aSummary = $isolatedSummary[$jobKey] ?? [];
            $bSummary = $isolatedSummary[$otherKey] ?? [];
            $classA = (string) ($aSummary['resource_class'] ?? ($targets[$jobKey]['resource_class'] ?? 'medium'));
            $classB = (string) ($bSummary['resource_class'] ?? ($targets[$otherKey]['resource_class'] ?? 'medium'));
            $weight = (($classA === 'light' && $classB === 'light') ? 1 : (($classA === 'medium' && $classB === 'light') || ($classA === 'light' && $classB === 'medium') ? 2 : 5));
            $candidates[] = ['primary_job_key' => $jobKey, 'secondary_job_key' => $otherKey, 'weight' => $weight];
        }
    }

    usort($candidates, static fn (array $a, array $b): int => ($a['weight'] <=> $b['weight']) ?: strcmp($a['primary_job_key'] . $a['secondary_job_key'], $b['primary_job_key'] . $b['secondary_job_key']));

    return $candidates;
}

function scheduler_profiling_run_pair_probe(array $run, array $primary, array $secondary): array
{
    $definitions = scheduler_job_definitions();
    $primaryTimeout = (int) (scheduler_resolve_job_timeout((string) ($primary['job_key'] ?? ''), $primary, $definitions[(string) ($primary['job_key'] ?? '')] ?? null)['enforced_timeout_seconds'] ?? 300);
    $secondaryTimeout = (int) (scheduler_resolve_job_timeout((string) ($secondary['job_key'] ?? ''), $secondary, $definitions[(string) ($secondary['job_key'] ?? '')] ?? null)['enforced_timeout_seconds'] ?? 300);
    $combinedTimeout = $primaryTimeout + $secondaryTimeout + 180;
    $primaryClaim = db_sync_schedule_claim_job_forced((int) ($primary['id'] ?? 0), $combinedTimeout);
    $secondaryClaim = db_sync_schedule_claim_job_forced((int) ($secondary['id'] ?? 0), $combinedTimeout);
    if ($primaryClaim === null || $secondaryClaim === null) {
        if ($primaryClaim !== null) {
            db_sync_schedule_release_claim((int) ($primaryClaim['id'] ?? 0), gmdate('Y-m-d H:i:s', time() + 60), 'profiling-claim-released');
        }
        if ($secondaryClaim !== null) {
            db_sync_schedule_release_claim((int) ($secondaryClaim['id'] ?? 0), gmdate('Y-m-d H:i:s', time() + 60), 'profiling-claim-released');
        }
        throw new RuntimeException('Could not claim both jobs for compatibility probing.');
    }

    $dispatchResult = scheduler_dispatch_background_job($primaryClaim);
    usleep(300000);
    $inlineResult = scheduler_run_job($secondaryClaim);
    $primaryRow = scheduler_profiling_wait_for_job_finish((int) ($primaryClaim['id'] ?? 0), $primaryTimeout + 120) ?? [];
    if ((string) ($primaryRow['current_state'] ?? '') === 'running') {
        $primaryRow['last_status'] = 'failed';
        $primaryRow['last_error'] = 'Compatibility probe timed out while waiting for the background job to finish.';
    }
    $primaryMetric = scheduler_profiling_latest_metric_for_job((string) ($primaryClaim['job_key'] ?? ''));
    $secondaryMetric = scheduler_profiling_latest_metric_for_job((string) ($secondaryClaim['job_key'] ?? ''));

    $primaryResult = [
        'job_id' => (int) ($primaryClaim['id'] ?? 0),
        'job_key' => (string) ($primaryClaim['job_key'] ?? ''),
        'status' => (string) ($primaryRow['last_status'] ?? 'failed'),
        'started_at' => $primaryRow['last_started_at'] ?? $dispatchResult['started_at'] ?? null,
        'finished_at' => $primaryRow['last_finished_at'] ?? null,
        'duration_ms' => isset($primaryMetric['wall_duration_seconds']) ? (int) round(((float) $primaryMetric['wall_duration_seconds']) * 1000) : 0,
        'summary' => (string) ($primaryRow['last_result'] ?? $dispatchResult['summary'] ?? 'Background compatibility probe finished.'),
        'error' => $primaryRow['last_error'] ?? null,
        'rows_seen' => 0,
        'rows_written' => 0,
        'warnings' => [],
        'meta' => [
            'resource_usage' => [
                'cpu_percent' => $primaryMetric['cpu_percent'] ?? null,
                'memory_peak_delta_bytes' => $primaryMetric['memory_peak_delta_bytes'] ?? $primaryMetric['memory_peak_bytes'] ?? null,
                'lock_wait_seconds' => $primaryMetric['lock_wait_seconds'] ?? null,
                'queue_wait_seconds' => $primaryMetric['queue_wait_seconds'] ?? null,
                'overlap_count' => $primaryMetric['overlap_count'] ?? null,
            ],
        ],
    ];

    scheduler_profiling_insert_sample((int) $run['id'], $primaryClaim, 'compatibility', 1, (string) ($secondaryClaim['job_key'] ?? ''), $primaryResult, $primaryMetric);
    scheduler_profiling_insert_sample((int) $run['id'], $secondaryClaim, 'compatibility', 1, (string) ($primaryClaim['job_key'] ?? ''), $inlineResult, $secondaryMetric);

    $capacity = scheduler_capacity_model();
    $combinedCpu = (float) ($primaryMetric['cpu_percent'] ?? 0.0) + (float) ($secondaryMetric['cpu_percent'] ?? 0.0);
    $combinedMemory = (int) ($primaryMetric['memory_peak_delta_bytes'] ?? $primaryMetric['memory_peak_bytes'] ?? 0) + (int) ($secondaryMetric['memory_peak_delta_bytes'] ?? $secondaryMetric['memory_peak_bytes'] ?? 0);
    $maxLockWait = max((float) ($primaryMetric['lock_wait_seconds'] ?? 0.0), (float) ($secondaryMetric['lock_wait_seconds'] ?? 0.0));
    $hasFailure = ($primaryResult['status'] ?? '') === 'failed' || ($inlineResult['status'] ?? '') === 'failed';
    $compatibility = 'safe';
    $recommendedParallelism = 2;
    $reason = 'Pair completed within conservative CPU, memory, lock, and failure thresholds.';

    if ($hasFailure || $combinedCpu > ((float) $capacity['cpu_budget_percent'] * 0.75) || $combinedMemory > ((int) $capacity['memory_budget_bytes'] * 0.75) || $maxLockWait >= 5.0) {
        $compatibility = 'incompatible';
        $recommendedParallelism = 1;
        $reason = $hasFailure
            ? 'Compatibility probe failed or timed out, so the pairing should be avoided.'
            : 'Compatibility probe exceeded conservative resource or lock thresholds, so the pairing should be avoided.';
    } elseif ($combinedCpu > ((float) $capacity['cpu_budget_percent'] * 0.55) || $combinedMemory > ((int) $capacity['memory_budget_bytes'] * 0.55)) {
        $compatibility = 'degraded';
        $recommendedParallelism = 1;
        $reason = 'Compatibility probe succeeded but resource pressure was high enough that the jobs should usually run solo.';
    }

    $metrics = [
        'combined_cpu_percent' => round($combinedCpu, 2),
        'combined_memory_bytes' => $combinedMemory,
        'max_lock_wait_seconds' => round($maxLockWait, 2),
        'primary_status' => $primaryResult['status'] ?? 'failed',
        'secondary_status' => $inlineResult['status'] ?? 'failed',
    ];

    db_scheduler_profiling_pairing_upsert([
        'profiling_run_id' => (int) $run['id'],
        'primary_job_key' => (string) ($primaryClaim['job_key'] ?? ''),
        'secondary_job_key' => (string) ($secondaryClaim['job_key'] ?? ''),
        'probe_status' => 'completed',
        'compatibility' => $compatibility,
        'recommended_parallelism' => $recommendedParallelism,
        'reason_text' => $reason,
        'metrics_json' => json_encode($metrics, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);

    return ['compatibility' => $compatibility, 'reason' => $reason, 'metrics' => $metrics];
}

function scheduler_profiling_synthesize_recommendations(array $run, array $targets, array $isolatedSamples, array $pairings): array
{
    $isolatedSummary = scheduler_profiling_sample_summary($isolatedSamples);
    $rowsForOffsets = array_values($targets);
    $recommendations = [];
    $safePairings = [];
    $badPairings = [];
    foreach ($pairings as $pairing) {
        $compatibility = (string) ($pairing['compatibility'] ?? 'pending');
        $entry = [
            'primary_job_key' => (string) ($pairing['primary_job_key'] ?? ''),
            'secondary_job_key' => (string) ($pairing['secondary_job_key'] ?? ''),
            'compatibility' => $compatibility,
            'reason_text' => (string) ($pairing['reason_text'] ?? ''),
            'recommended_parallelism' => (int) ($pairing['recommended_parallelism'] ?? 1),
            'metrics' => scheduler_json_decode_assoc($pairing['metrics_json'] ?? null),
        ];
        if ($compatibility === 'safe') {
            $safePairings[] = $entry;
        } elseif (in_array($compatibility, ['degraded', 'incompatible'], true)) {
            $badPairings[] = $entry;
        }
    }

    foreach ($targets as $jobKey => $row) {
        $summary = $isolatedSummary[$jobKey] ?? [];
        $constraints = scheduler_job_constraints($jobKey);
        $resourceClass = (string) ($summary['resource_class'] ?? $row['resource_class'] ?? 'medium');
        $timeoutBase = (float) ($summary['p95_wall_seconds'] ?? $summary['average_wall_seconds'] ?? ($row['p95_duration_seconds'] ?? $row['average_duration_seconds'] ?? 60));
        $timeoutSeconds = max((int) ($row['timeout_seconds'] ?? 300), (int) ceil(($timeoutBase * 1.5) + 30));
        $intervalMinutes = (int) ($row['interval_minutes'] ?? 15);
        if ($resourceClass === 'heavy') {
            $intervalMinutes = min($constraints['max_interval_minutes'], max($intervalMinutes, (int) ceil(max(5.0, $timeoutBase / 45.0))));
        } elseif ($resourceClass === 'light' && $timeoutBase > 0) {
            $intervalMinutes = max($constraints['min_interval_minutes'], min($intervalMinutes, max(1, (int) floor(max(1.0, $timeoutBase / 30.0)))));
        }
        $recommendedRow = array_merge($row, [
            'interval_minutes' => $intervalMinutes,
            'timeout_seconds' => $timeoutSeconds,
        ]);
        $offsetMinutes = scheduler_recommended_offset_minutes_for_job($recommendedRow, $rowsForOffsets);
        $parallelism = (int) ($summary['preferred_max_parallelism'] ?? ($row['preferred_max_parallelism'] ?? 1));
        $jobBadPairings = array_values(array_filter($badPairings, static fn (array $entry): bool => $entry['primary_job_key'] === $jobKey || $entry['secondary_job_key'] === $jobKey));
        if ($jobBadPairings !== []) {
            $parallelism = 1;
        }
        $mustRunAlone = !empty($row['must_run_alone']) || $resourceClass === 'heavy' || $jobBadPairings !== [];
        if ($mustRunAlone) {
            $parallelism = 1;
        }
        $recommendations[$jobKey] = [
            'job_key' => $jobKey,
            'label' => (string) ($row['label'] ?? ucwords(str_replace('_', ' ', $jobKey))),
            'recommended_interval_minutes' => $intervalMinutes,
            'recommended_offset_minutes' => $offsetMinutes,
            'recommended_timeout_seconds' => $timeoutSeconds,
            'latest_allowed_start_policy' => 'Start no later than the due time plus one interval minute window, with starvation protection preserved.',
            'resource_class' => $resourceClass,
            'preferred_max_parallelism' => $parallelism,
            'must_run_alone' => $mustRunAlone,
            'reserved_capacity' => scheduler_is_protected_job($jobKey),
            'incompatible_job_keys' => array_values(array_unique(array_map(static function (array $entry) use ($jobKey): string {
                return $entry['primary_job_key'] === $jobKey ? $entry['secondary_job_key'] : $entry['primary_job_key'];
            }, $jobBadPairings))),
            'explanation' => [
                'Built from isolated baseline runtime/resource samples and conservative compatibility probing.',
                scheduler_is_protected_job($jobKey) ? 'Protected job offsets remain dedicated and reserved.' : 'Offset recommendation avoids protected slots and busy offsets.',
                $mustRunAlone ? 'Solo execution is recommended because profiling or policy marked the job as risky in parallel.' : 'Parallel budget recommendation remains bounded by conservative resource ceilings.',
            ],
            'delta' => [
                'interval_minutes' => $intervalMinutes - (int) ($row['interval_minutes'] ?? 0),
                'offset_minutes' => $offsetMinutes - (int) ($row['offset_minutes'] ?? 0),
                'timeout_seconds' => $timeoutSeconds - (int) ($row['timeout_seconds'] ?? 0),
                'preferred_max_parallelism' => $parallelism - (int) ($row['preferred_max_parallelism'] ?? 1),
                'resource_class_changed' => $resourceClass !== (string) ($row['resource_class'] ?? 'medium'),
            ],
        ];
        foreach ($rowsForOffsets as &$candidateRow) {
            if ((string) ($candidateRow['job_key'] ?? '') === $jobKey) {
                $candidateRow['offset_minutes'] = $offsetMinutes;
                $candidateRow['interval_minutes'] = $intervalMinutes;
                break;
            }
        }
        unset($candidateRow);
    }

    return [
        'generated_at' => gmdate(DATE_ATOM),
        'jobs' => $recommendations,
        'safe_pairings' => $safePairings,
        'bad_pairings' => $badPairings,
        'reserved_capacity_jobs' => scheduler_protected_job_keys(),
        'notes' => [
            'Fairness, anti-starvation, due-window urgency, and live CPU/memory/lock-aware shifting remain active after baseline synthesis.',
            'Protected jobs keep their dedicated offsets and reserved capacity treatment.',
        ],
    ];
}

function scheduler_profiling_apply_recommendations(int $runId, bool $preserveManualOverrides): array
{
    $run = scheduler_profiling_decode_run(db_scheduler_profiling_run_fetch($runId));
    if ($run === null) {
        return ['ok' => false, 'message' => 'Profiling run not found.'];
    }
    $recommendations = (array) ($run['recommendations'] ?? []);
    $jobs = (array) ($recommendations['jobs'] ?? []);
    if ($jobs === []) {
        return ['ok' => false, 'message' => 'This profiling run does not have synthesized schedule recommendations yet.'];
    }

    $actor = scheduler_operator_identity_label();
    $beforeSnapshotId = db_scheduler_schedule_snapshot_insert($runId, 'profiling_before_apply', $actor, 'Snapshot captured before applying synthesized scheduler recommendations.', db_sync_schedule_fetch_all());
    $appliedCount = 0;
    foreach (db_sync_schedule_fetch_all() as $row) {
        $jobKey = (string) ($row['job_key'] ?? '');
        $recommendation = $jobs[$jobKey] ?? null;
        if (!is_array($recommendation)) {
            continue;
        }
        if ($preserveManualOverrides && (string) ($row['tuning_mode'] ?? 'automatic') === 'manual') {
            continue;
        }
        $changes = [
            'interval_minutes' => (int) ($recommendation['recommended_interval_minutes'] ?? $row['interval_minutes'] ?? 5),
            'offset_minutes' => (int) ($recommendation['recommended_offset_minutes'] ?? $row['offset_minutes'] ?? 0),
            'timeout_seconds' => (int) ($recommendation['recommended_timeout_seconds'] ?? $row['timeout_seconds'] ?? 300),
            'preferred_max_parallelism' => (int) ($recommendation['preferred_max_parallelism'] ?? $row['preferred_max_parallelism'] ?? 1),
            'last_auto_tune_reason' => 'Applied synthesized baseline from Performance Monitoring Run #' . $runId . '.',
        ];
        if (db_sync_schedule_apply_adjustment((int) ($row['id'] ?? 0), $changes)) {
            db_sync_schedule_update_resource_profile((int) ($row['id'] ?? 0), [
                'resource_class' => (string) ($recommendation['resource_class'] ?? $row['resource_class'] ?? 'medium'),
                'resource_class_confidence' => $row['resource_class_confidence'] ?? 1,
                'telemetry_sample_count' => $row['telemetry_sample_count'] ?? 0,
                'learning_mode' => $row['learning_mode'] ?? 0,
                'allow_parallel' => empty($recommendation['must_run_alone']),
                'prefers_solo' => !empty($recommendation['must_run_alone']) || ((int) ($recommendation['preferred_max_parallelism'] ?? 1) <= 1),
                'must_run_alone' => !empty($recommendation['must_run_alone']),
                'preferred_max_parallelism' => (int) ($recommendation['preferred_max_parallelism'] ?? 1),
                'last_capacity_reason' => 'Synthesized baseline applied from Performance Monitoring Run #' . $runId . '.',
            ] + $row);
            db_scheduler_tuning_action_log($jobKey, 'admin', 'profiling_apply', 'Applied synthesized scheduler baseline from Performance Monitoring Run.', [
                'interval_minutes' => (int) ($row['interval_minutes'] ?? 0),
                'offset_minutes' => (int) ($row['offset_minutes'] ?? 0),
                'timeout_seconds' => (int) ($row['timeout_seconds'] ?? 0),
                'preferred_max_parallelism' => (int) ($row['preferred_max_parallelism'] ?? 1),
            ], $changes, ['profiling_run_id' => $runId]);
            $appliedCount++;
        }
    }

    $rules = [];
    foreach ((array) ($recommendations['bad_pairings'] ?? []) as $pairing) {
        $rules[] = [
            'primary_job_key' => (string) ($pairing['primary_job_key'] ?? ''),
            'secondary_job_key' => (string) ($pairing['secondary_job_key'] ?? ''),
            'rule_type' => 'avoid',
            'notes' => 'Applied from Performance Monitoring Run #' . $runId . '.',
            'metadata' => (array) ($pairing['metrics'] ?? []),
        ];
    }
    foreach ((array) ($recommendations['safe_pairings'] ?? []) as $pairing) {
        $rules[] = [
            'primary_job_key' => (string) ($pairing['primary_job_key'] ?? ''),
            'secondary_job_key' => (string) ($pairing['secondary_job_key'] ?? ''),
            'rule_type' => 'safe',
            'notes' => 'Applied from Performance Monitoring Run #' . $runId . '.',
            'metadata' => (array) ($pairing['metrics'] ?? []),
        ];
    }
    db_scheduler_pairing_rules_replace_from_profiling_run($runId, $rules, 'Applied from Performance Monitoring Run.');

    $afterSnapshotId = db_scheduler_schedule_snapshot_insert($runId, 'profiling_after_apply', $actor, 'Snapshot captured after applying synthesized scheduler recommendations.', db_sync_schedule_fetch_all());
    db_scheduler_profiling_run_update($runId, [
        'run_status' => 'applied',
        'current_phase' => 'applied',
        'applied_at' => gmdate('Y-m-d H:i:s'),
        'finished_at' => gmdate('Y-m-d H:i:s'),
        'applied_snapshot_id' => $beforeSnapshotId,
        'rollback_snapshot_id' => $afterSnapshotId,
        'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), ['message' => 'Synthesized schedule applied to the adaptive scheduler baseline.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);

    return ['ok' => true, 'message' => 'Applied synthesized schedule to ' . $appliedCount . ' job(s).'];
}

function scheduler_profiling_dismiss_recommendations(int $runId): array
{
    $run = scheduler_profiling_decode_run(db_scheduler_profiling_run_fetch($runId));
    if ($run === null) {
        return ['ok' => false, 'message' => 'Profiling run not found.'];
    }

    db_scheduler_profiling_run_update($runId, [
        'run_status' => 'dismissed',
        'current_phase' => 'dismissed',
        'finished_at' => gmdate('Y-m-d H:i:s'),
        'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), ['message' => 'Recommendations were reviewed and dismissed; the current scheduler baseline remains active.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);

    return ['ok' => true, 'message' => 'Profiling recommendations dismissed and the current schedule was kept.'];
}

function scheduler_profiling_rollback_last_apply(): array
{
    foreach (scheduler_profiling_latest_runs(12) as $run) {
        if ((string) ($run['run_status'] ?? '') !== 'applied' || (int) ($run['applied_snapshot_id'] ?? 0) <= 0) {
            continue;
        }
        $snapshot = db_scheduler_schedule_snapshot_fetch((int) $run['applied_snapshot_id']);
        if ($snapshot === null) {
            continue;
        }
        $rows = scheduler_json_decode_assoc($snapshot['schedule_json'] ?? null);
        if ($rows === []) {
            continue;
        }
        foreach ($rows as $row) {
            db_sync_schedule_apply_adjustment((int) ($row['id'] ?? 0), [
                'interval_minutes' => (int) ($row['interval_minutes'] ?? 5),
                'offset_minutes' => (int) ($row['offset_minutes'] ?? 0),
                'timeout_seconds' => (int) ($row['timeout_seconds'] ?? 300),
                'preferred_max_parallelism' => (int) ($row['preferred_max_parallelism'] ?? 1),
                'priority' => (string) ($row['priority'] ?? 'normal'),
                'tuning_mode' => (string) ($row['tuning_mode'] ?? 'automatic'),
                'last_auto_tune_reason' => 'Rolled back to the snapshot captured before Performance Monitoring Run #' . (int) ($run['id'] ?? 0) . ' was applied.',
            ]);
        }
        db_scheduler_pairing_rules_replace_from_profiling_run(0, [], 'Cleared profiling pairing rules during rollback.');
        db_scheduler_schedule_snapshot_insert((int) ($run['id'] ?? 0), 'profiling_rollback_snapshot', scheduler_operator_identity_label(), 'Snapshot captured after rolling back a synthesized schedule.', db_sync_schedule_fetch_all());
        db_scheduler_profiling_run_update((int) ($run['id'] ?? 0), [
            'run_status' => 'rolled_back',
            'current_phase' => 'rolled_back',
            'finished_at' => gmdate('Y-m-d H:i:s'),
        ]);

        return ['ok' => true, 'message' => 'Rolled scheduler settings back to the snapshot captured before the last synthesized apply.'];
    }

    return ['ok' => false, 'message' => 'No applied Performance Monitoring Run snapshot is available to roll back.'];
}

function scheduler_profiling_tick(?callable $logger = null): ?array
{
    $run = scheduler_profiling_active_run();
    if ($run === null) {
        return null;
    }

    try {
        $targets = scheduler_profiling_target_jobs($run);
        $running = db_sync_schedule_fetch_running_jobs();
        $isolatedSamples = db_scheduler_profiling_samples_fetch((int) $run['id'], 'isolated');
        $pairings = db_scheduler_profiling_pairings_fetch((int) $run['id']);

        if ((string) ($run['current_phase'] ?? '') === 'waiting_for_active_jobs') {
            if ($running !== []) {
                db_scheduler_profiling_run_update((int) $run['id'], [
                    'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), [
                        'active_jobs_remaining' => count($running),
                        'running_job_keys' => array_values(array_map(static fn (array $row): string => (string) ($row['job_key'] ?? ''), $running)),
                        'message' => 'Normal scheduler dispatch is paused while active jobs drain before profiling begins.',
                    ]), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                ]);

                return ['mode' => 'profiling', 'run' => $run, 'status' => 'waiting_for_active_jobs', 'jobs_processed' => 0];
            }
            db_scheduler_profiling_run_update((int) $run['id'], [
                'run_status' => 'isolated',
                'current_phase' => 'isolated_baseline',
            ]);
            $run['run_status'] = 'isolated';
            $run['current_phase'] = 'isolated_baseline';
        }

        if ((string) ($run['current_phase'] ?? '') === 'isolated_baseline') {
            $nextJob = scheduler_profiling_next_isolated_job($run, $targets, $isolatedSamples);
            if ($nextJob !== null) {
                $result = scheduler_profiling_run_isolated_sample($run, $nextJob);
                $updatedSamples = db_scheduler_profiling_samples_fetch((int) $run['id'], 'isolated');
                $completedJobs = count(array_unique(array_map(static fn (array $sample): string => (string) ($sample['job_key'] ?? ''), $updatedSamples)));
                db_scheduler_profiling_run_update((int) $run['id'], [
                    'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), [
                        'total_jobs' => count($targets),
                        'isolated_completed_jobs' => $completedJobs,
                        'message' => 'Completed isolated baseline sample ' . (int) ($nextJob['profiling_sample_index'] ?? 1) . ' for ' . (string) ($nextJob['job_key'] ?? '') . '.',
                    ]), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                ]);
                if ($logger !== null) {
                    $logger('profiling.isolated_sample', ['run_id' => (int) $run['id'], 'job' => (string) ($nextJob['job_key'] ?? ''), 'status' => (string) ($result['status'] ?? 'failed')]);
                }

                return ['mode' => 'profiling', 'run' => $run, 'status' => 'isolated_sample_completed', 'jobs_processed' => 1];
            }
            if ((string) ($run['execution_mode'] ?? 'isolated_only') === 'isolated_only' || count($targets) < 2) {
                $recommendations = scheduler_profiling_synthesize_recommendations($run, $targets, $isolatedSamples, $pairings);
                db_scheduler_profiling_run_update((int) $run['id'], [
                    'run_status' => 'awaiting_review',
                    'current_phase' => 'review',
                    'finished_at' => gmdate('Y-m-d H:i:s'),
                    'recommendations_json' => json_encode($recommendations, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                    'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), ['message' => 'Isolated baseline profiling completed and synthesized schedule recommendations are ready for review.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                ]);

                return ['mode' => 'profiling', 'run' => $run, 'status' => 'awaiting_review', 'jobs_processed' => 0];
            }
            db_scheduler_profiling_run_update((int) $run['id'], [
                'run_status' => 'compatibility',
                'current_phase' => 'compatibility_probing',
            ]);
            $run['run_status'] = 'compatibility';
            $run['current_phase'] = 'compatibility_probing';
        }

        if ((string) ($run['current_phase'] ?? '') === 'compatibility_probing') {
            $isolatedSummary = scheduler_profiling_sample_summary($isolatedSamples);
            $candidates = scheduler_profiling_pair_candidates($targets, $isolatedSummary);
            $completed = [];
            foreach ($pairings as $pairing) {
                $completed[(string) ($pairing['primary_job_key'] ?? '') . '|' . (string) ($pairing['secondary_job_key'] ?? '')] = true;
            }
            foreach ($candidates as $candidate) {
                $pairKey = $candidate['primary_job_key'] . '|' . $candidate['secondary_job_key'];
                if (isset($completed[$pairKey])) {
                    continue;
                }
                $primary = $targets[$candidate['primary_job_key']] ?? null;
                $secondary = $targets[$candidate['secondary_job_key']] ?? null;
                if ($primary === null || $secondary === null) {
                    continue;
                }
                $compatibilityCheck = scheduler_jobs_are_compatible(
                    array_merge($primary, ['resource_class' => $isolatedSummary[$candidate['primary_job_key']]['resource_class'] ?? ($primary['resource_class'] ?? 'medium')]),
                    array_merge($secondary, ['resource_class' => $isolatedSummary[$candidate['secondary_job_key']]['resource_class'] ?? ($secondary['resource_class'] ?? 'medium')])
                );
                if (!$compatibilityCheck) {
                    db_scheduler_profiling_pairing_upsert([
                        'profiling_run_id' => (int) $run['id'],
                        'primary_job_key' => $candidate['primary_job_key'],
                        'secondary_job_key' => $candidate['secondary_job_key'],
                        'probe_status' => 'skipped',
                        'compatibility' => 'incompatible',
                        'recommended_parallelism' => 1,
                        'reason_text' => 'Existing solo or incompatibility rules already mark this pairing as unsafe.',
                        'metrics_json' => json_encode(['weight' => $candidate['weight']], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                    ]);
                } else {
                    scheduler_profiling_run_pair_probe($run, $primary, $secondary);
                }
                $updatedPairings = db_scheduler_profiling_pairings_fetch((int) $run['id']);
                db_scheduler_profiling_run_update((int) $run['id'], [
                    'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), [
                        'compatibility_completed_pairs' => count($updatedPairings),
                        'compatibility_total_pairs' => count($candidates),
                        'message' => 'Compatibility probing evaluated ' . $candidate['primary_job_key'] . ' with ' . $candidate['secondary_job_key'] . '.',
                    ]), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                ]);

                return ['mode' => 'profiling', 'run' => $run, 'status' => 'compatibility_probe_completed', 'jobs_processed' => 2];
            }

            $updatedPairings = db_scheduler_profiling_pairings_fetch((int) $run['id']);
            $recommendations = scheduler_profiling_synthesize_recommendations($run, $targets, $isolatedSamples, $updatedPairings);
            db_scheduler_profiling_run_update((int) $run['id'], [
                'run_status' => 'awaiting_review',
                'current_phase' => 'review',
                'finished_at' => gmdate('Y-m-d H:i:s'),
                'recommendations_json' => json_encode($recommendations, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
                'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), ['message' => 'Compatibility probing finished and synthesized schedule recommendations are ready for preview.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            ]);

            return ['mode' => 'profiling', 'run' => $run, 'status' => 'awaiting_review', 'jobs_processed' => 0];
        }
    } catch (Throwable $exception) {
        db_scheduler_profiling_run_update((int) $run['id'], [
            'run_status' => 'failed',
            'current_phase' => 'failed',
            'failure_message' => scheduler_normalize_error_message($exception->getMessage()),
            'finished_at' => gmdate('Y-m-d H:i:s'),
            'progress_json' => json_encode(array_merge((array) ($run['progress'] ?? []), ['message' => 'Profiling failed and the scheduler can resume normal mode on the next tick.']), JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
        ]);

        return ['mode' => 'profiling', 'run' => $run, 'status' => 'failed', 'jobs_processed' => 0, 'error' => $exception->getMessage()];
    }

    return ['mode' => 'profiling', 'run' => $run, 'status' => 'idle', 'jobs_processed' => 0];
}

function scheduler_console_result_label(?string $result): string
{
    $value = trim((string) $result);
    if ($value === '') {
        return 'No runs yet';
    }

    return match ($value) {
        'success' => 'OK',
        'failed' => 'Failed',
        'timeout' => 'Timed out',
        'running' => 'Running',
        'blocked', 'lock_conflict', 'lock_skipped' => 'Blocked',
        'skipped_no_change' => 'Skipped (no change)',
        'skipped_within_freshness_window' => 'Skipped (within freshness window)',
        'forced_refresh_due_to_staleness' => 'Forced refresh',
        'never' => 'No runs yet',
        default => ucwords(str_replace('_', ' ', $value)),
    };
}

function scheduler_console_job_state(array $job): string
{
    if ((int) ($job['lock_conflicts_recent'] ?? 0) > 0 || (float) ($job['last_lock_wait_seconds'] ?? 0.0) > 0.0) {
        return 'blocked';
    }

    $lastResult = (string) ($job['last_result'] ?? '');
    if (in_array($lastResult, ['skipped_no_change', 'skipped_within_freshness_window'], true)) {
        return 'skipped';
    }

    return match ((string) ($job['current_state'] ?? 'waiting')) {
        'running' => 'running',
        default => 'waiting',
    };
}

function scheduler_console_expected_duration_seconds(array $job): int
{
    $candidates = [
        (float) ($job['p95_duration_seconds'] ?? 0.0),
        (float) ($job['average_duration_seconds'] ?? 0.0),
        (float) ($job['last_duration_seconds'] ?? 0.0),
    ];
    $baseline = 0.0;
    foreach ($candidates as $candidate) {
        if ($candidate > $baseline) {
            $baseline = $candidate;
        }
    }

    if ($baseline <= 0.0) {
        $baseline = max(60.0, ((float) ($job['resolved_timeout_seconds'] ?? 300)) * 0.5);
    }

    $expected = (int) ceil($baseline * 1.35);
    $timeoutCap = max(60, (int) ($job['resolved_timeout_seconds'] ?? 300));

    return max(60, min($timeoutCap, $expected));
}

function scheduler_console_detect_job_issues(array $job, int $memoryThresholdBytes = 314572800): array
{
    $issues = [];
    $jobLabel = (string) ($job['label'] ?? $job['job_key'] ?? 'Job');
    $jobKey = (string) ($job['job_key'] ?? '');
    $memoryBytes = max(
        (int) ($job['projected_memory_bytes'] ?? 0),
        (int) ($job['last_memory_peak_bytes'] ?? 0),
        (int) ($job['average_memory_peak_bytes'] ?? 0),
        (int) ($job['p95_memory_peak_bytes'] ?? 0)
    );

    if ($memoryBytes > $memoryThresholdBytes) {
        $issues[] = [
            'severity' => 'high',
            'type' => 'memory',
            'job_key' => $jobKey,
            'job_label' => $jobLabel,
            'title' => 'High memory usage',
            'description' => $jobLabel . ' is using ' . scheduler_format_bytes($memoryBytes) . '.',
            'action_label' => 'Stop & investigate',
        ];
    }

    $lockConflicts = (int) ($job['lock_conflicts_recent'] ?? 0);
    if ($lockConflicts > 0 || (float) ($job['last_lock_wait_seconds'] ?? 0.0) > 0.0) {
        $issues[] = [
            'severity' => 'critical',
            'type' => 'blocked',
            'job_key' => $jobKey,
            'job_label' => $jobLabel,
            'title' => 'Blocked job',
            'description' => $jobLabel . ' is waiting on locks (' . max($lockConflicts, 1) . ' recent conflict' . ($lockConflicts === 1 ? '' : 's') . ').',
            'action_label' => 'Stop & investigate',
        ];
    }

    $startedAt = trim((string) ($job['last_started_at'] ?? ''));
    if ((string) ($job['current_state'] ?? '') === 'running' && $startedAt !== '') {
        $startedUnix = strtotime($startedAt);
        if ($startedUnix !== false) {
            $elapsed = max(0, time() - $startedUnix);
            $expected = scheduler_console_expected_duration_seconds($job);
            if ($elapsed > $expected) {
                $issues[] = [
                    'severity' => 'high',
                    'type' => 'long_running',
                    'job_key' => $jobKey,
                    'job_label' => $jobLabel,
                    'title' => 'Long-running job',
                    'description' => $jobLabel . ' has been running for ' . human_duration_ago($elapsed) . ' (expected under ' . human_duration_ago($expected) . ').',
                    'action_label' => 'Stop & investigate',
                ];
            }
        }
    }

    $lastError = strtolower((string) ($job['last_error'] ?? ''));
    if ($lastError !== '' && (str_contains($lastError, 'out of memory') || str_contains($lastError, 'allowed memory size'))) {
        $issues[] = [
            'severity' => 'critical',
            'type' => 'oom',
            'job_key' => $jobKey,
            'job_label' => $jobLabel,
            'title' => 'OOM event',
            'description' => $jobLabel . ' most recently failed with an out-of-memory error.',
            'action_label' => 'Stop & investigate',
        ];
    }

    return $issues;
}

function scheduler_console_issue_priority(array $issue): int
{
    return match ((string) ($issue['severity'] ?? 'medium')) {
        'critical' => 0,
        'high' => 1,
        'medium' => 2,
        default => 3,
    };
}

function scheduler_console_resource_warnings(array $jobs, array $healthSummary, array $daemonState): array
{
    $warnings = [];
    if ((float) ($healthSummary['memory_budget_ratio'] ?? 0.0) >= 0.85) {
        $warnings[] = [
            'severity' => 'high',
            'title' => 'High memory usage',
            'description' => 'Scheduler memory usage is at ' . number_format(((float) ($healthSummary['memory_budget_ratio'] ?? 0.0)) * 100, 0) . '% of budget.',
        ];
    }

    if ((float) ($healthSummary['cpu_budget_ratio'] ?? 0.0) >= 0.9) {
        $warnings[] = [
            'severity' => 'critical',
            'title' => 'CPU saturation',
            'description' => 'Scheduler CPU usage is at ' . number_format(((float) ($healthSummary['cpu_budget_ratio'] ?? 0.0)) * 100, 0) . '% of budget.',
        ];
    }

    foreach ($jobs as $job) {
        foreach (scheduler_console_detect_job_issues($job) as $issue) {
            if (($issue['type'] ?? '') === 'oom') {
                $warnings[] = [
                    'severity' => 'critical',
                    'title' => 'OOM event',
                    'description' => (string) ($issue['description'] ?? ''),
                ];
                break 2;
            }
        }
    }

    if (($daemonState['derived_status'] ?? 'stopped') !== 'running') {
        $warnings[] = [
            'severity' => 'critical',
            'title' => 'Scheduler attention needed',
            'description' => 'The scheduler daemon is ' . (string) ($daemonState['derived_status'] ?? 'stopped') . '.',
        ];
    }

    return $warnings;
}

function scheduler_console_pipeline_health(array $jobs, array $pipelineSettings): array
{
    $jobMap = [];
    foreach ($jobs as $job) {
        $jobMap[(string) ($job['job_key'] ?? '')] = $job;
    }

    $pipelines = [
        [
            'key' => 'current',
            'label' => 'Current sync',
            'enabled' => ($pipelineSettings['alliance_current_pipeline_enabled'] ?? '1') === '1',
            'jobs' => ['alliance_current_sync', 'market_hub_current_sync'],
        ],
        [
            'key' => 'alliance_history',
            'label' => 'Alliance history',
            'enabled' => ($pipelineSettings['alliance_history_pipeline_enabled'] ?? '1') === '1',
            'jobs' => ['alliance_historical_sync'],
        ],
        [
            'key' => 'hub_history',
            'label' => 'Hub history',
            'enabled' => ($pipelineSettings['hub_history_pipeline_enabled'] ?? '1') === '1',
            'jobs' => ['market_hub_historical_sync'],
        ],
        [
            'key' => 'local_history',
            'label' => 'Local history',
            'enabled' => ($pipelineSettings['market_hub_local_history_pipeline_enabled'] ?? '1') === '1',
            'jobs' => ['market_hub_local_history_sync'],
        ],
    ];

    $results = [];
    foreach ($pipelines as $pipeline) {
        $state = 'OK';
        $summary = 'On track';
        $jobsForPipeline = [];
        foreach ($pipeline['jobs'] as $jobKey) {
            if (isset($jobMap[$jobKey])) {
                $jobsForPipeline[] = $jobMap[$jobKey];
            }
        }

        if (!$pipeline['enabled']) {
            $state = 'OK';
            $summary = 'Disabled';
        } elseif ($jobsForPipeline === []) {
            $state = 'Blocked';
            $summary = 'No registered jobs';
        } else {
            $blocked = false;
            $delayed = false;
            foreach ($jobsForPipeline as $job) {
                $issues = scheduler_console_detect_job_issues($job);
                foreach ($issues as $issue) {
                    if (in_array((string) ($issue['type'] ?? ''), ['blocked', 'oom'], true)) {
                        $blocked = true;
                        break 2;
                    }
                    if (($issue['type'] ?? '') === 'long_running') {
                        $delayed = true;
                    }
                }

                if (!empty($job['degraded']) || (string) ($job['last_result'] ?? '') === 'failed') {
                    $blocked = true;
                    break;
                }

                if ((int) ($job['lateness_seconds'] ?? 0) >= max(60, ((int) ($job['interval_minutes'] ?? 1) * 60))) {
                    $delayed = true;
                }
            }

            if ($blocked) {
                $state = 'Blocked';
                $summary = 'Needs intervention';
            } elseif ($delayed) {
                $state = 'Delayed';
                $summary = 'Behind schedule';
            }
        }

        $results[] = [
            'key' => $pipeline['key'],
            'label' => $pipeline['label'],
            'state' => $state,
            'summary' => $summary,
        ];
    }

    return $results;
}

function scheduler_console_system_status(array $healthSummary, array $resourceWarnings, array $activeIssues): array
{
    $status = 'healthy';
    $reason = 'All key scheduler signals are within expected limits.';

    $hasCritical = array_filter($resourceWarnings, static fn (array $warning): bool => (string) ($warning['severity'] ?? '') === 'critical');
    $criticalIssues = array_filter($activeIssues, static fn (array $issue): bool => (string) ($issue['severity'] ?? '') === 'critical');

    if ($hasCritical !== [] || $criticalIssues !== [] || in_array((string) ($healthSummary['pressure'] ?? 'healthy'), ['congested', 'overload_protection'], true)) {
        $status = in_array((string) ($healthSummary['pressure'] ?? 'healthy'), ['overload_protection'], true) || $criticalIssues !== [] ? 'critical' : 'degraded';
        $reason = $status === 'critical'
            ? 'Multiple jobs need immediate attention.'
            : 'Some jobs are delayed or resource pressure is elevated.';
    } elseif ((float) ($healthSummary['cpu_budget_ratio'] ?? 0.0) >= 0.7 || (float) ($healthSummary['memory_budget_ratio'] ?? 0.0) >= 0.7 || $activeIssues !== []) {
        $status = 'degraded';
        $reason = 'Resource pressure or job performance is trending above normal.';
    }

    return [
        'label' => ucfirst($status),
        'status' => $status,
        'reason' => $reason,
    ];
}

function sync_schedule_settings_view_model(): array
{
    scheduler_registry_bootstrap();
    $selectedProfile = scheduler_selected_operational_profile();
    $profileMatrix = scheduler_operational_profile_matrix($selectedProfile);

    try {
        $rows = db_sync_schedule_fetch_all();
    } catch (Throwable) {
        $rows = [];
    }

    $definitions = data_sync_schedule_job_definitions();
    try {
        $currentStatusMap = db_scheduler_job_current_status_fetch_map(array_map(static fn (array $row): string => (string) ($row['job_key'] ?? ''), $rows));
        $recentActions = db_scheduler_tuning_actions_recent(12);
        $outcomeSummary = db_sync_schedule_recent_outcomes_summary(180);
        $recentPlannerDecisions = db_scheduler_planner_decisions_recent(20);
        $recentResourceMetrics = db_scheduler_resource_metrics_recent_all(20);
        $partitionDiagnostics = db_market_history_partition_diagnostics();
    } catch (Throwable) {
        $currentStatusMap = [];
        $recentActions = [];
        $outcomeSummary = [];
        $recentPlannerDecisions = [];
        $recentResourceMetrics = [];
        $partitionDiagnostics = ['partitioned_tables' => [], 'evaluation_tables' => []];
    }

    $configuredJobs = [];
    $discoveredJobs = [];
    $internalJobs = [];
    $pipelineSettings = data_sync_pipeline_settings_view(get_settings(array_keys(data_sync_pipeline_setting_defaults())));
    $liveCapacity = scheduler_live_capacity_snapshot();
    $recentDecisionCounts = scheduler_recent_planner_decision_counts();
    $daemonState = scheduler_daemon_health_summary();
    $healthSummary = [
        'total_jobs' => 0,
        'running_jobs' => 0,
        'waiting_jobs' => 0,
        'stopped_jobs' => 0,
        'degraded_jobs' => 0,
        'lock_conflicts' => 0,
        'late_jobs' => 0,
        'cpu_budget_percent' => (float) ($liveCapacity['cpu_budget_percent'] ?? 0.0),
        'memory_budget_bytes' => (int) ($liveCapacity['memory_budget_bytes'] ?? 0),
        'current_cpu_used_percent' => (float) ($liveCapacity['current_cpu_used_percent'] ?? 0.0),
        'current_memory_used_bytes' => (int) ($liveCapacity['current_memory_used_bytes'] ?? 0),
        'cpu_budget_ratio' => (float) ($liveCapacity['cpu_budget_ratio'] ?? 0.0),
        'memory_budget_ratio' => (float) ($liveCapacity['memory_budget_ratio'] ?? 0.0),
        'timeout_rate' => (float) ($liveCapacity['timeout_rate'] ?? 0.0),
        'failure_rate' => (float) ($liveCapacity['failure_rate'] ?? 0.0),
        'current_concurrency_level' => (int) ($liveCapacity['running_jobs'] ?? 0),
        'max_concurrent_jobs' => (int) ($liveCapacity['max_concurrent_jobs'] ?? 1),
        'reserved_critical_cpu_percent' => (float) ($liveCapacity['reserved_critical_cpu_percent'] ?? 0.0),
        'reserved_critical_memory_bytes' => (int) ($liveCapacity['reserved_critical_memory_bytes'] ?? 0),
        'pressure' => (string) ($liveCapacity['pressure'] ?? 'healthy'),
        'daemon' => $daemonState,
    ];

    foreach ($rows as $row) {
        $jobKey = trim((string) ($row['job_key'] ?? ''));
        if ($jobKey === '') {
            continue;
        }

        if (scheduler_is_dedicated_worker_job($jobKey)) {
            continue;
        }

        $definition = $definitions[$jobKey] ?? [
            'label' => ucwords(str_replace('_', ' ', $jobKey)),
            'enabled_key' => $jobKey . '_enabled',
            'interval_minutes_key' => $jobKey . '_interval_minutes',
            'offset_minutes_key' => $jobKey . '_offset_minutes',
            'priority_key' => $jobKey . '_priority',
            'timeout_key' => $jobKey . '_timeout_seconds',
            'mode_key' => $jobKey . '_tuning_mode',
            'default_interval_minutes' => 30,
            'default_offset_minutes' => (int) ($row['offset_minutes'] ?? 0),
            'priority' => 'normal',
            'timeout_seconds' => 300,
            'concurrency_policy' => 'single',
            'tuning_mode' => 'automatic',
            'explicitly_configured' => false,
            'discovery_classification' => scheduler_is_internal_mechanic_job($jobKey) ? 'internal' : 'operational',
        ];

        $statusProjection = $currentStatusMap[$jobKey] ?? [];
        $dependencyMetadata = scheduler_dependency_metadata($jobKey);
        $changeDetection = is_array($statusProjection['last_change_detection'] ?? null) ? $statusProjection['last_change_detection'] : [];
        $executionContext = is_array($statusProjection['last_execution_context'] ?? null) ? $statusProjection['last_execution_context'] : [];
        $jobRunStats = db_sync_schedule_recent_job_run_stats($jobKey, 20);
        $currentState = (string) ($row['current_state'] ?? ((int) ($row['enabled'] ?? 1) === 1 ? 'waiting' : 'stopped'));
        $nextDueAt = $row['next_due_at'] ?? $row['next_run_at'] ?? null;
        $latenessSeconds = $nextDueAt !== null ? max(0, time() - (int) strtotime((string) $nextDueAt)) : 0;
        $timeoutResolution = scheduler_resolve_job_timeout($jobKey, $row, $definition);
        $lastAction = null;
        foreach ($recentActions as $action) {
            if (($action['job_key'] ?? '') === $jobKey) {
                $lastAction = $action;
                break;
            }
        }

        $isDegraded = !empty($row['degraded_until']) && strtotime((string) $row['degraded_until']) > time();
        $card = [
            'job_key' => $jobKey,
            'label' => (string) ($definition['label'] ?? $jobKey),
            'enabled' => (int) ($row['enabled'] ?? 1),
            'priority' => (string) ($row['priority'] ?? ($definition['priority'] ?? 'normal')),
            'interval_minutes' => (int) ($row['interval_minutes'] ?? ($definition['default_interval_minutes'] ?? 30)),
            'offset_minutes' => (int) ($row['offset_minutes'] ?? ($definition['default_offset_minutes'] ?? 0)),
            'next_due_at' => $nextDueAt,
            'last_started_at' => $statusProjection['last_started_at'] ?? $row['last_started_at'] ?? null,
            'last_finished_at' => $statusProjection['last_finished_at'] ?? $row['last_finished_at'] ?? null,
            'last_duration_seconds' => $row['last_duration_seconds'] ?? null,
            'average_duration_seconds' => $row['average_duration_seconds'] ?? $jobRunStats['average_duration_seconds'],
            'p95_duration_seconds' => $row['p95_duration_seconds'] ?? $jobRunStats['p95_duration_seconds'],
            'timeout_seconds' => (int) ($row['timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300)),
            'resolved_timeout_seconds' => (int) ($timeoutResolution['resolved_timeout_seconds'] ?? ($row['timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300))),
            'enforced_timeout_seconds' => (int) ($timeoutResolution['enforced_timeout_seconds'] ?? ($row['timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300))),
            'timeout_source' => (string) ($timeoutResolution['timeout_source'] ?? 'unknown'),
            'definition_timeout_seconds' => (int) ($timeoutResolution['definition_timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300)),
            'schedule_timeout_seconds' => isset($timeoutResolution['schedule_timeout_seconds']) && $timeoutResolution['schedule_timeout_seconds'] !== null
                ? (int) $timeoutResolution['schedule_timeout_seconds']
                : null,
            'global_default_timeout_seconds' => (int) ($timeoutResolution['global_default_timeout_seconds'] ?? scheduler_global_timeout_default_seconds()),
            'env_timeout_seconds' => isset($timeoutResolution['env_timeout_seconds']) && $timeoutResolution['env_timeout_seconds'] !== null
                ? (int) $timeoutResolution['env_timeout_seconds']
                : null,
            'last_result' => (string) ($statusProjection['latest_status'] ?? $row['last_result'] ?? $row['last_status'] ?? 'never'),
            'last_error' => (string) ($statusProjection['last_failure_message'] ?? $row['last_error'] ?? ''),
            'current_state' => $currentState,
            'allow_backfill' => !empty($row['allow_backfill']) || !empty($definition['allow_backfill']),
            'backfill_priority' => (string) ($row['backfill_priority'] ?? ($definition['backfill_priority'] ?? ($row['priority'] ?? ($definition['priority'] ?? 'normal')))),
            'min_backfill_gap_seconds' => (int) ($row['min_backfill_gap_seconds'] ?? ($definition['min_backfill_gap_seconds'] ?? 900)),
            'max_early_start_seconds' => (int) ($row['max_early_start_seconds'] ?? ($definition['max_early_start_seconds'] ?? 0)),
            'last_execution_mode' => (string) ($row['last_execution_mode'] ?? 'scheduled'),
            'concurrency_policy' => (string) ($row['concurrency_policy'] ?? ($definition['concurrency_policy'] ?? 'single')),
            'tuning_mode' => (string) ($row['tuning_mode'] ?? ($definition['tuning_mode'] ?? 'automatic')),
            'value_source' => ((string) ($row['tuning_mode'] ?? 'automatic')) === 'manual' ? 'manual' : (!empty($row['last_auto_tuned_at']) ? 'auto-tuned' : 'baseline'),
            'last_auto_tune_reason' => (string) ($row['last_auto_tune_reason'] ?? ''),
            'last_auto_tuned_at' => $row['last_auto_tuned_at'] ?? null,
            'skips_recent' => (int) (($statusProjection['recent_skip_count'] ?? 0) + ($statusProjection['recent_deferral_count'] ?? 0)),
            'lock_conflicts_recent' => (int) ($statusProjection['recent_lock_conflict_count'] ?? 0),
            'timeout_count_recent' => (int) ($statusProjection['recent_timeout_count'] ?? 0),
            'recent_deferral_count' => (int) ($statusProjection['recent_deferral_count'] ?? 0),
            'lateness_seconds' => $latenessSeconds,
            'degraded' => $isDegraded,
            'explicitly_configured' => !empty($row['explicitly_configured']),
            'discovered_from_code' => !empty($row['discovered_from_code']),
            'enabled_key' => (string) $definition['enabled_key'],
            'interval_minutes_key' => (string) $definition['interval_minutes_key'],
            'offset_minutes_key' => (string) $definition['offset_minutes_key'],
            'priority_key' => (string) $definition['priority_key'],
            'timeout_key' => (string) $definition['timeout_key'],
            'mode_key' => (string) $definition['mode_key'],
            'latest_action' => $lastAction,
            'recent_outcomes' => $outcomeSummary[$jobKey] ?? ['failed_runs' => 0, 'successful_runs' => 0, 'total_runs' => 0],
            'discovery_classification' => (string) ($definition['discovery_classification'] ?? (scheduler_is_internal_mechanic_job($jobKey) ? 'internal' : 'operational')),
            'protected_offset' => scheduler_is_protected_job($jobKey),
            'profile_interval_minutes' => (int) (($profileMatrix['jobs'][$jobKey]['interval_minutes'] ?? ($definition['default_interval_minutes'] ?? 30))),
            'profile_timeout_seconds' => (int) (($profileMatrix['jobs'][$jobKey]['timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300))),
            'profile_priority' => (string) (($profileMatrix['jobs'][$jobKey]['priority'] ?? ($definition['priority'] ?? 'normal'))),
            'change_aware' => !empty($statusProjection['change_aware']) || !empty($dependencyMetadata['change_aware']),
            'supports_no_change_skip' => !empty($dependencyMetadata['supports_no_change_skip']),
            'freshness_ceiling_seconds' => $dependencyMetadata['freshness_ceiling_seconds'],
            'minimum_rerun_gap_seconds' => $dependencyMetadata['minimum_rerun_gap_seconds'],
            'dependency_metadata' => $dependencyMetadata,
            'last_upstream_change_seen' => $changeDetection['last_upstream_change_seen'] ?? null,
            'last_no_change_skip_at' => $statusProjection['last_no_change_skip_at'] ?? null,
            'last_no_change_reason' => $statusProjection['last_no_change_reason'] ?? null,
            'materialization_trigger' => $executionContext['trigger'] ?? $changeDetection['trigger'] ?? null,
            'last_materialization_input_version' => $executionContext['input_fingerprint'] ?? $changeDetection['input_fingerprint'] ?? null,
            'last_materialization_output_version' => ((array) ($executionContext['output_versions'] ?? [])) !== []
                ? hash('sha256', json_encode($executionContext['output_versions'], JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE))
                : null,
            'last_change_detection' => $changeDetection,
            'last_execution_context' => $executionContext,
            'upstream_dependency_labels' => array_values(array_filter(array_map(
                static fn (array $signal): string => (string) ($signal['label'] ?? $signal['signal_key'] ?? ''),
                (array) ($dependencyMetadata['upstream_signals'] ?? [])
            ))),
        ];
        $resourceProfile = scheduler_job_recent_resource_profile($jobKey, $row + ['status_projection' => $statusProjection]);
        $urgency = scheduler_job_urgency_snapshot($row, $recentDecisionCounts);
        $card += [
            'resource_class' => (string) ($row['resource_class'] ?? $resourceProfile['resource_class'] ?? 'medium'),
            'resource_class_confidence' => (float) ($row['resource_class_confidence'] ?? $resourceProfile['resource_class_confidence'] ?? 0.0),
            'learning_mode' => !empty($row['learning_mode']) || !empty($resourceProfile['learning_mode']),
            'telemetry_sample_count' => (int) ($row['telemetry_sample_count'] ?? $resourceProfile['sample_count'] ?? 0),
            'last_cpu_percent' => $row['last_cpu_percent'] ?? $resourceProfile['last_cpu_percent'] ?? null,
            'average_cpu_percent' => $row['average_cpu_percent'] ?? $resourceProfile['average_cpu_percent'] ?? null,
            'p95_cpu_percent' => $row['p95_cpu_percent'] ?? $resourceProfile['p95_cpu_percent'] ?? null,
            'last_memory_peak_bytes' => $row['last_memory_peak_bytes'] ?? $resourceProfile['last_memory_peak_bytes'] ?? null,
            'average_memory_peak_bytes' => $row['average_memory_peak_bytes'] ?? $resourceProfile['average_memory_peak_bytes'] ?? null,
            'p95_memory_peak_bytes' => $row['p95_memory_peak_bytes'] ?? $resourceProfile['p95_memory_peak_bytes'] ?? null,
            'last_queue_wait_seconds' => $row['last_queue_wait_seconds'] ?? $resourceProfile['last_queue_wait_seconds'] ?? null,
            'last_lock_wait_seconds' => $row['last_lock_wait_seconds'] ?? $resourceProfile['last_lock_wait_seconds'] ?? null,
            'average_lock_wait_seconds' => $row['average_lock_wait_seconds'] ?? $resourceProfile['average_lock_wait_seconds'] ?? null,
            'recent_timeout_rate' => $row['recent_timeout_rate'] ?? $resourceProfile['recent_timeout_rate'] ?? null,
            'recent_failure_rate' => $row['recent_failure_rate'] ?? $resourceProfile['recent_failure_rate'] ?? null,
            'allow_parallel' => !empty($row['allow_parallel']) || !empty($resourceProfile['allow_parallel']),
            'prefers_solo' => !empty($row['prefers_solo']) || !empty($resourceProfile['prefers_solo']),
            'must_run_alone' => !empty($row['must_run_alone']) || !empty($resourceProfile['must_run_alone']),
            'preferred_max_parallelism' => (int) ($row['preferred_max_parallelism'] ?? $resourceProfile['preferred_max_parallelism'] ?? 1),
            'projected_cpu_percent' => $row['current_projected_cpu_percent'] ?? $resourceProfile['projection_cpu_percent'] ?? null,
            'projected_memory_bytes' => $row['current_projected_memory_bytes'] ?? $resourceProfile['projection_memory_bytes'] ?? null,
            'latest_allowed_start_at' => scheduler_latest_allowed_start_at($row),
            'urgency_score' => $urgency['urgency_score'] ?? 0,
            'starvation_indicator' => !empty($urgency['starvation_indicator']),
            'queue_wait_seconds' => $urgency['queue_wait_seconds'] ?? 0,
            'seconds_to_latest_allowed_start' => $urgency['seconds_to_latest_allowed_start'] ?? null,
            'current_pressure_state' => (string) ($statusProjection['current_pressure_state'] ?? $row['current_pressure_state'] ?? $liveCapacity['pressure'] ?? 'healthy'),
            'capacity_reason' => (string) ($statusProjection['last_planner_reason_text'] ?? $row['last_capacity_reason'] ?? ''),
            'status_projection' => $statusProjection,
        ];
        $jobIssues = scheduler_console_detect_job_issues($card);
        $card['status_label'] = scheduler_console_result_label((string) ($card['last_result'] ?? 'never'));
        $card['job_state'] = scheduler_console_job_state($card);
        $card['issues'] = $jobIssues;
        $card['needs_attention_action'] = ((string) ($card['last_result'] ?? '') === 'failed') || $jobIssues !== [];

        if ($card['discovery_classification'] === 'internal') {
            $internalJobs[] = $card;
        } elseif ($card['explicitly_configured']) {
            $healthSummary['total_jobs']++;
            $healthSummary[$currentState . '_jobs'] = (int) ($healthSummary[$currentState . '_jobs'] ?? 0) + 1;
            $healthSummary['lock_conflicts'] += $card['lock_conflicts_recent'];
            if ($card['lateness_seconds'] >= 60) {
                $healthSummary['late_jobs']++;
            }
            if ($isDegraded) {
                $healthSummary['degraded_jobs']++;
            }
            $configuredJobs[] = $card;
        } else {
            $healthSummary['total_jobs']++;
            $healthSummary[$currentState . '_jobs'] = (int) ($healthSummary[$currentState . '_jobs'] ?? 0) + 1;
            $healthSummary['lock_conflicts'] += $card['lock_conflicts_recent'];
            if ($card['lateness_seconds'] >= 60) {
                $healthSummary['late_jobs']++;
            }
            if ($isDegraded) {
                $healthSummary['degraded_jobs']++;
            }
            $discoveredJobs[] = $card;
        }
    }

    $allOperationalJobs = array_merge($configuredJobs, $discoveredJobs);
    $allIssues = [];
    foreach ($allOperationalJobs as $job) {
        foreach (scheduler_console_detect_job_issues($job) as $issue) {
            $allIssues[] = $issue;
        }
    }
    usort($allIssues, static function (array $a, array $b): int {
        return scheduler_console_issue_priority($a) <=> scheduler_console_issue_priority($b)
            ?: strcmp((string) ($a['job_label'] ?? ''), (string) ($b['job_label'] ?? ''));
    });

    $healthSummary['pressure'] = scheduler_pressure_label($healthSummary);
    $resourceWarnings = scheduler_console_resource_warnings($allOperationalJobs, $healthSummary, $daemonState);
    $pipelineHealth = scheduler_console_pipeline_health($allOperationalJobs, $pipelineSettings);
    $runtimeDatasetCards = supplycore_settings_runtime_dataset_cards();
    $datasetFailures = array_values(array_filter($runtimeDatasetCards, static fn (array $card): bool => !empty($card['show_latest_failure'])));
    $systemStatus = scheduler_console_system_status($healthSummary, $resourceWarnings, $allIssues);
    if ($datasetFailures !== []) {
        $systemStatus = [
            'label' => 'Needs attention',
            'status' => 'degraded',
            'reason' => 'One or more user-facing datasets most recently failed to refresh.',
        ];
    }
    $activeProfilingRun = scheduler_profiling_active_run();
    $profilingRuns = scheduler_profiling_latest_runs();
    $profilingPreviewRun = $activeProfilingRun;
    if ($profilingPreviewRun === null) {
        foreach ($profilingRuns as $profilingRunRow) {
            if (is_array($profilingRunRow['recommendations'] ?? null) && ((array) ($profilingRunRow['recommendations']['jobs'] ?? [])) !== []) {
                $profilingPreviewRun = $profilingRunRow;
                break;
            }
        }
    }

    return [
        'selected_profile' => $selectedProfile,
        'profile_options' => scheduler_operational_profile_options(),
        'profile_runtime' => (array) ($profileMatrix['runtime'] ?? []),
        'configured_jobs' => $configuredJobs,
        'discovered_jobs' => $discoveredJobs,
        'internal_jobs' => $internalJobs,
        'health_summary' => $healthSummary,
        'daemon_state' => $daemonState,
        'recent_actions' => $recentActions,
        'recent_planner_decisions' => $recentPlannerDecisions,
        'recent_resource_metrics' => $recentResourceMetrics,
        'partition_diagnostics' => $partitionDiagnostics,
        'running_jobs' => (array) ($liveCapacity['running_jobs_detail'] ?? []),
        'live_capacity' => $liveCapacity,
        'pipeline_settings' => $pipelineSettings,
        'system_status' => $systemStatus,
        'active_issues' => array_slice($allIssues, 0, 3),
        'active_issue_count' => count($allIssues),
        'resource_warnings' => $resourceWarnings,
        'pipeline_health' => $pipelineHealth,
        'runtime_dataset_cards' => $runtimeDatasetCards,
        'profiling_active_run' => $activeProfilingRun,
        'profiling_runs' => $profilingRuns,
        'profiling_preview_run' => $profilingPreviewRun,
        'profiling_samples' => $profilingPreviewRun !== null ? db_scheduler_profiling_samples_fetch((int) ($profilingPreviewRun['id'] ?? 0)) : [],
        'profiling_pairings' => $profilingPreviewRun !== null ? db_scheduler_profiling_pairings_fetch((int) ($profilingPreviewRun['id'] ?? 0)) : [],
        'schedule_snapshots' => db_scheduler_schedule_snapshots_recent(8),
        'change_aware_summary' => [
            'skipped_no_change' => count(array_filter(array_merge($configuredJobs, $discoveredJobs), static fn (array $job): bool => (string) ($job['last_result'] ?? '') === 'skipped_no_change')),
            'skipped_within_freshness_window' => count(array_filter(array_merge($configuredJobs, $discoveredJobs), static fn (array $job): bool => (string) ($job['last_result'] ?? '') === 'skipped_within_freshness_window')),
            'forced_refresh_due_to_staleness' => count(array_filter(array_merge($configuredJobs, $discoveredJobs), static fn (array $job): bool => (string) ($job['last_result'] ?? '') === 'forced_refresh_due_to_staleness')),
            'change_aware_jobs' => count(array_filter(array_merge($configuredJobs, $discoveredJobs), static fn (array $job): bool => !empty($job['change_aware']))),
        ],
    ];
}

function scheduler_request_bool(array $request, string $key): int
{
    return sanitize_sync_schedule_enabled($request[$key] ?? null);
}

function scheduler_request_int(array $request, string $key, int $default, int $min, int $max): int
{
    $value = (int) ($request[$key] ?? $default);

    return max($min, min($max, $value));
}

function scheduler_apply_operational_profile(string $profile): bool
{
    $safeProfile = sanitize_scheduler_operational_profile($profile);
    $definitions = data_sync_schedule_job_definitions();
    $profileMatrix = scheduler_operational_profile_matrix($safeProfile);
    $profileJobs = (array) ($profileMatrix['jobs'] ?? []);

    try {
        db_transaction(function () use ($safeProfile, $definitions, $profileJobs): void {
            foreach ($definitions as $jobKey => $definition) {
                if (!($definition['explicitly_configured'] ?? false)) {
                    continue;
                }

                $jobProfile = (array) ($profileJobs[$jobKey] ?? []);
                $intervalMinutes = max(1, min(1440, (int) ($jobProfile['interval_minutes'] ?? ($definition['default_interval_minutes'] ?? 30))));
                $timeoutSeconds = max(30, min(7200, (int) ($jobProfile['timeout_seconds'] ?? ($definition['timeout_seconds'] ?? 300))));
                $priority = trim((string) ($jobProfile['priority'] ?? ($definition['priority'] ?? 'normal')));
                if (!array_key_exists($priority, scheduler_priority_options())) {
                    $priority = (string) ($definition['priority'] ?? 'normal');
                }
                $offsetMinutes = max(0, min(1439, (int) ($definition['default_offset_minutes'] ?? 0)));

                db_sync_schedule_upsert(
                    $jobKey,
                    1,
                    $intervalMinutes * 60,
                    $offsetMinutes * 60,
                    [
                        'interval_minutes' => $intervalMinutes,
                        'offset_minutes' => $offsetMinutes,
                        'priority' => $priority,
                        'timeout_seconds' => $timeoutSeconds,
                        'concurrency_policy' => (string) ($definition['concurrency_policy'] ?? 'single'),
                        'tuning_mode' => 'automatic',
                        'discovered_from_code' => 1,
                        'explicitly_configured' => true,
                        'last_auto_tune_reason' => 'Applied scheduler profile "' . $safeProfile . '" from Settings.',
                    ]
                );

                db_scheduler_tuning_action_log(
                    $jobKey,
                    'admin',
                    'profile_apply',
                    'Admin applied the "' . $safeProfile . '" scheduler profile from the sync control panel.',
                    [],
                    [
                        'profile' => $safeProfile,
                        'interval_minutes' => $intervalMinutes,
                        'offset_minutes' => $offsetMinutes,
                        'priority' => $priority,
                        'timeout_seconds' => $timeoutSeconds,
                        'tuning_mode' => 'automatic',
                    ],
                    []
                );
            }
        });
    } catch (Throwable) {
        return false;
    }

    return true;
}

function save_data_sync_settings(array $request): array
{
    $settingsSaved = save_settings(data_sync_settings_from_request($request));

    if ($settingsSaved) {
        return [
            'ok' => true,
            'message' => 'Settings saved successfully. Continuous worker services keep their own recurring job registry, so this page now saves only the shared app settings used by sync jobs.',
        ];
    }

    return [
        'ok' => false,
        'message' => 'Settings were not persisted. Please verify the database schema is up to date and that the web app can write to app_settings.',
    ];
}

function sanitize_redis_host(?string $value): string
{
    $host = trim((string) $value);

    return $host !== '' ? mb_substr($host, 0, 190) : (string) config('redis.host', '127.0.0.1');
}

function sanitize_redis_prefix(?string $value): string
{
    $prefix = preg_replace('/[^a-z0-9:_-]+/i', '-', trim((string) $value)) ?? '';
    $prefix = trim($prefix, '-:');

    return $prefix !== '' ? mb_substr($prefix, 0, 80) : (string) config('redis.prefix', 'supplycore');
}

function sanitize_redis_port(mixed $value): string
{
    return (string) max(1, min(65535, (int) $value));
}

function sanitize_redis_database(mixed $value): string
{
    return (string) max(0, min(15, (int) $value));
}

function data_sync_settings_from_request(array $request): array
{
    $allianceCurrentEnabled = sanitize_pipeline_enabled($request['alliance_current_pipeline_enabled'] ?? null);
    $allianceHistoryEnabled = sanitize_pipeline_enabled($request['alliance_history_pipeline_enabled'] ?? null);
    $hubHistoryEnabled = sanitize_pipeline_enabled($request['hub_history_pipeline_enabled'] ?? null);
    $localHistoryEnabled = sanitize_pipeline_enabled($request['market_hub_local_history_pipeline_enabled'] ?? null);

    $baselineDate = sync_automation_enabled_since_date();

    return [
        'scheduler_operational_profile' => sanitize_scheduler_operational_profile($request['scheduler_operational_profile'] ?? 'medium'),
        'incremental_updates_enabled' => sanitize_pipeline_enabled($request['incremental_updates_enabled'] ?? null),
        'incremental_strategy' => sanitize_incremental_strategy($request['incremental_strategy'] ?? null),
        'incremental_delete_policy' => sanitize_incremental_delete_policy($request['incremental_delete_policy'] ?? null),
        'incremental_chunk_size' => sanitize_incremental_chunk_size($request['incremental_chunk_size'] ?? null),
        'alliance_current_pipeline_enabled' => $allianceCurrentEnabled,
        'alliance_history_pipeline_enabled' => $allianceHistoryEnabled,
        'hub_history_pipeline_enabled' => $hubHistoryEnabled,
        'market_hub_local_history_pipeline_enabled' => $localHistoryEnabled,
        'sync_automation_enabled_since' => $baselineDate,
        'alliance_current_backfill_start_date' => data_sync_backfill_start_date('alliance_current_backfill_start_date', $allianceCurrentEnabled === '1', $baselineDate),
        'alliance_history_backfill_start_date' => data_sync_backfill_start_date('alliance_history_backfill_start_date', $allianceHistoryEnabled === '1', $baselineDate),
        'hub_history_backfill_start_date' => data_sync_backfill_start_date('hub_history_backfill_start_date', $hubHistoryEnabled === '1', $baselineDate),
        'market_history_retention_raw_days' => sanitize_retention_days($request['market_history_retention_raw_days'] ?? null, 30),
        'market_history_retention_hourly_days' => sanitize_retention_days($request['market_history_retention_hourly_days'] ?? null, 90),
        'market_history_retention_daily_days' => sanitize_market_history_daily_retention_days($request['market_history_retention_daily_days'] ?? null, 365),
        'static_data_source_url' => sanitize_static_data_source_url($request['static_data_source_url'] ?? null),
        'redis_cache_enabled' => isset($request['redis_cache_enabled']) ? '1' : '0',
        'redis_locking_enabled' => isset($request['redis_locking_enabled']) ? '1' : '0',
        'redis_host' => sanitize_redis_host($request['redis_host'] ?? null),
        'redis_port' => sanitize_redis_port($request['redis_port'] ?? config('redis.port', 6379)),
        'redis_database' => sanitize_redis_database($request['redis_database'] ?? config('redis.database', 0)),
        'redis_password' => trim((string) ($request['redis_password'] ?? '')),
        'redis_prefix' => sanitize_redis_prefix($request['redis_prefix'] ?? null),
    ];
}

function market_compare_setting_float(string $key, float $default, float $min, float $max): float
{
    $raw = get_setting($key, (string) $default);
    $value = (float) $raw;

    return max($min, min($max, $value));
}

function market_compare_setting_int(string $key, int $default, int $min, int $max): int
{
    $raw = get_setting($key, (string) $default);
    $value = (int) $raw;

    return max($min, min($max, $value));
}

function market_compare_thresholds(): array
{
    return [
        'deviation_percent' => market_compare_setting_float('market_compare_deviation_percent', 5.0, 0.1, 100.0),
        'min_alliance_sell_volume' => market_compare_setting_int('market_compare_min_alliance_sell_volume', 50, 0, 5000000),
        'min_alliance_sell_orders' => market_compare_setting_int('market_compare_min_alliance_sell_orders', 3, 0, 100000),
    ];
}


function market_comparison_context(): array
{
    return [
        'alliance_destination' => selected_station_name('alliance_station_id') ?? 'Operational destination not configured',
        'reference_hub' => market_hub_reference_name(),
    ];
}

function market_comparison_snapshot_key(): string
{
    return 'market_comparison_summaries';
}

function loss_demand_snapshot_key(): string
{
    return 'loss_demand_summaries';
}

function dashboard_snapshot_key(): string
{
    return 'dashboard_summaries';
}

function market_comparison_outcomes_build(array $typeIds = []): array
{
    $thresholds = market_compare_thresholds();
    $evaluatedRows = [];

    foreach (market_compare_aggregates($typeIds) as $row) {
        $evaluatedRows[] = market_compare_evaluate_row($row, $thresholds);
    }

    $evaluatedRows = item_scope_filter_rows(
        $evaluatedRows,
        static fn (array $row): int => (int) ($row['type_id'] ?? 0)
    );

    return [
        'thresholds' => $thresholds,
        'rows' => array_values($evaluatedRows),
        'in_both_markets' => array_values(array_filter($evaluatedRows, static fn (array $row): bool => (bool) $row['in_both_markets'])),
        'missing_in_alliance' => array_values(array_filter($evaluatedRows, static fn (array $row): bool => (bool) $row['missing_in_alliance'])),
        'overpriced_in_alliance' => array_values(array_filter($evaluatedRows, static fn (array $row): bool => (bool) $row['overpriced_in_alliance'])),
        'underpriced_in_alliance' => array_values(array_filter($evaluatedRows, static fn (array $row): bool => (bool) $row['underpriced_in_alliance'])),
        'weak_or_missing_alliance_stock' => array_values(array_filter($evaluatedRows, static fn (array $row): bool => (bool) ($row['weak_alliance_stock'] ?? false) || (bool) ($row['missing_in_alliance'] ?? false))),
    ];
}

function market_comparison_snapshot_payload(): array
{
    return supplycore_materialized_snapshot_read_or_bootstrap(
        market_comparison_snapshot_key(),
        static fn (): array => market_comparison_outcomes_build(),
        'market-comparison-bootstrap'
    );
}

function market_comparison_refresh_summary(string $reason = 'manual'): array
{
    supplycore_materialized_snapshot_mark_updating(market_comparison_snapshot_key(), $reason);
    $snapshot = market_comparison_outcomes_build();
    $rowCount = count((array) ($snapshot['rows'] ?? []));
    $stored = supplycore_materialized_snapshot_store(market_comparison_snapshot_key(), $snapshot, [
        'reason' => $reason,
        'row_count' => $rowCount,
    ]);

    unset($snapshot);
    if (function_exists('gc_collect_cycles')) {
        gc_collect_cycles();
    }

    return $stored;
}

function market_comparison_refresh_summary_job_result(string $reason = 'manual'): array
{
    $snapshot = market_comparison_refresh_summary($reason);
    $rowCount = count((array) ($snapshot['rows'] ?? []));
    $freshness = is_array($snapshot['_freshness'] ?? null) ? $snapshot['_freshness'] : [];

    return sync_result_shape() + [
        'rows_seen' => $rowCount,
        'rows_written' => $rowCount,
        'cursor' => 'market_comparison:' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'rows' => $rowCount,
            'computed_at' => (string) ($freshness['computed_at'] ?? gmdate(DATE_ATOM)),
            'reason' => $reason,
        ]),
        'meta' => [
            'outcome_reason' => 'Market comparison summaries were recomputed and written to materialized storage plus Redis.',
            'snapshot_generated_at' => (string) ($freshness['computed_at'] ?? ''),
        ],
    ];
}

function loss_demand_summary_build(): array
{
    $marketSnapshot = market_comparison_snapshot_payload();
    $marketRows = array_values((array) ($marketSnapshot['rows'] ?? []));
    $typeLookup = [];

    foreach ($marketRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId > 0) {
            $typeLookup[$typeId] = $row;
        }
    }

    if ($typeLookup === []) {
        return [
            'rows' => [],
            'summary' => [
                'tracked_type_count' => 0,
                'active_loss_demand_count' => 0,
                'losses_24h' => 0,
                'losses_7d' => 0,
            ],
            'top_rows' => [],
        ];
    }

    try {
        $lossRows = db_killmail_tracked_recent_item_losses(array_keys($typeLookup), 24 * 7);
    } catch (Throwable) {
        $lossRows = [];
    }

    $lossRows = item_scope_filter_rows(
        $lossRows,
        static fn (array $row): int => (int) ($row['type_id'] ?? 0)
    );

    $rows = [];
    foreach ($lossRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId <= 0) {
            continue;
        }

        $market = $typeLookup[$typeId] ?? [];
        $quantity7d = max(0, (int) ($row['quantity_7d'] ?? 0));
        $losses7d = max(0, (int) ($row['losses_7d'] ?? 0));
        $referencePrice = isset($market['reference_best_sell_price']) ? (float) $market['reference_best_sell_price'] : null;
        $estimatedRestock = $referencePrice !== null ? round($referencePrice * $quantity7d, 2) : 0.0;
        $priorityScore = (int) min(100, round(($quantity7d * 1.2) + ($losses7d * 6.0) + max(0, (int) ($market['volume_score'] ?? 0) * 0.35)));

        $rows[] = [
            'type_id' => $typeId,
            'type_name' => (string) (($market['type_name'] ?? $row['type_name']) ?? ''),
            'quantity_24h' => max(0, (int) ($row['quantity_24h'] ?? 0)),
            'quantity_7d' => $quantity7d,
            'losses_24h' => max(0, (int) ($row['losses_24h'] ?? 0)),
            'losses_7d' => $losses7d,
            'latest_loss_at' => $row['latest_loss_at'] ?? null,
            'reference_best_sell_price' => $referencePrice,
            'estimated_restock_isk' => $estimatedRestock,
            'volume_score' => (int) ($market['volume_score'] ?? 0),
            'priority_score' => $priorityScore,
        ];
    }

    usort($rows, static fn (array $a, array $b): int => ((int) ($b['priority_score'] ?? 0) <=> (int) ($a['priority_score'] ?? 0)) ?: ((int) ($b['quantity_7d'] ?? 0) <=> (int) ($a['quantity_7d'] ?? 0)));

    return [
        'rows' => $rows,
        'summary' => [
            'tracked_type_count' => count($typeLookup),
            'active_loss_demand_count' => count($rows),
            'losses_24h' => array_sum(array_map(static fn (array $row): int => (int) ($row['quantity_24h'] ?? 0), $rows)),
            'losses_7d' => array_sum(array_map(static fn (array $row): int => (int) ($row['quantity_7d'] ?? 0), $rows)),
        ],
        'top_rows' => array_slice($rows, 0, 12),
    ];
}

function loss_demand_snapshot_payload(): array
{
    return supplycore_materialized_snapshot_read_or_bootstrap(
        loss_demand_snapshot_key(),
        static fn (): array => loss_demand_summary_build(),
        'loss-demand-bootstrap'
    );
}

