        'strong' => ['max_percent' => (float) ($settings['deal_alert_strong_threshold_percent'] ?? 10.0), 'rank' => $ranks['strong']],
        'watch' => ['max_percent' => (float) ($settings['deal_alert_watch_threshold_percent'] ?? 15.0), 'rank' => $ranks['watch']],
