        'last_materialized_at' => $payload['last_materialized_at'] ?? null,
        'first_materialized_at' => $payload['first_materialized_at'] ?? null,
        'last_attempt_status' => $payload['last_attempt_status'] ?? 'never_ran',
        'last_success_status' => $payload['last_success_status'] ?? null,
        'last_reason_zero_output' => $payload['last_reason_zero_output'] ?? null,
        'last_failure_reason' => $payload['last_failure_reason'] ?? null,
        'last_deferred_at' => $payload['last_deferred_at'] ?? null,
        'last_deferred_reason' => $payload['last_deferred_reason'] ?? null,
        'input_row_count' => (int) ($payload['input_row_count'] ?? 0),
        'history_row_count' => (int) ($payload['history_row_count'] ?? 0),
        'candidate_row_count' => (int) ($payload['candidate_row_count'] ?? 0),
        'output_row_count' => (int) ($payload['output_row_count'] ?? 0),
        'persisted_row_count' => (int) ($payload['persisted_row_count'] ?? 0),
        'inactive_row_count' => (int) ($payload['inactive_row_count'] ?? 0),
        'sources_scanned' => (int) ($payload['sources_scanned'] ?? 0),
        'last_duration_ms' => isset($payload['last_duration_ms']) ? (int) $payload['last_duration_ms'] : null,
        'metadata_json' => json_encode($meta, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
    ]);
}

function deal_alert_zero_output_reason(array $stats, array $sources): string
{
    if ($sources === []) {
        return 'No market sources are configured for deal-alert detection yet.';
    }

    if (($stats['input_row_count'] ?? 0) === 0) {
        return 'Current market snapshots returned zero sell listings across all configured deal-alert sources.';
    }

    if (($stats['history_row_count'] ?? 0) === 0) {
        return 'Historical baselines were unavailable, so no listings could be evaluated against normal pricing.';
    }

    if (($stats['candidate_row_count'] ?? 0) === 0) {
        return 'Listings were loaded, but baseline/freshness validation filtered every row before anomaly scoring.';
    }

    if (($stats['output_row_count'] ?? 0) === 0) {
        return 'Candidates were evaluated successfully, but none crossed the configured severity thresholds.';
    }

    return 'The deal-alert scan completed without producing persisted rows.';
}

function deal_alert_refresh_current(string $reason = 'manual', bool $persist = true): array
{
    $startedAt = microtime(true);
    $startedAtSql = gmdate('Y-m-d H:i:s');
    $settings = deal_alert_settings();
    $enabled = ($settings['deal_alerts_enabled'] ?? '1') === '1';
    $statusSnapshot = deal_alert_materialization_status();

    if (!$enabled) {
        $inactiveCount = $persist ? db_market_deal_alerts_mark_missing_inactive([]) : 0;
        $durationMs = (int) round((microtime(true) - $startedAt) * 1000);
        if ($persist) {
            deal_alert_materialization_record([
                'last_run_started_at' => $startedAtSql,
                'last_run_finished_at' => gmdate('Y-m-d H:i:s'),
                'last_success_at' => gmdate('Y-m-d H:i:s'),
                'last_materialized_at' => gmdate('Y-m-d H:i:s'),
                'first_materialized_at' => $statusSnapshot['first_materialized_at'] ?? gmdate('Y-m-d H:i:s'),
                'last_attempt_status' => 'disabled',
                'last_success_status' => 'disabled',
                'last_reason_zero_output' => 'Deal alerts are disabled in settings.',
                'last_failure_reason' => null,
                'input_row_count' => 0,
                'history_row_count' => 0,
                'candidate_row_count' => 0,
                'output_row_count' => 0,
                'persisted_row_count' => 0,
                'inactive_row_count' => $inactiveCount,
                'sources_scanned' => 0,
                'last_duration_ms' => $durationMs,
                'metadata' => [
                    'reason' => $reason,
                    'verification_mode' => $persist ? 'persisted' : 'dry_run',
                ],
            ]);
        }

        return sync_result_shape() + [
            'rows_seen' => 0,
            'rows_written' => $inactiveCount,
            'cursor' => 'deal_alerts_disabled:' . gmdate('Y-m-d H:i:s'),
            'checksum' => sync_checksum(['enabled' => false, 'reason' => $reason, 'at' => gmdate(DATE_ATOM)]),
            'meta' => [
                'outcome_reason' => 'Deal alerts were disabled in settings, so all active anomaly windows were marked inactive.',
                'input_row_count' => 0,
                'candidate_row_count' => 0,
                'output_row_count' => 0,
                'persisted_row_count' => 0,
                'materialization_write_timestamp' => $persist ? gmdate('Y-m-d H:i:s') : null,
                'last_calculation_duration_ms' => $durationMs,
                'last_zero_output_reason' => 'Deal alerts are disabled in settings.',
            ],
        ];
    }

    $windowDays = max(3, (int) ($settings['deal_alert_baseline_days'] ?? 14));
    $minHistoryPoints = max(3, (int) ($settings['deal_alert_min_history_points'] ?? 5));
    $sources = deal_alert_detection_sources();
    $now = gmdate('Y-m-d H:i:s');
    $rowsToUpsert = [];
    $activeAlertKeys = [];
    $rowsSeen = 0;
    $historyRowCount = 0;
    $candidateRowCount = 0;
    $sourceInputCounts = [];
    $sourceCandidateCounts = [];
    $sourceOutputCounts = [];

    foreach ($sources as $source) {
        $currentRows = db_market_lowest_sell_orders_by_source((string) $source['source_type'], (int) $source['source_id']);
        $sourceKey = (string) ($source['source_type'] ?? 'market_hub') . ':' . (int) ($source['source_id'] ?? 0);
        $sourceInputCounts[$sourceKey] = count($currentRows);
        if ($currentRows === []) {
            continue;
        }

        $typeIds = array_values(array_unique(array_filter(array_map(static fn (array $row): int => (int) ($row['type_id'] ?? 0), $currentRows), static fn (int $typeId): bool => $typeId > 0)));
        if ($typeIds === []) {
            continue;
        }

        $historyRows = db_market_history_daily_window_by_type_ids((string) $source['source_type'], (int) $source['source_id'], $typeIds, $windowDays);
        $historyRowCount += count($historyRows);
        $historyByType = [];
        foreach ($historyRows as $historyRow) {
            $typeId = (int) ($historyRow['type_id'] ?? 0);
            $normalized = deal_alert_normalize_history_row($historyRow, 'market_history_daily');
            if ($typeId <= 0 || $normalized === null) {
                continue;
            }
            $historyByType[$typeId][] = $normalized;
        }

        $localHistoryByType = [];
        if (($source['source_type'] ?? '') === 'market_hub') {
            $localRows = db_market_hub_local_history_daily_window_by_type_ids(
                market_hub_local_history_source(),
                (int) $source['source_id'],
                $typeIds,
                $windowDays
            );
            $historyRowCount += count($localRows);

            foreach ($localRows as $localRow) {
                $typeId = (int) ($localRow['type_id'] ?? 0);
                $normalized = deal_alert_normalize_history_row($localRow, 'market_hub_local_history_daily');
                if ($typeId <= 0 || $normalized === null) {
                    continue;
                }
                $localHistoryByType[$typeId][] = $normalized;
            }
        }

        foreach ($currentRows as $currentRow) {
            $rowsSeen++;
            $typeId = (int) ($currentRow['type_id'] ?? 0);
            $currentPrice = isset($currentRow['price']) ? (float) $currentRow['price'] : 0.0;
            if ($typeId <= 0 || $currentPrice <= 0.0) {
                continue;
            }

            $baselineInput = $localHistoryByType[$typeId] ?? [];
            if (count($baselineInput) < $minHistoryPoints) {
                $baselineInput = $historyByType[$typeId] ?? [];
            }

            $baseline = deal_alert_baseline_from_rows($baselineInput);
            if ($baseline === null || (int) ($baseline['points'] ?? 0) < $minHistoryPoints) {
                continue;
            }

            $normalPrice = (float) ($baseline['normal_price'] ?? 0.0);
            if ($normalPrice <= 0.0) {
                continue;
            }

            $candidateRowCount++;
            $sourceCandidateCounts[$sourceKey] = (int) ($sourceCandidateCounts[$sourceKey] ?? 0) + 1;
            $percentOfNormal = ($currentPrice / $normalPrice) * 100.0;
            $severity = deal_alert_severity_for_percent($percentOfNormal);
            if ($severity === null) {
                continue;
            }

            $quantityAvailable = max(0, (int) ($currentRow['volume_remain'] ?? 0));
            $listingCount = max(0, (int) ($currentRow['sell_order_count'] ?? 0));
            $observedAt = trim((string) ($currentRow['observed_at'] ?? $now));
            $observedTimestamp = strtotime($observedAt);
            $freshnessSeconds = $observedTimestamp === false ? 0 : max(0, time() - $observedTimestamp);
            $anomalyScore = deal_alert_anomaly_score($percentOfNormal, $quantityAvailable, (int) ($baseline['points'] ?? 0), (int) ($severity['rank'] ?? 1));
            $alertKey = deal_alert_alert_key($typeId, (string) $source['source_type'], (int) $source['source_id'], $percentOfNormal);

            $metadata = [
                'reason' => $reason,
                'type_name' => (string) ($currentRow['type_name'] ?? ''),
                'market_label' => deal_alert_market_label((string) $source['source_type']),
                'total_sell_volume' => max(0, (int) ($currentRow['total_sell_volume'] ?? 0)),
                'baseline_model' => (string) ($baseline['baseline_model'] ?? 'median_weighted_blend'),
                'history_window_days' => $windowDays,
            ];

            $rowsToUpsert[] = [
                'alert_key' => $alertKey,
                'item_type_id' => $typeId,
                'source_type' => (string) $source['source_type'],
                'source_id' => (int) $source['source_id'],
                'source_name' => (string) $source['source_name'],
                'percent_band' => deal_alert_percent_band($percentOfNormal),
                'current_price' => round($currentPrice, 2),
                'normal_price' => round($normalPrice, 2),
                'percent_of_normal' => round($percentOfNormal, 4),
                'anomaly_score' => $anomalyScore,
                'severity' => (string) ($severity['severity'] ?? 'watch'),
                'severity_rank' => (int) ($severity['rank'] ?? 1),
                'quantity_available' => $quantityAvailable,
                'listing_count' => $listingCount,
                'best_order_id' => isset($currentRow['order_id']) ? (int) $currentRow['order_id'] : null,
                'baseline_model' => (string) ($baseline['baseline_model'] ?? 'median_weighted_blend'),
                'baseline_points' => (int) ($baseline['points'] ?? 0),
                'baseline_median_price' => (float) ($baseline['median_price'] ?? 0.0),
                'baseline_weighted_price' => (float) ($baseline['weighted_price'] ?? 0.0),
                'observed_at' => $observedTimestamp === false ? $now : gmdate('Y-m-d H:i:s', $observedTimestamp),
                'detected_at' => $now,
                'last_seen_at' => $now,
                'inactive_at' => null,
                'freshness_seconds' => $freshnessSeconds,
                'status' => 'active',
                'metadata_json' => json_encode($metadata, JSON_UNESCAPED_SLASHES | JSON_INVALID_UTF8_SUBSTITUTE),
            ];
            $activeAlertKeys[] = $alertKey;
            $sourceOutputCounts[$sourceKey] = (int) ($sourceOutputCounts[$sourceKey] ?? 0) + 1;
        }
    }

    $outputRowCount = count($rowsToUpsert);
    $inactiveCount = 0;
    $rowsWritten = 0;
    $lastMaterializedAt = null;
    $attemptStatus = 'success_empty';
    $lastSuccessStatus = 'success_empty';
    $zeroOutputReason = $outputRowCount === 0 ? deal_alert_zero_output_reason([
        'input_row_count' => $rowsSeen,
        'history_row_count' => $historyRowCount,
        'candidate_row_count' => $candidateRowCount,
        'output_row_count' => $outputRowCount,
    ], $sources) : null;
    if ($persist) {
        try {
            $rowsWritten = db_market_deal_alerts_upsert_current($rowsToUpsert);
            $inactiveCount = db_market_deal_alerts_mark_missing_inactive($activeAlertKeys);
            $lastMaterializedAt = gmdate('Y-m-d H:i:s');
            $attemptStatus = $outputRowCount > 0 ? 'success_alerts' : 'success_empty';
            $lastSuccessStatus = $attemptStatus;
            supplycore_cache_bust(['dashboard']);
        } catch (Throwable $exception) {
            $durationMs = (int) round((microtime(true) - $startedAt) * 1000);
            deal_alert_materialization_record([
                'last_run_started_at' => $startedAtSql,
                'last_run_finished_at' => gmdate('Y-m-d H:i:s'),
                'last_attempt_status' => 'persistence_failed',
                'last_failure_reason' => scheduler_normalize_error_message($exception->getMessage()),
                'last_reason_zero_output' => $zeroOutputReason,
                'input_row_count' => $rowsSeen,
                'history_row_count' => $historyRowCount,
                'candidate_row_count' => $candidateRowCount,
                'output_row_count' => $outputRowCount,
                'persisted_row_count' => 0,
                'inactive_row_count' => 0,
                'sources_scanned' => count($sources),
                'last_duration_ms' => $durationMs,
                'metadata' => [
                    'reason' => $reason,
                    'verification_mode' => 'persisted',
                    'source_input_counts' => $sourceInputCounts,
                    'source_candidate_counts' => $sourceCandidateCounts,
                    'source_output_counts' => $sourceOutputCounts,
                ],
            ]);
            throw $exception;
        }
    }

    $durationMs = (int) round((microtime(true) - $startedAt) * 1000);
    if ($persist) {
        $firstMaterializedAt = $statusSnapshot['first_materialized_at'] ?? $lastMaterializedAt;
        if ($firstMaterializedAt === null && $lastMaterializedAt !== null) {
            $firstMaterializedAt = $lastMaterializedAt;
        }
        deal_alert_materialization_record([
            'last_run_started_at' => $startedAtSql,
            'last_run_finished_at' => gmdate('Y-m-d H:i:s'),
            'last_success_at' => gmdate('Y-m-d H:i:s'),
            'last_materialized_at' => $lastMaterializedAt,
            'first_materialized_at' => $firstMaterializedAt,
            'last_attempt_status' => $attemptStatus,
            'last_success_status' => $lastSuccessStatus,
            'last_reason_zero_output' => $zeroOutputReason,
            'last_failure_reason' => null,
            'input_row_count' => $rowsSeen,
            'history_row_count' => $historyRowCount,
            'candidate_row_count' => $candidateRowCount,
            'output_row_count' => $outputRowCount,
            'persisted_row_count' => $rowsWritten,
            'inactive_row_count' => $inactiveCount,
            'sources_scanned' => count($sources),
            'last_duration_ms' => $durationMs,
            'metadata' => [
                'reason' => $reason,
                'verification_mode' => 'persisted',
                'source_input_counts' => $sourceInputCounts,
                'source_candidate_counts' => $sourceCandidateCounts,
                'source_output_counts' => $sourceOutputCounts,
                'source_count' => count($sources),
            ],
        ]);
    }

    return sync_result_shape() + [
        'rows_seen' => $rowsSeen,
        'rows_written' => $persist ? ($rowsWritten + $inactiveCount) : $outputRowCount,
        'cursor' => 'deal_alerts:' . gmdate('Y-m-d H:i:s'),
        'checksum' => sync_checksum([
            'reason' => $reason,
            'active_alerts' => count($activeAlertKeys),
            'rows_seen' => $rowsSeen,
            'rows_written' => $rowsWritten,
            'inactive_count' => $inactiveCount,
        ]),
        'meta' => [
            'outcome_reason' => $persist
                ? 'Current market sell orders were compared against local historical baselines and persisted into the active deal-alert layer.'
                : 'Current market sell orders were compared against local historical baselines in diagnostic mode without writing the materialized layer.',
            'active_alerts' => count($activeAlertKeys),
            'sources_scanned' => count($sources),
            'input_row_count' => $rowsSeen,
            'history_row_count' => $historyRowCount,
            'candidate_row_count' => $candidateRowCount,
            'output_row_count' => $outputRowCount,
            'persisted_row_count' => $persist ? $rowsWritten : 0,
            'inactive_row_count' => $inactiveCount,
            'materialization_write_timestamp' => $lastMaterializedAt,
            'last_calculation_duration_ms' => $durationMs,
            'last_zero_output_reason' => $zeroOutputReason,
            'source_input_counts' => $sourceInputCounts,
            'source_candidate_counts' => $sourceCandidateCounts,
            'source_output_counts' => $sourceOutputCounts,
            'verification_mode' => $persist ? 'persisted' : 'dry_run',
        ],
    ];
}

function deal_alert_refresh_job_result(string $reason = 'manual'): array
{
    return deal_alert_refresh_current($reason);
}

function deal_alert_refresh_diagnostic_result(string $reason = 'diagnostic', bool $persist = false): array
{
    return deal_alert_refresh_current($reason, $persist);
}

function deal_alert_record_scheduler_deferral(string $reason, ?array $schedule = null): void
{
    $job = $schedule;
    if ($job === null) {
        $rows = db_sync_schedule_fetch_by_job_keys(['deal_alerts_sync']);
        $job = $rows[0] ?? [];
    }
    $status = deal_alert_materialization_status();

    deal_alert_materialization_record([
        'last_job_key' => 'deal_alerts_sync',
        'last_attempt_status' => 'deferred',
        'last_deferred_at' => gmdate('Y-m-d H:i:s'),
        'last_deferred_reason' => $reason,
        'last_failure_reason' => null,
        'last_reason_zero_output' => $status['last_reason_zero_output'] ?? null,
        'input_row_count' => $status['input_row_count'] ?? 0,
        'history_row_count' => $status['history_row_count'] ?? 0,
        'candidate_row_count' => $status['candidate_row_count'] ?? 0,
        'output_row_count' => $status['output_row_count'] ?? 0,
        'persisted_row_count' => $status['persisted_row_count'] ?? 0,
        'inactive_row_count' => $status['inactive_row_count'] ?? 0,
        'sources_scanned' => $status['sources_scanned'] ?? 0,
        'metadata' => [
            'scheduler_consecutive_deferrals' => (int) ($job['consecutive_deferrals'] ?? 0),
            'scheduler_priority' => (string) ($job['priority'] ?? 'high'),
        ],
    ]);
}

function deal_alert_severity_label(string $severity): string
{
    return match ($severity) {
        'critical' => 'Critical misprice',
        'very_strong' => 'Very strong deal',
        'strong' => 'Strong deal',
        default => 'Watch',
    };
}

function deal_alert_severity_tone(string $severity): string
{
    return match ($severity) {
        'critical' => 'border-rose-400/35 bg-rose-500/12 text-rose-100',
        'very_strong' => 'border-orange-400/35 bg-orange-500/12 text-orange-100',
        'strong' => 'border-amber-400/35 bg-amber-500/12 text-amber-100',
        default => 'border-sky-400/25 bg-sky-500/10 text-sky-100',
    };
}

function deal_alert_market_filter_options(): array
{
    return [
        '' => 'All markets',
        'alliance_structure' => 'Alliance Market',
        'market_hub' => 'Reference Hub',
    ];
}

function deal_alert_sort_options(): array
{
    return [
        'severity' => 'Severity',
        'percent' => 'Lowest % of normal',
        'freshness' => 'Newest seen',
        'price' => 'Lowest price',
    ];
}

function deal_alert_minimum_severity_options(): array
{
    return [
        0 => 'All severities',
        4 => 'Critical only',
        3 => 'Very strong + critical',
        2 => 'Strong + higher',
        1 => 'Watch + higher',
    ];
}

function deal_alerts_page_filters(array $query): array
{
    $market = trim((string) ($query['market'] ?? ''));
    if (!array_key_exists($market, deal_alert_market_filter_options())) {
        $market = '';
    }

    $sort = trim((string) ($query['sort'] ?? 'severity'));
    if (!array_key_exists($sort, deal_alert_sort_options())) {
        $sort = 'severity';
    }

    $minSeverityRank = (int) ($query['min_severity'] ?? 0);
    if (!array_key_exists($minSeverityRank, deal_alert_minimum_severity_options())) {
        $minSeverityRank = 0;
    }

    $page = max(1, (int) ($query['page'] ?? 1));
    $perPage = 25;

    return [
        'market' => $market,
        'sort' => $sort,
        'minimum_severity_rank' => $minSeverityRank,
        'search' => trim((string) ($query['search'] ?? '')),
        'page' => $page,
        'per_page' => $perPage,
    ];
}

function deal_alert_status_presentation(array $materialization, array $schedule, array $summary): array
{
    $attemptStatus = (string) ($materialization['last_attempt_status'] ?? 'never_ran');
    if ($attemptStatus === 'never_ran' && !empty($schedule['last_error'])) {
        $attemptStatus = 'failed';
    } elseif ($attemptStatus === 'never_ran' && !empty($schedule['last_finished_at'])) {
        $attemptStatus = ((int) ($schedule['consecutive_deferrals'] ?? 0) > 0) ? 'deferred' : 'success_empty';
    }
    $persistedRowCount = (int) ($materialization['persisted_row_count'] ?? 0);
    $activeCount = (int) ($summary['active_count'] ?? 0);
    $sourceMismatch = $persistedRowCount > 0 && $activeCount === 0 && $attemptStatus === 'success_alerts';

    return match ($attemptStatus) {
        'deferred' => [
            'code' => 'deferred',
            'label' => 'Deferred before execution',
            'tone' => 'border-amber-400/25 bg-amber-500/10 text-amber-100',
            'detail' => (string) ($materialization['last_deferred_reason'] ?? 'Planner pressure deferred the job before execution.'),
        ],
        'success_alerts' => [
            'code' => $sourceMismatch ? 'source_mismatch' : 'success_alerts',
            'label' => $sourceMismatch ? 'Source unavailable / page mismatch' : 'Ran successfully and wrote alerts',
            'tone' => $sourceMismatch ? 'border-rose-400/25 bg-rose-500/10 text-rose-100' : 'border-emerald-400/25 bg-emerald-500/10 text-emerald-100',
            'detail' => $sourceMismatch
                ? 'The latest successful materialization wrote alerts, but the page query returned no active rows.'
                : 'Latest run scanned live listings, evaluated candidates, and persisted active deal alerts.',
        ],
        'success_empty', 'disabled' => [
            'code' => 'success_empty',
            'label' => 'Ran successfully but no alerts found',
            'tone' => 'border-sky-400/25 bg-sky-500/10 text-sky-100',
            'detail' => (string) ($materialization['last_reason_zero_output'] ?? 'Latest run completed successfully without actionable alerts.'),
        ],
        'persistence_failed' => [
            'code' => 'persistence_failed',
            'label' => 'Ran but persistence failed',
            'tone' => 'border-rose-400/25 bg-rose-500/10 text-rose-100',
            'detail' => (string) ($materialization['last_failure_reason'] ?? 'Rows were built, but the materialized write did not complete.'),
        ],
        'failed' => [
            'code' => 'failed',
            'label' => 'Ran and failed',
            'tone' => 'border-rose-400/25 bg-rose-500/10 text-rose-100',
            'detail' => (string) ($materialization['last_failure_reason'] ?? ($schedule['last_error'] ?? 'The last run ended with a failure.')),
        ],
        default => [
            'code' => 'never_ran',
            'label' => 'Never ran',
            'tone' => 'border-slate-400/20 bg-slate-500/10 text-slate-100',
            'detail' => 'No successful or failed deal-alert execution has been recorded yet.',
        ],
    };
}

function deal_alerts_page_data(array $query = []): array
{
    $filters = deal_alerts_page_filters($query);
    $offset = ($filters['page'] - 1) * $filters['per_page'];
    $rows = db_market_deal_alerts_list($filters, $filters['per_page'], $offset);
    $total = db_market_deal_alerts_count($filters);
    $summary = db_market_deal_alerts_active_summary();
    $materialization = deal_alert_materialization_status();
    $schedule = db_sync_schedule_fetch_by_job_keys(['deal_alerts_sync'])[0] ?? [];
    $statusPresentation = deal_alert_status_presentation($materialization, $schedule, $summary);
    $pages = max(1, (int) ceil($total / max(1, $filters['per_page'])));

    $mappedRows = array_map(static function (array $row): array {
        $severity = (string) ($row['severity'] ?? 'watch');
        $typeName = trim((string) ($row['type_name'] ?? ''));
        $marketLabel = deal_alert_market_label((string) ($row['source_type'] ?? 'market_hub'));

        return $row + [
            'display_name' => $typeName !== '' ? $typeName : ('Type #' . (int) ($row['item_type_id'] ?? 0)),
            'market_label' => $marketLabel,
            'severity_label' => deal_alert_severity_label($severity),
            'severity_tone' => deal_alert_severity_tone($severity),
            'current_price_label' => market_format_isk(isset($row['current_price']) ? (float) $row['current_price'] : null),
            'normal_price_label' => market_format_isk(isset($row['normal_price']) ? (float) $row['normal_price'] : null),
            'percent_of_normal_label' => market_format_percentage((float) ($row['percent_of_normal'] ?? 0.0), 2),
            'freshness_relative' => supplycore_relative_datetime(isset($row['last_seen_at']) ? (string) $row['last_seen_at'] : null),
            'freshness_at' => supplycore_format_datetime(isset($row['last_seen_at']) ? (string) $row['last_seen_at'] : null),
        ];
    }, $rows);

    return [
        'filters' => $filters,
        'rows' => $mappedRows,
        'total' => $total,
        'page_count' => $pages,
        'materialization' => [
            'status' => $statusPresentation,
            'last_run_started_at' => $materialization['last_run_started_at'],
            'last_run_finished_at' => $materialization['last_run_finished_at'],
            'last_success_at' => $materialization['last_success_at'],
            'last_materialized_at' => $materialization['last_materialized_at'],
            'first_materialized_at' => $materialization['first_materialized_at'],
            'input_row_count' => (int) ($materialization['input_row_count'] ?? 0),
            'history_row_count' => (int) ($materialization['history_row_count'] ?? 0),
            'candidate_row_count' => (int) ($materialization['candidate_row_count'] ?? 0),
            'output_row_count' => (int) ($materialization['output_row_count'] ?? 0),
            'persisted_row_count' => (int) ($materialization['persisted_row_count'] ?? 0),
            'inactive_row_count' => (int) ($materialization['inactive_row_count'] ?? 0),
            'sources_scanned' => (int) ($materialization['sources_scanned'] ?? 0),
            'last_duration_ms' => $materialization['last_duration_ms'],
            'last_reason_zero_output' => $materialization['last_reason_zero_output'],
            'last_failure_reason' => $materialization['last_failure_reason'],
            'last_deferred_at' => $materialization['last_deferred_at'],
            'last_deferred_reason' => $materialization['last_deferred_reason'],
            'metadata' => $materialization['metadata'],
        ],
        'scheduler' => [
            'priority' => (string) ($schedule['priority'] ?? 'high'),
            'latency_sensitive' => !empty($schedule['latency_sensitive']),
            'user_facing' => !empty($schedule['user_facing']),
            'consecutive_deferrals' => (int) ($schedule['consecutive_deferrals'] ?? 0),
            'last_status' => (string) ($schedule['last_status'] ?? 'unknown'),
            'last_result' => (string) ($schedule['last_result'] ?? ''),
            'last_error' => isset($schedule['last_error']) ? (string) $schedule['last_error'] : null,
            'last_started_at' => isset($schedule['last_started_at']) ? (string) $schedule['last_started_at'] : null,
            'last_finished_at' => isset($schedule['last_finished_at']) ? (string) $schedule['last_finished_at'] : null,
            'latest_allowed_start_at' => isset($schedule['latest_allowed_start_at']) ? (string) $schedule['latest_allowed_start_at'] : null,
        ],
        'source_verification' => [
            'freshness_timestamp_source' => 'market_deal_alert_materialization_status.last_materialized_at',
            'summary_source' => 'market_deal_alerts_current active summary',
            'table_row_source' => 'market_deal_alerts_current filtered by active status',
            'latest_success_output_source' => 'market_deal_alert_materialization_status persisted counters + market_deal_alerts_current rows',
            'page_source_mismatch' => ($statusPresentation['code'] ?? '') === 'source_mismatch',
        ],
        'summary' => [
            'active_count' => (int) ($summary['active_count'] ?? 0),
            'critical_count' => (int) ($summary['critical_count'] ?? 0),
            'last_seen_at' => isset($materialization['last_materialized_at']) && $materialization['last_materialized_at'] !== null
                ? (string) $materialization['last_materialized_at']
                : (isset($summary['last_seen_at']) ? (string) $summary['last_seen_at'] : null),
            'last_seen_relative' => supplycore_relative_datetime(isset($materialization['last_materialized_at']) && $materialization['last_materialized_at'] !== null ? (string) $materialization['last_materialized_at'] : (isset($summary['last_seen_at']) ? (string) $summary['last_seen_at'] : null)),
            'last_seen_label' => supplycore_format_datetime(isset($materialization['last_materialized_at']) && $materialization['last_materialized_at'] !== null ? (string) $materialization['last_materialized_at'] : (isset($summary['last_seen_at']) ? (string) $summary['last_seen_at'] : null)),
        ],
    ];
}

function deal_alert_popup_view_model(): array
{
    $rows = db_market_deal_alerts_popup_rows(deal_alert_popup_min_severity_rank(), 3);

    return array_map(static function (array $row): array {
        $severity = (string) ($row['severity'] ?? 'watch');
        $typeName = trim((string) ($row['type_name'] ?? ''));

        return $row + [
            'display_name' => $typeName !== '' ? $typeName : ('Type #' . (int) ($row['item_type_id'] ?? 0)),
            'severity_label' => deal_alert_severity_label($severity),
            'severity_tone' => deal_alert_severity_tone($severity),
            'market_label' => deal_alert_market_label((string) ($row['source_type'] ?? 'market_hub')),
            'current_price_label' => market_format_isk(isset($row['current_price']) ? (float) $row['current_price'] : null),
            'normal_price_label' => market_format_isk(isset($row['normal_price']) ? (float) $row['normal_price'] : null),
            'percent_of_normal_label' => market_format_percentage((float) ($row['percent_of_normal'] ?? 0.0), 2),
            'freshness_relative' => supplycore_relative_datetime(isset($row['last_seen_at']) ? (string) $row['last_seen_at'] : null),
        ];
    }, $rows);
}

function deal_alert_dismiss(string $alertKey, int $severityRank): bool
{
    $settings = deal_alert_settings();

    return db_market_deal_alerts_dismiss(
        $alertKey,
        $severityRank,
        (int) ($settings['deal_alert_popup_dismiss_minutes'] ?? 120)
    );
}

function deal_alert_safe_return_path(string $value): string
{
    $path = trim($value);

    if ($path === '' || !str_starts_with($path, '/')) {
        return '/deal-alerts';
    }

    if (preg_match('/[\r\n]/', $path) === 1) {
        return '/deal-alerts';
    }

    return $path;
}

function dashboard_sync_dataset_active_error(array $states): ?string
{
    foreach ($states as $state) {
        if (!is_array($state) || (string) ($state['status'] ?? '') !== 'failed') {
            continue;
        }

        $message = trim((string) ($state['last_error_message'] ?? ''));
        if ($message !== '') {
            return $message;
        }
    }

    return null;
}

function sync_status_for_dataset_keys(array $datasetKeys): array
{
    $normalizedKeys = array_values(array_unique(array_filter(array_map(
        static fn (mixed $datasetKey): string => trim((string) $datasetKey),
        $datasetKeys
    ), static fn (string $datasetKey): bool => $datasetKey !== '')));

    if ($normalizedKeys === []) {
        return [
            'states' => [],
            'runs' => [],
            'last_success_at' => null,
            'last_error_message' => null,
            'recent_rows_written' => 0,
        ];
    }

    try {
        $states = [];
        $runs = [];
        $lastSuccessAt = null;
        $lastErrorMessage = null;
        $recentRowsWritten = 0;

        foreach ($normalizedKeys as $datasetKey) {
            $state = db_sync_state_get($datasetKey);
            if ($state !== null) {
                $states[] = $state;

                $candidate = $state['last_success_at'] ?? null;
                if (is_string($candidate) && $candidate !== '' && ($lastSuccessAt === null || strtotime($candidate) > strtotime($lastSuccessAt))) {
                    $lastSuccessAt = $candidate;
                }

                $recentRowsWritten += max(0, (int) ($state['last_row_count'] ?? 0));
            }

            $latestRun = db_sync_run_latest_by_dataset($datasetKey);
            if ($latestRun !== null) {
                $runs[] = $latestRun;

                if ($lastErrorMessage === null && (string) ($latestRun['run_status'] ?? '') === 'failed') {
                    $message = trim((string) ($latestRun['error_message'] ?? ''));
                    if ($message !== '') {
                        $lastErrorMessage = $message;
                    }
                }
            }
        }

        if ($lastErrorMessage === null) {
            foreach ($states as $state) {
                $message = trim((string) ($state['last_error_message'] ?? ''));
                if ($message !== '') {
                    $lastErrorMessage = $message;
                    break;
                }
            }
        }

        usort($states, static fn (array $a, array $b): int => strcmp((string) ($b['updated_at'] ?? ''), (string) ($a['updated_at'] ?? '')));
        usort($runs, static fn (array $a, array $b): int => (int) ($b['id'] ?? 0) <=> (int) ($a['id'] ?? 0));

        return [
            'states' => $states,
            'runs' => $runs,
            'last_success_at' => $lastSuccessAt,
            'last_error_message' => $lastErrorMessage,
            'recent_rows_written' => $recentRowsWritten,
        ];
    } catch (Throwable) {
        return [
            'states' => [],
            'runs' => [],
            'last_success_at' => null,
            'last_error_message' => null,
            'recent_rows_written' => 0,
        ];
    }
}

function supplycore_latest_run_failure_message(array $runs): ?string
{
    $latestRun = is_array($runs[0] ?? null) ? $runs[0] : null;
    if (!is_array($latestRun) || !supplycore_status_is_failure((string) ($latestRun['run_status'] ?? ''))) {
        return null;
    }

    $message = trim((string) ($latestRun['error_message'] ?? ''));

    return $message !== '' ? $message : null;
}

function supplycore_status_is_failure(string $status): bool
{
    $normalized = strtolower(trim($status));

    return in_array($normalized, ['failed', 'failure', 'error', 'timeout', 'timed_out'], true);
}

function supplycore_freshness_bucket(?int $ageSeconds, int $freshSeconds, int $delayedSeconds, bool $runningNow = false): string
{
    if ($runningNow) {
        return 'updating';
    }

    if ($ageSeconds === null) {
        return 'stale';
    }

    if ($ageSeconds <= max(60, $freshSeconds)) {
        return 'fresh';
    }

    if ($ageSeconds <= max($freshSeconds, $delayedSeconds)) {
        return 'delayed';
    }

    return 'stale';
}

function supplycore_dataset_runtime_status_from_sync(array $spec): array
{
    $datasetKeys = array_values(array_filter(array_map(
        static fn (mixed $value): string => trim((string) $value),
        (array) ($spec['dataset_keys'] ?? [])
    ), static fn (string $value): bool => $value !== ''));
    $status = sync_status_for_dataset_keys($datasetKeys);
    $states = array_values((array) ($status['states'] ?? []));
    $runs = array_values((array) ($status['runs'] ?? []));
    $latestRun = is_array($runs[0] ?? null) ? $runs[0] : null;
    $lastSuccessAt = isset($status['last_success_at']) ? (string) $status['last_success_at'] : null;
    $lastSuccessAt = is_string($lastSuccessAt) && trim($lastSuccessAt) !== '' ? $lastSuccessAt : null;
    $lastSuccessTimestamp = $lastSuccessAt !== null ? (strtotime($lastSuccessAt) ?: null) : null;
    $ageSeconds = $lastSuccessTimestamp !== null ? max(0, time() - $lastSuccessTimestamp) : null;
    $runningNow = false;

    foreach ($states as $state) {
        if ((string) ($state['status'] ?? '') === 'running') {
            $runningNow = true;
            break;
        }
    }

    $freshSeconds = max(60, (int) ($spec['fresh_seconds'] ?? 900));
    $delayedSeconds = max($freshSeconds, (int) ($spec['delayed_seconds'] ?? ($freshSeconds * 3)));
    $freshnessState = supplycore_freshness_bucket($ageSeconds, $freshSeconds, $delayedSeconds, $runningNow);
    $latestFailureMessage = supplycore_latest_run_failure_message($runs);
    $latestRunStatus = is_array($latestRun) ? (string) ($latestRun['run_status'] ?? '') : '';

    if (supplycore_status_is_failure($latestRunStatus)) {
        $freshnessState = 'failed';
    }

    return [
        'key' => (string) ($spec['key'] ?? ($datasetKeys[0] ?? 'dataset')),
        'label' => (string) ($spec['label'] ?? 'Dataset'),
        'source' => 'sync_state',
        'dataset_keys' => $datasetKeys,
        'last_success_at_raw' => $lastSuccessAt,
        'last_success_at' => supplycore_format_datetime($lastSuccessAt),
        'last_success_relative' => supplycore_relative_datetime($lastSuccessAt),
        'freshness_reference_at_raw' => $lastSuccessAt,
        'freshness_state' => $freshnessState,
        'freshness_label' => supplycore_operational_status_view_model($freshnessState)['label'],
        'freshness_tone' => supplycore_operational_status_view_model($freshnessState)['tone'],
        'age_seconds' => $ageSeconds,
        'running_now' => $runningNow,
        'latest_run_status' => $latestRunStatus,
        'latest_failure_message' => $latestFailureMessage,
        'show_latest_failure' => $latestFailureMessage !== null,
        'recent_rows_written' => (int) ($status['recent_rows_written'] ?? 0),
    ];
}

function supplycore_dataset_runtime_status_from_snapshot(array $spec): array
{
    $snapshotKey = trim((string) ($spec['snapshot_key'] ?? ''));
    $jobKey = trim((string) ($spec['job_key'] ?? ''));
    $meta = $snapshotKey !== '' ? supplycore_snapshot_freshness($snapshotKey) : [];
    $computedAt = trim((string) ($meta['computed_at'] ?? ''));
    $computedAt = $computedAt !== '' ? $computedAt : null;
    $runningNow = (string) ($meta['status'] ?? '') === 'updating';
    $freshSeconds = max(60, (int) ($meta['refresh_interval_seconds'] ?? ($spec['fresh_seconds'] ?? 900)));
    $delayedSeconds = max($freshSeconds, (int) ($meta['stale_after_seconds'] ?? ($spec['delayed_seconds'] ?? ($freshSeconds * 3))));
    $ageSeconds = isset($meta['age_seconds']) ? (int) $meta['age_seconds'] : null;
    $freshnessState = supplycore_freshness_bucket($ageSeconds, $freshSeconds, $delayedSeconds, $runningNow);
    $jobStatus = $jobKey !== '' ? (db_scheduler_job_current_status_fetch_map([$jobKey])[$jobKey] ?? []) : [];
    $latestStatus = (string) ($jobStatus['latest_status'] ?? '');
    $latestFailureMessage = supplycore_status_is_failure($latestStatus)
        ? (trim((string) ($jobStatus['last_failure_message'] ?? '')) ?: null)
        : null;

    if (supplycore_status_is_failure($latestStatus)) {
        $freshnessState = 'failed';
    }

    return [
        'key' => (string) ($spec['key'] ?? ($snapshotKey !== '' ? $snapshotKey : 'snapshot')),
        'label' => (string) ($spec['label'] ?? 'Dataset'),
        'source' => 'snapshot',
        'snapshot_key' => $snapshotKey,
        'job_key' => $jobKey !== '' ? $jobKey : null,
        'last_success_at_raw' => $computedAt,
        'last_success_at' => supplycore_format_datetime($computedAt),
        'last_success_relative' => supplycore_relative_datetime($computedAt),
        'freshness_reference_at_raw' => $computedAt,
        'freshness_state' => $freshnessState,
        'freshness_label' => supplycore_operational_status_view_model($freshnessState)['label'],
        'freshness_tone' => supplycore_operational_status_view_model($freshnessState)['tone'],
        'age_seconds' => $ageSeconds,
        'running_now' => $runningNow,
        'latest_run_status' => $latestStatus,
        'latest_failure_message' => $latestFailureMessage,
        'show_latest_failure' => $latestFailureMessage !== null,
    ];
}

function supplycore_dataset_runtime_status_from_killmail(array $spec = []): array
{
    $status = db_killmail_ingestion_status();
    $state = is_array($status['state'] ?? null) ? $status['state'] : [];
    $latestRun = is_array($status['latest_run'] ?? null) ? $status['latest_run'] : [];
    $workerStatus = zkill_worker_runtime_status();
    $lastSuccessAt = isset($state['last_success_at']) ? (string) $state['last_success_at'] : null;
    $lastSuccessAt = is_string($lastSuccessAt) && trim($lastSuccessAt) !== '' ? $lastSuccessAt : null;
    $lastSuccessTimestamp = $lastSuccessAt !== null ? (strtotime($lastSuccessAt) ?: null) : null;
    $ageSeconds = $lastSuccessTimestamp !== null ? max(0, time() - $lastSuccessTimestamp) : null;
    $runningNow = in_array((string) ($workerStatus['status'] ?? ''), ['running', 'success'], true)
        && isset($workerStatus['age_seconds'])
        && (int) $workerStatus['age_seconds'] <= 120;
    $freshSeconds = max(60, (int) ($spec['fresh_seconds'] ?? 900));
    $delayedSeconds = max($freshSeconds, (int) ($spec['delayed_seconds'] ?? 2700));
    $latestRunStatus = (string) ($latestRun['run_status'] ?? ($state['status'] ?? ''));
    $latestFailureMessage = supplycore_status_is_failure($latestRunStatus)
        ? (trim((string) (($latestRun['error_message'] ?? $state['last_error_message'] ?? ''))) ?: null)
        : null;
    $freshnessState = supplycore_freshness_bucket($ageSeconds, $freshSeconds, $delayedSeconds, $runningNow);

    if (supplycore_status_is_failure($latestRunStatus)) {
        $freshnessState = 'failed';
    }

    return [
        'key' => (string) ($spec['key'] ?? 'killmail.r2z2.stream'),
        'label' => (string) ($spec['label'] ?? 'Killmail stream'),
        'source' => 'killmail_worker',
        'dataset_keys' => [killmail_sync_dataset_key()],
        'last_success_at_raw' => $lastSuccessAt,
        'last_success_at' => killmail_format_datetime($lastSuccessAt),
        'last_success_relative' => killmail_relative_datetime($lastSuccessAt),
        'freshness_reference_at_raw' => $lastSuccessAt,
        'freshness_state' => $freshnessState,
        'freshness_label' => supplycore_operational_status_view_model($freshnessState)['label'],
        'freshness_tone' => supplycore_operational_status_view_model($freshnessState)['tone'],
        'age_seconds' => $ageSeconds,
        'running_now' => $runningNow,
        'latest_run_status' => $latestRunStatus,
        'latest_failure_message' => $latestFailureMessage,
        'show_latest_failure' => $latestFailureMessage !== null,
        'tracked_alliance_count' => (int) ($status['tracked_alliance_count'] ?? 0),
        'tracked_corporation_count' => (int) ($status['tracked_corporation_count'] ?? 0),
        'worker_status' => $workerStatus,
        'sync_state' => $state,
        'latest_run' => $latestRun,
    ];
}

function supplycore_dataset_runtime_status(array $spec): array
{
    $source = trim((string) ($spec['source'] ?? 'sync'));

    return match ($source) {
        'snapshot' => supplycore_dataset_runtime_status_from_snapshot($spec),
        'killmail' => supplycore_dataset_runtime_status_from_killmail($spec),
        default => supplycore_dataset_runtime_status_from_sync($spec),
    };
}

