        'gap_to_target_fit_count' => 0,
        'fleet_ready' => 0,
        'complete_fits_available' => 0,
        'fleet_gap' => 0,
        'blocked_fits' => 0,
        'overcapacity' => 0,
        'bottleneck_item_name' => null,
