function buy_all_parse_bool_query(array $query, string $key, bool $default = false): bool
{
    if (!array_key_exists($key, $query)) {
        return $default;
    }

    $value = $query[$key];
    if (is_bool($value)) {
        return $value;
    }

    $normalized = strtolower(trim((string) $value));

    return in_array($normalized, ['1', 'true', 'yes', 'on'], true);
}

function buy_all_request(array $query = []): array
{
    $modes = buy_all_mode_definitions();
    $sortOptions = buy_all_sort_options();
    $mode = strtolower(trim((string) ($query['mode'] ?? 'blended')));
    if (!isset($modes[$mode])) {
        $mode = 'blended';
    }

    $sort = strtolower(trim((string) ($query['sort'] ?? ($modes[$mode]['default_sort'] ?? 'blended_score'))));
    if (!isset($sortOptions[$sort])) {
        $sort = (string) ($modes[$mode]['default_sort'] ?? 'blended_score');
    }

    $filters = [
        'doctrine_linked_only' => buy_all_parse_bool_query($query, 'doctrine_linked_only', (bool) ($modes[$mode]['require_doctrine_linked'] ?? false)),
        'positive_net_margin_only' => buy_all_parse_bool_query($query, 'positive_net_margin_only', (bool) ($modes[$mode]['positive_margin_bias'] ?? false)),
        'allow_low_margin_doctrine_critical' => buy_all_parse_bool_query($query, 'allow_low_margin_doctrine_critical', true),
        'exclude_incomplete_pricing' => buy_all_parse_bool_query($query, 'exclude_incomplete_pricing', false),
        'exclude_oversized_low_efficiency' => buy_all_parse_bool_query($query, 'exclude_oversized_low_efficiency', false),
        'min_priority_threshold' => max(0.0, min(100.0, (float) ($query['min_priority_threshold'] ?? 0))),
        'min_net_margin_threshold' => max(-100.0, min(500.0, (float) ($query['min_net_margin_threshold'] ?? 0))),
        'min_net_profit_threshold' => max(-1000000000.0, (float) ($query['min_net_profit_threshold'] ?? 0)),
    ];

    return [
        'mode' => $mode,
        'sort' => $sort,
        'page' => max(1, (int) ($query['page'] ?? 1)),
        'filters' => $filters,
    ];
}

function buy_all_round_quantity(int $quantity): int
{
    if ($quantity <= 10) {
        return $quantity;
    }
    if ($quantity <= 50) {
        return (int) (ceil($quantity / 5) * 5);
    }

    return (int) (ceil($quantity / 10) * 10);
}

function buy_all_latest_market_history_by_type(string $sourceType, int $sourceId, array $typeIds, int $days = 14): array
{
    $safeTypeIds = array_values(array_unique(array_filter(array_map('intval', $typeIds), static fn (int $typeId): bool => $typeId > 0)));
    if ($sourceId <= 0 || $safeTypeIds === []) {
        return [];
    }

    try {
        $rows = db_market_history_daily_window_by_type_ids($sourceType, $sourceId, $safeTypeIds, $days);
    } catch (Throwable) {
        return [];
    }

    $indexed = [];
    foreach ($rows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId <= 0 || isset($indexed[$typeId])) {
            continue;
        }
        $indexed[$typeId] = $row;
    }

    return $indexed;
}

function buy_all_fit_activity_pressure_modifier(array $fit, string $hullClass): float
{
    $supply = is_array($fit['supply'] ?? null) ? $fit['supply'] : [];
    $recent24h = max(
        0.0,
        (float) ($supply['recent_hull_losses_24h'] ?? 0),
        (float) ($supply['recent_item_fit_losses_24h'] ?? 0)
    );
    $recent7d = max(
        0.0,
        (float) ($supply['recent_hull_losses_7d'] ?? 0),
        (float) ($supply['recent_item_fit_losses_7d'] ?? 0)
    );
    $pressureBonus = match ((string) ($supply['resupply_pressure_state'] ?? 'stable')) {
        'urgent_resupply' => 0.18,
        'resupply_soon' => 0.12,
        'elevated' => 0.06,
        default => 0.0,
    };
    $trendBonus = (($supply['readiness_trend_direction'] ?? 'unknown') === 'down') ? 0.04 : 0.0;
    $classScale = match ($hullClass) {
        'titan' => 0.35,
        'super' => 0.50,
        'capital' => 0.70,
        'implants_support' => 0.60,
        default => 1.0,
    };
    $modifier = 1.0 + (($recent24h * 0.10) + ($recent7d * 0.025)) * $classScale + $pressureBonus + $trendBonus;

    return round(min(1.45, max(1.0, $modifier)), 2);
}

function buy_all_primary_hull_class(array $classes): string
{
    $classes = array_values(array_unique(array_filter(array_map(static fn ($value): string => trim((string) $value), $classes))));
    if ($classes === []) {
        return 'subcap';
    }
    if (count($classes) === 1) {
        return $classes[0];
    }

    $weights = ['titan' => 5, 'super' => 4, 'capital' => 3, 'subcap' => 2, 'implants_support' => 1];
    usort($classes, static fn (string $a, string $b): int => (($weights[$b] ?? 0) <=> ($weights[$a] ?? 0)) ?: strcasecmp($a, $b));

    return 'mixed:' . implode(',', $classes);
}

function buy_all_hull_class_label(string $class): string
{
    if (str_starts_with($class, 'mixed:')) {
        $parts = explode(',', substr($class, 6));
        $labels = array_map(static fn (string $part): string => doctrine_hull_class_label($part), array_filter($parts, static fn (string $part): bool => $part !== ''));

        return 'Mixed (' . implode(', ', $labels) . ')';
    }

    return doctrine_hull_class_label($class);
}

function buy_all_item_impact_map(array $fits, array $itemsByFitId, array $marketByTypeId, array $metadataByType = []): array
{
    $impactByType = [];

    foreach ($fits as $fit) {
        $fitId = (int) ($fit['id'] ?? 0);
        if ($fitId <= 0) {
            continue;
        }

        $fitItems = array_values((array) ($itemsByFitId[$fitId] ?? []));
        if ($fitItems === []) {
            continue;
        }

        $supply = is_array($fit['supply'] ?? null) ? $fit['supply'] : [];
        if (!($supply['operationally_owned'] ?? true)) {
            continue;
        }
        $targetReadyFits = max(0, (int) ($supply['doctrine_target_fleet_size'] ?? $supply['recommended_target_fit_count'] ?? 0));
        $fitReadyCapacity = max(0, (int) ($supply['fleet_ready'] ?? $supply['complete_fits_available'] ?? 0));
        $targetShortfall = max(0, (int) ($supply['blocked_fits'] ?? max(0, $targetReadyFits - $fitReadyCapacity)));
        $fitName = (string) ($fit['fit_name'] ?? ('Fit #' . $fitId));
        $primaryGroupName = trim((string) ($supply['primary_group_name'] ?? $fit['primary_group_name'] ?? ''));
        $groupNames = $primaryGroupName !== '' ? [$primaryGroupName] : [];
        $hullClass = doctrine_fit_hull_class($fit, $fitItems, $metadataByType);
        $activityModifier = buy_all_fit_activity_pressure_modifier($fit, $hullClass);

        foreach ($fitItems as $item) {
            if (array_key_exists('is_stock_tracked', $item) && !(bool) $item['is_stock_tracked']) {
                continue;
            }

            $typeId = (int) ($item['type_id'] ?? 0);
            if ($typeId <= 0) {
                continue;
            }

            $requiredQty = max(1, (int) ($item['quantity'] ?? 1));
            $localStock = max(0, (int) (($marketByTypeId[$typeId]['alliance_total_sell_volume'] ?? 0)));
            $itemFitCapacity = intdiv($localStock, $requiredQty);
            $itemBlockType = doctrine_item_block_type($item, $metadataByType);
            $exactDeficitQuantity = $itemBlockType === 'hard_blocker' ? max(0, ($targetReadyFits * $requiredQty) - $localStock) : 0;
            $supportDeficitQuantity = $itemBlockType !== 'hard_blocker' ? max(0, ($targetReadyFits * $requiredQty) - $localStock) : 0;
            $deterministicBlockedFits = ((int) ($supply['bottleneck_type_id'] ?? 0) === $typeId && $itemBlockType === 'hard_blocker')
                ? $targetShortfall
                : 0;

            if (!isset($impactByType[$typeId])) {
                $impactByType[$typeId] = [
                    'type_id' => $typeId,
                    'valid_doctrine_names' => [],
                    'valid_fit_names' => [],
                    'valid_fit_ids' => [],
                    'fit_hull_classes' => [],
                    'target_ready_fits' => 0,
                    'total_target_shortfall' => 0,
                    'deterministic_blocked_fits' => 0,
                    'exact_deficit_quantity' => 0,
                    'support_deficit_quantity' => 0,
                    'exact_deficit_fit_count' => 0,
                    'blocked_fit_count' => 0,
                    'bottleneck_fit_count' => 0,
                    'required_quantity_total' => 0,
                    'item_block_types' => [],
                    'activity_modifier_total' => 0.0,
                    'activity_modifier_count' => 0,
                    'activity_pressure_modifier' => 1.0,
                    'affected_fits' => [],
                ];
            }

            $impactByType[$typeId]['target_ready_fits'] += $targetReadyFits;
            $impactByType[$typeId]['total_target_shortfall'] += $targetShortfall;
            $impactByType[$typeId]['deterministic_blocked_fits'] += $deterministicBlockedFits;
            $impactByType[$typeId]['exact_deficit_quantity'] += $exactDeficitQuantity;
            $impactByType[$typeId]['support_deficit_quantity'] += $supportDeficitQuantity;
            $impactByType[$typeId]['required_quantity_total'] += $requiredQty;
            $impactByType[$typeId]['valid_fit_names'][$fitName] = true;
            $impactByType[$typeId]['valid_fit_ids'][$fitId] = true;
            $impactByType[$typeId]['fit_hull_classes'][$hullClass] = true;
            $impactByType[$typeId]['item_block_types'][$itemBlockType] = true;
            $impactByType[$typeId]['activity_modifier_total'] += $activityModifier;
            $impactByType[$typeId]['activity_modifier_count']++;
            if ($exactDeficitQuantity > 0) {
                $impactByType[$typeId]['exact_deficit_fit_count']++;
            }
            if ($deterministicBlockedFits > 0) {
                $impactByType[$typeId]['blocked_fit_count']++;
            }
            if ((int) ($supply['bottleneck_type_id'] ?? 0) === $typeId && (($supply['bottleneck_is_stock_tracked'] ?? true) === true)) {
                $impactByType[$typeId]['bottleneck_fit_count']++;
            }
            foreach ($groupNames as $groupName) {
                $safeName = trim((string) $groupName);
                if ($safeName !== '') {
                    $impactByType[$typeId]['valid_doctrine_names'][$safeName] = true;
                }
            }
            $impactByType[$typeId]['affected_fits'][] = [
                'fit_id' => $fitId,
                'fit_name' => $fitName,
                'group_names' => $groupNames,
                'hull_class' => $hullClass,
                'hull_class_label' => doctrine_hull_class_label($hullClass),
                'required_quantity' => $requiredQty,
                'local_stock' => $localStock,
                'item_block_type' => $itemBlockType,
                'item_fit_capacity' => $itemFitCapacity,
                'fit_ready_capacity' => $fitReadyCapacity,
                'target_ready_fits' => $targetReadyFits,
                'target_shortfall' => $targetShortfall,
                'exact_deficit_quantity' => $exactDeficitQuantity,
                'support_deficit_quantity' => $supportDeficitQuantity,
                'deterministic_blocked_fits' => $deterministicBlockedFits,
                'activity_pressure_modifier' => $activityModifier,
            ];
        }
    }

    foreach ($impactByType as $typeId => &$impact) {
        $impact['valid_doctrine_count'] = count((array) ($impact['valid_doctrine_names'] ?? []));
        $impact['valid_fits_count'] = count((array) ($impact['valid_fit_ids'] ?? []));
        $impact['deterministic_blocked_fits'] = min(
            max(0, (int) ($impact['deterministic_blocked_fits'] ?? 0)),
            max(0, (int) ($impact['total_target_shortfall'] ?? 0))
        );
        $impact['activity_pressure_modifier'] = round(
            (float) ($impact['activity_modifier_count'] ?? 0) > 0
                ? ((float) ($impact['activity_modifier_total'] ?? 0.0) / (float) ($impact['activity_modifier_count'] ?? 1))
                : 1.0,
            2
        );
        $impact['hull_class'] = buy_all_primary_hull_class(array_keys((array) ($impact['fit_hull_classes'] ?? [])));
        $impact['hull_class_label'] = buy_all_hull_class_label((string) ($impact['hull_class'] ?? 'subcap'));
        $impact['item_block_type'] = isset($impact['item_block_types']['hard_blocker']) ? 'hard_blocker' : (isset($impact['item_block_types']['soft_blocker']) ? 'soft_blocker' : 'sustainment');
        $impact['item_block_type_label'] = doctrine_item_block_type_label((string) ($impact['item_block_type'] ?? 'hard_blocker'));
        $impact['valid_doctrine_names'] = array_values(array_keys((array) ($impact['valid_doctrine_names'] ?? [])));
        $impact['valid_fit_names'] = array_values(array_keys((array) ($impact['valid_fit_names'] ?? [])));
        $impact['valid_fit_ids'] = array_values(array_keys((array) ($impact['valid_fit_ids'] ?? [])));
        $impact['fit_hull_classes'] = array_values(array_keys((array) ($impact['fit_hull_classes'] ?? [])));
        $impact['affected_fits'] = array_values(array_filter(
            (array) ($impact['affected_fits'] ?? []),
            static fn (array $fit): bool => (int) ($fit['deterministic_blocked_fits'] ?? 0) > 0 || (int) ($fit['exact_deficit_quantity'] ?? 0) > 0 || (int) ($fit['support_deficit_quantity'] ?? 0) > 0
        ));
    }
    unset($impact);

    return $impactByType;
}

function buy_all_reason_meta(array $candidate): array
{
    $blockedFits = max(0, (int) ($candidate['deterministic_blocked_fits'] ?? $candidate['blocked_fit_impact'] ?? 0));
    $targetReadyFits = max(0, (int) ($candidate['target_ready_fits'] ?? 0));
    $validDoctrineCount = max(0, (int) ($candidate['valid_doctrine_count'] ?? 0));
    $exactDeficitQuantity = max(0, (int) ($candidate['exact_deficit_quantity'] ?? 0));
    $exactDeficitFitCount = max(0, (int) ($candidate['exact_deficit_fit_count'] ?? 0));
    $hullClassLabel = strtolower((string) ($candidate['hull_class_label'] ?? 'doctrine'));
    $activityModifier = max(1.0, (float) ($candidate['activity_pressure_modifier'] ?? 1.0));

    if ($blockedFits > 0) {
        return [
            'code' => 'deterministic_doctrine_blocking',
            'text' => 'Blocks ' . doctrine_format_quantity($blockedFits) . ' of ' . doctrine_format_quantity($targetReadyFits) . ' target ' . $hullClassLabel . ' fits across ' . doctrine_format_quantity($validDoctrineCount) . ' valid doctrines.',
            'theme' => 'Deterministic doctrine blocking',
        ];
    }
    if ($exactDeficitQuantity > 0) {
        return [
            'code' => 'exact_doctrine_deficit',
            'text' => 'Exact doctrine deficit for ' . doctrine_format_quantity($exactDeficitFitCount) . ' ' . $hullClassLabel . ' fits.',
            'theme' => 'Exact doctrine deficit',
        ];
    }
    if ((bool) ($candidate['missing_in_alliance'] ?? false) && (($candidate['net_profit_total'] ?? null) !== null) && (float) ($candidate['net_profit_total'] ?? 0.0) > 0.0) {
        return ['code' => 'profitable_import_spread', 'text' => 'Profitable import candidate but not doctrine-blocking.', 'theme' => 'Profitable seeding'];
    }
    if ($activityModifier > 1.05) {
        return ['code' => 'activity_elevated_low_deficit', 'text' => 'Activity elevated for hull family but deterministic deficit is low.', 'theme' => 'Activity elevated'];
    }
    if ((bool) ($candidate['missing_in_alliance'] ?? false)) {
        return ['code' => 'missing_alliance_stock', 'text' => 'Missing alliance stock with hub availability to seed.', 'theme' => 'Seed backlog'];
    }
    if ((float) ($candidate['net_margin_percent'] ?? -999.0) >= 15.0 && (float) ($candidate['volume_efficiency'] ?? 0.0) > 0.0) {
        return ['code' => 'low_volume_high_margin_import', 'text' => 'Low-volume, high-margin import candidate.', 'theme' => 'High-margin imports'];
    }
    if (!empty($candidate['is_doctrine_linked'])) {
        return ['code' => 'enabled_item_replenishment_candidate', 'text' => 'Doctrine-linked replenishment candidate from valid fit relationships.', 'theme' => 'Doctrine replenishment'];
    }

    return ['code' => 'local_price_dislocation', 'text' => 'Local price dislocation or stock pressure suggests action.', 'theme' => 'Market dislocations'];
}

function buy_all_compare_items(array $a, array $b, string $sort, string $mode): int
{
    $cmp = 0;
    switch ($sort) {
        case 'necessity':
            $cmp = ((float) ($b['necessity_score'] ?? 0.0) <=> (float) ($a['necessity_score'] ?? 0.0))
                ?: ((int) ($b['doctrine_fit_impact'] ?? 0) <=> (int) ($a['doctrine_fit_impact'] ?? 0))
                ?: (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)));
            break;
        case 'net_profit':
            $cmp = (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)))
                ?: (((float) ($b['net_margin_percent'] ?? -INF)) <=> ((float) ($a['net_margin_percent'] ?? -INF)))
                ?: ((float) ($b['profit_score'] ?? 0.0) <=> (float) ($a['profit_score'] ?? 0.0));
            break;
        case 'doctrine_impact':
            $cmp = ((int) ($b['doctrine_fit_impact'] ?? 0) <=> (int) ($a['doctrine_fit_impact'] ?? 0))
                ?: ((float) ($b['necessity_score'] ?? 0.0) <=> (float) ($a['necessity_score'] ?? 0.0));
            break;
        case 'blocked_fit_impact':
            $cmp = ((int) ($b['blocked_fit_impact'] ?? 0) <=> (int) ($a['blocked_fit_impact'] ?? 0))
                ?: ((float) ($b['necessity_score'] ?? 0.0) <=> (float) ($a['necessity_score'] ?? 0.0));
            break;
        case 'volume_efficiency':
            $cmp = (((float) ($b['volume_efficiency'] ?? -INF)) <=> ((float) ($a['volume_efficiency'] ?? -INF)))
                ?: (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)));
            break;
        case 'isk_efficiency':
            $cmp = (((float) ($b['isk_efficiency'] ?? -INF)) <=> ((float) ($a['isk_efficiency'] ?? -INF)))
                ?: (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)));
            break;
        case 'margin_percent':
            $cmp = (((float) ($b['net_margin_percent'] ?? -INF)) <=> ((float) ($a['net_margin_percent'] ?? -INF)))
                ?: (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)));
            break;
        default:
            $cmp = ((float) ($b['blended_score'] ?? 0.0) <=> (float) ($a['blended_score'] ?? 0.0))
                ?: ((float) ($b['necessity_score'] ?? 0.0) <=> (float) ($a['necessity_score'] ?? 0.0))
                ?: (((float) ($b['net_profit_total'] ?? -INF)) <=> ((float) ($a['net_profit_total'] ?? -INF)));
            break;
    }

    if ($cmp !== 0) {
        return $cmp;
    }

    if ($mode === 'doctrine_critical') {
        return ((int) ($b['doctrine_fit_impact'] ?? 0) <=> (int) ($a['doctrine_fit_impact'] ?? 0))
            ?: strcasecmp((string) ($a['item_name'] ?? ''), (string) ($b['item_name'] ?? ''));
    }

    return strcasecmp((string) ($a['item_name'] ?? ''), (string) ($b['item_name'] ?? ''));
}

function buy_all_pack_pages(array $items): array
{
    $pages = [];
    $maxTypes = buy_all_page_item_type_limit();
    $maxVolume = buy_all_page_volume_limit();
    $pageIndex = 0;
    $pages[$pageIndex] = [
        'number' => 1,
        'items' => [],
        'item_count' => 0,
        'total_units' => 0,
        'total_volume' => 0.0,
        'total_buy_cost' => 0.0,
        'total_expected_sell_value' => 0.0,
        'total_hauling_cost' => 0.0,
        'total_gross_profit' => 0.0,
        'total_net_profit' => 0.0,
        'doctrine_critical_count' => 0,
        'high_necessity_count' => 0,
        'medium_necessity_count' => 0,
        'low_necessity_count' => 0,
    ];
    $excluded = [];

    foreach ($items as $item) {
        $remainingQuantity = max(0, (int) ($item['quantity'] ?? 0));
        $unitVolume = max(0.0, (float) ($item['unit_volume'] ?? 0.0));
        if ($remainingQuantity <= 0) {
            continue;
        }
        if ($unitVolume > $maxVolume) {
            $excluded[] = $item + ['exclusion_reason' => 'Unit volume exceeds the page cargo limit.'];
            continue;
        }

        while ($remainingQuantity > 0) {
            $page = &$pages[$pageIndex];
            $remainingVolume = max(0.0, $maxVolume - (float) ($page['total_volume'] ?? 0.0));
            $remainingTypeSlots = max(0, $maxTypes - (int) ($page['item_count'] ?? 0));

            if ($remainingTypeSlots <= 0 || ($unitVolume > 0.0 && $remainingVolume < $unitVolume && ($page['item_count'] ?? 0) > 0)) {
                $pageIndex++;
                $pages[$pageIndex] = [
                    'number' => $pageIndex + 1,
                    'items' => [],
                    'item_count' => 0,
                    'total_units' => 0,
                    'total_volume' => 0.0,
                    'total_buy_cost' => 0.0,
                    'total_expected_sell_value' => 0.0,
                    'total_hauling_cost' => 0.0,
                    'total_gross_profit' => 0.0,
                    'total_net_profit' => 0.0,
                    'doctrine_critical_count' => 0,
                    'high_necessity_count' => 0,
                    'medium_necessity_count' => 0,
                    'low_necessity_count' => 0,
                ];
                unset($page);
                continue;
            }

            $maxByVolume = $unitVolume > 0.0 ? (int) floor($remainingVolume / $unitVolume) : $remainingQuantity;
            if ($unitVolume > 0.0) {
                $maxByVolume = max(0, $maxByVolume);
            }
            if ($maxByVolume <= 0 && $unitVolume > 0.0) {
                $pageIndex++;
                $pages[$pageIndex] = [
                    'number' => $pageIndex + 1,
                    'items' => [],
                    'item_count' => 0,
                    'total_units' => 0,
                    'total_volume' => 0.0,
                    'total_buy_cost' => 0.0,
                    'total_expected_sell_value' => 0.0,
                    'total_hauling_cost' => 0.0,
                    'total_gross_profit' => 0.0,
                    'total_net_profit' => 0.0,
                    'doctrine_critical_count' => 0,
                    'high_necessity_count' => 0,
                    'medium_necessity_count' => 0,
                    'low_necessity_count' => 0,
                ];
                unset($page);
                continue;
            }

            $chunkQuantity = $unitVolume > 0.0 ? min($remainingQuantity, $maxByVolume) : $remainingQuantity;
            if ($chunkQuantity <= 0) {
                break;
            }

            $chunk = $item;
            $chunk['quantity'] = $chunkQuantity;
            $chunk['total_volume'] = $unitVolume * $chunkQuantity;
            $chunk['hauling_cost_total'] = (float) ($item['hauling_cost_per_unit'] ?? 0.0) * $chunkQuantity;
            $chunk['buy_cost_total'] = isset($item['buy_price']) && $item['buy_price'] !== null ? ((float) $item['buy_price'] * $chunkQuantity) : null;
            $chunk['expected_sell_total'] = isset($item['sell_price']) && $item['sell_price'] !== null ? ((float) $item['sell_price'] * $chunkQuantity) : null;
            $chunk['gross_profit_total'] = isset($item['gross_profit_per_unit']) && $item['gross_profit_per_unit'] !== null ? ((float) $item['gross_profit_per_unit'] * $chunkQuantity) : null;
            $chunk['net_profit_total'] = isset($item['net_profit_per_unit']) && $item['net_profit_per_unit'] !== null ? ((float) $item['net_profit_per_unit'] * $chunkQuantity) : null;

            $page['items'][] = $chunk;
            $page['item_count']++;
            $page['total_units'] += $chunkQuantity;
            $page['total_volume'] += (float) $chunk['total_volume'];
            $page['total_buy_cost'] += (float) ($chunk['buy_cost_total'] ?? 0.0);
            $page['total_expected_sell_value'] += (float) ($chunk['expected_sell_total'] ?? 0.0);
            $page['total_hauling_cost'] += (float) ($chunk['hauling_cost_total'] ?? 0.0);
            $page['total_gross_profit'] += (float) ($chunk['gross_profit_total'] ?? 0.0);
            $page['total_net_profit'] += (float) ($chunk['net_profit_total'] ?? 0.0);
            if (!empty($chunk['is_doctrine_critical'])) {
                $page['doctrine_critical_count']++;
            }
            $necessity = (float) ($chunk['necessity_score'] ?? 0.0);
            if ($necessity >= 70.0) {
                $page['high_necessity_count']++;
            } elseif ($necessity >= 40.0) {
                $page['medium_necessity_count']++;
            } else {
                $page['low_necessity_count']++;
            }

            $remainingQuantity -= $chunkQuantity;
            unset($page);

            if ($remainingQuantity > 0) {
                $pageIndex++;
                $pages[$pageIndex] = [
                    'number' => $pageIndex + 1,
                    'items' => [],
                    'item_count' => 0,
                    'total_units' => 0,
                    'total_volume' => 0.0,
                    'total_buy_cost' => 0.0,
                    'total_expected_sell_value' => 0.0,
                    'total_hauling_cost' => 0.0,
                    'total_gross_profit' => 0.0,
                    'total_net_profit' => 0.0,
                    'doctrine_critical_count' => 0,
                    'high_necessity_count' => 0,
                    'medium_necessity_count' => 0,
                    'low_necessity_count' => 0,
                ];
            }
        }
    }

    $pages = array_values(array_filter($pages, static fn (array $page): bool => (array) ($page['items'] ?? []) !== []));
    foreach ($pages as &$page) {
        $lines = array_map(static fn (array $row): string => trim((string) ($row['item_name'] ?? '')) . ' ' . (int) ($row['quantity'] ?? 0), $page['items']);
        $page['necessity_mix_summary'] = 'High ' . doctrine_format_quantity((int) ($page['high_necessity_count'] ?? 0))
            . ' · Medium ' . doctrine_format_quantity((int) ($page['medium_necessity_count'] ?? 0))
            . ' · Low ' . doctrine_format_quantity((int) ($page['low_necessity_count'] ?? 0));
        $page['clipboard_text'] = implode("\n", array_filter($lines, static fn (string $line): bool => trim($line) !== ''));
    }
    unset($page);

    return ['pages' => $pages, 'excluded_items' => $excluded];
}

function buy_all_planner_data(array $query = []): array
{
    $request = buy_all_request($query);
    $modeDefinitions = buy_all_mode_definitions();
    $modeConfig = $modeDefinitions[$request['mode']] ?? $modeDefinitions['blended'];
    $thresholds = market_compare_thresholds();
    $marketOutcomes = market_comparison_outcomes();
    $marketRows = array_values((array) ($marketOutcomes['rows'] ?? []));
    $marketByTypeId = [];
    foreach ($marketRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId > 0) {
            $marketByTypeId[$typeId] = $row;
        }
    }

    $doctrineSnapshot = doctrine_operational_snapshot();
    $fits = array_values((array) ($doctrineSnapshot['fits'] ?? []));
    $globalLayerRows = array_values((array) (($doctrineSnapshot['global_layer']['rows'] ?? [])));
    $globalByTypeId = [];
    foreach ($globalLayerRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId > 0) {
            $globalByTypeId[$typeId] = $row;
        }
    }

    $topMissingItems = array_values((array) ($doctrineSnapshot['top_missing_items'] ?? []));
    $topMissingByTypeId = [];
    foreach ($topMissingItems as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId > 0) {
            $topMissingByTypeId[$typeId] = $row;
        }
    }

    $fitIds = array_values(array_filter(array_map(static fn (array $fit): int => (int) ($fit['id'] ?? 0), $fits), static fn (int $fitId): bool => $fitId > 0));
    $itemsByFitId = [];
    $candidateTypeIds = array_keys($marketByTypeId);
    try {
        foreach (db_doctrine_fit_items_by_fit_ids($fitIds) as $item) {
            $fitId = (int) ($item['doctrine_fit_id'] ?? 0);
            $typeId = (int) ($item['type_id'] ?? 0);
            if ($fitId <= 0 || $typeId <= 0 || !item_scope_is_type_id_in_scope($typeId)) {
                continue;
            }
            $itemsByFitId[$fitId][] = $item;
            $candidateTypeIds[] = $typeId;
        }
    } catch (Throwable) {
        $itemsByFitId = [];
    }

    $candidateTypeIds = array_values(array_unique(array_merge($candidateTypeIds, array_keys($globalByTypeId), array_keys($topMissingByTypeId))));
    $typeMetaById = [];
    foreach (db_ref_item_types_by_ids($candidateTypeIds) as $row) {
        $typeMetaById[(int) ($row['type_id'] ?? 0)] = $row;
    }
    $typeMetadataById = item_scope_metadata_by_type_ids($candidateTypeIds);
    $doctrineDemandByType = buy_all_item_impact_map($fits, $itemsByFitId, $marketByTypeId, $typeMetadataById);
    $candidateTypeIds = array_values(array_unique(array_merge($candidateTypeIds, array_keys($doctrineDemandByType))));

    $allianceStructureId = configured_structure_destination_id_for_esi_sync();
    $hubSourceId = sync_source_id_from_hub_ref(market_hub_setting_reference());
    $allianceHistoryByType = buy_all_latest_market_history_by_type('alliance_structure', $allianceStructureId, $candidateTypeIds, 14);
    $hubHistoryByType = buy_all_latest_market_history_by_type('market_hub', $hubSourceId, $candidateTypeIds, 14);

    $rankedItems = [];
    foreach ($candidateTypeIds as $typeId) {
        $market = $marketByTypeId[$typeId] ?? [];
        $global = $globalByTypeId[$typeId] ?? [];
        $missing = $topMissingByTypeId[$typeId] ?? [];
        $demand = $doctrineDemandByType[$typeId] ?? [];
        $meta = $typeMetaById[$typeId] ?? [];
        $itemName = trim((string) (($meta['type_name'] ?? $market['type_name'] ?? $global['type_name'] ?? $missing['item_name'] ?? ('Type #' . $typeId))));
        if ($itemName === '') {
            continue;
        }

        $unitVolume = max(0.0, (float) ($meta['volume'] ?? 0.0));
        $localQty = max(0, (int) ($market['alliance_total_sell_volume'] ?? 0));
        $exactDeficitQuantity = max(0, (int) ($demand['exact_deficit_quantity'] ?? 0));
        $seedFloor = max(0, (int) ($thresholds['min_alliance_sell_volume'] ?? 0) - $localQty);
        $referenceVolume = max(0, (int) ($market['reference_total_sell_volume'] ?? 0));
        $velocityBuffer = max(0, min(500, (int) ceil($referenceVolume * (((bool) ($market['missing_in_alliance'] ?? false)) ? 0.20 : 0.12))));
        $economicRecommendedQuantity = max(0, min(500, max($seedFloor, $velocityBuffer)));
        $blockedFitImpact = max(0, (int) ($demand['deterministic_blocked_fits'] ?? 0));
        $targetReadyFits = max(0, (int) ($demand['target_ready_fits'] ?? 0));
        $activityPressureModifier = max(1.0, (float) ($demand['activity_pressure_modifier'] ?? 1.0));
        $operationalBuffer = $exactDeficitQuantity > 0
            ? (int) ceil($exactDeficitQuantity * max(0.0, min(0.35, $activityPressureModifier - 1.0)))
            : 0;
        $operationalRecommendedQuantity = $exactDeficitQuantity > 0
            ? ($exactDeficitQuantity + $operationalBuffer)
            : ($blockedFitImpact > 0 ? (int) max(1, ceil(((int) ($demand['required_quantity_total'] ?? 0) / max(1, (int) ($demand['valid_fits_count'] ?? 1))) * $blockedFitImpact)) : 0);
        $economicRecommendedQuantity = buy_all_round_quantity(max(0, $economicRecommendedQuantity));
        $operationalRecommendedQuantity = buy_all_round_quantity(max(0, $operationalRecommendedQuantity));
        $finalPlannerQuantity = max($operationalRecommendedQuantity, $economicRecommendedQuantity);
        if ($blockedFitImpact <= 0 && $exactDeficitQuantity <= 0 && $economicRecommendedQuantity <= 0 && !((bool) ($market['missing_in_alliance'] ?? false))) {
            $finalPlannerQuantity = 0;
        }
        if ($unitVolume >= 50000.0 && $finalPlannerQuantity > 5) {
            $finalPlannerQuantity = min($finalPlannerQuantity, 5);
        } elseif ($unitVolume >= 10000.0 && $finalPlannerQuantity > 20) {
            $finalPlannerQuantity = min($finalPlannerQuantity, 20);
        }
        if ($exactDeficitQuantity > 0) {
            $finalPlannerQuantity = max($exactDeficitQuantity, $finalPlannerQuantity);
        }
        if ($finalPlannerQuantity <= 0) {
            continue;
        }

        $buyPrice = null;
        $buyPriceBasis = 'Unknown';
        if (isset($market['reference_best_sell_price']) && $market['reference_best_sell_price'] !== null) {
            $buyPrice = (float) $market['reference_best_sell_price'];
            $buyPriceBasis = 'Hub best sell';
        } elseif (isset($market['reference_best_buy_price']) && $market['reference_best_buy_price'] !== null) {
            $buyPrice = (float) $market['reference_best_buy_price'];
            $buyPriceBasis = 'Hub best buy fallback';
        } elseif (isset($hubHistoryByType[$typeId]['close_price']) && $hubHistoryByType[$typeId]['close_price'] !== null) {
            $buyPrice = (float) $hubHistoryByType[$typeId]['close_price'];
            $buyPriceBasis = 'Hub historical close fallback';
        } elseif (isset($hubHistoryByType[$typeId]['average_price']) && $hubHistoryByType[$typeId]['average_price'] !== null) {
            $buyPrice = (float) $hubHistoryByType[$typeId]['average_price'];
            $buyPriceBasis = 'Hub historical average fallback';
        }

        $sellPrice = null;
        $sellPriceBasis = 'Unknown';
        if (isset($market['alliance_best_sell_price']) && $market['alliance_best_sell_price'] !== null) {
            $sellPrice = (float) $market['alliance_best_sell_price'];
            $sellPriceBasis = 'Alliance best sell';
        } elseif (isset($allianceHistoryByType[$typeId]['close_price']) && $allianceHistoryByType[$typeId]['close_price'] !== null) {
            $sellPrice = (float) $allianceHistoryByType[$typeId]['close_price'];
            $sellPriceBasis = 'Alliance historical close fallback';
        } elseif (isset($allianceHistoryByType[$typeId]['average_price']) && $allianceHistoryByType[$typeId]['average_price'] !== null) {
            $sellPrice = (float) $allianceHistoryByType[$typeId]['average_price'];
            $sellPriceBasis = 'Alliance historical average fallback';
        }

        $haulingCostPerUnit = $unitVolume * buy_all_hauling_cost_per_m3();
        $grossProfitPerUnit = ($buyPrice !== null && $sellPrice !== null) ? ($sellPrice - $buyPrice) : null;
        $netProfitPerUnit = ($buyPrice !== null && $sellPrice !== null) ? ($sellPrice - $buyPrice - $haulingCostPerUnit) : null;
        $grossProfitTotal = $grossProfitPerUnit !== null ? $grossProfitPerUnit * $finalPlannerQuantity : null;
        $netProfitTotal = $netProfitPerUnit !== null ? $netProfitPerUnit * $finalPlannerQuantity : null;
        $grossMarginPercent = ($grossProfitPerUnit !== null && $buyPrice !== null && $buyPrice > 0.0) ? (($grossProfitPerUnit / $buyPrice) * 100.0) : null;
        $netMarginPercent = ($netProfitPerUnit !== null && $buyPrice !== null && $buyPrice > 0.0) ? (($netProfitPerUnit / $buyPrice) * 100.0) : null;
        $volumeEfficiency = ($netProfitTotal !== null && ($finalPlannerQuantity * max(1.0, $unitVolume)) > 0.0) ? ($netProfitTotal / ($finalPlannerQuantity * max(1.0, $unitVolume))) : null;
        $iskEfficiency = ($netProfitTotal !== null && $buyPrice !== null && $buyPrice > 0.0) ? (($netProfitTotal / ($buyPrice * $finalPlannerQuantity)) * 100.0) : null;

        $doctrineFitImpact = max(0, (int) ($demand['valid_fits_count'] ?? 0));
        $bottleneckFitCount = max(0, (int) ($demand['bottleneck_fit_count'] ?? 0));
        $globalPriority = max(0.0, min(100.0, (float) ($global['priority_score'] ?? 0.0)));
        $baseNecessityScore = min(100.0,
            min(40.0, $exactDeficitQuantity * 1.2)
            + min(28.0, $blockedFitImpact * 8.0)
            + min(18.0, $bottleneckFitCount * 9.0)
            + min(12.0, max(0, (int) ($demand['total_target_shortfall'] ?? 0)) * 2.5)
            + min(10.0, (((bool) ($market['missing_in_alliance'] ?? false) || (bool) ($market['weak_alliance_stock'] ?? false)) ? 10.0 : 0.0))
            + min(8.0, $globalPriority * 0.08)
        );
        $necessityScore = min(100.0, round($baseNecessityScore * $activityPressureModifier, 2));

        $profitBase = 0.0;
        if ($netProfitTotal !== null) {
            $profitBase += min(38.0, max(0.0, $netProfitTotal) / 5000000.0 * 38.0);
        }
        if ($netMarginPercent !== null) {
            $profitBase += min(24.0, max(0.0, $netMarginPercent) * 0.9);
        }
        $profitBase += min(22.0, max(0.0, (float) ($market['opportunity_score'] ?? 0.0)) * 0.22);
        if ($volumeEfficiency !== null) {
            $profitBase += min(16.0, max(0.0, $volumeEfficiency) / 250.0 * 16.0);
        }
        $profitScore = min(100.0, max(0.0, $profitBase));

        $modeRankScore = ($necessityScore * (float) ($modeConfig['necessity_weight'] ?? 0.5)) + ($profitScore * (float) ($modeConfig['profit_weight'] ?? 0.5));
        if ($request['mode'] === 'seed_backlog' && ((bool) ($market['missing_in_alliance'] ?? false) || (bool) ($market['weak_alliance_stock'] ?? false))) {
            $modeRankScore += 8.0;
        }
        if ($request['mode'] === 'opportunity' && $netProfitTotal !== null && $netProfitTotal > 0.0) {
            $modeRankScore += 10.0;
        }
        $finalPriorityScore = min(100.0, max(0.0, round($modeRankScore, 2)));
        $blendedScore = min(100.0, max(0.0, round(($necessityScore * 0.56) + ($profitScore * 0.44), 2)));
        $isDoctrineCritical = $exactDeficitQuantity > 0 || $bottleneckFitCount > 0 || $blockedFitImpact > 0;

        $candidate = [
            'item_id' => $typeId,
            'type_id' => $typeId,
            'item_name' => $itemName,
            'quantity' => $finalPlannerQuantity,
            'exact_deficit_quantity' => $exactDeficitQuantity,
            'operational_recommended_quantity' => $operationalRecommendedQuantity,
            'economic_recommended_quantity' => $economicRecommendedQuantity,
            'final_planner_quantity' => $finalPlannerQuantity,
            'buy_price' => $buyPrice,
            'buy_price_basis' => $buyPriceBasis,
            'sell_price' => $sellPrice,
            'sell_price_basis' => $sellPriceBasis,
            'unit_volume' => $unitVolume,
            'total_volume' => $unitVolume * $finalPlannerQuantity,
            'hauling_cost_per_unit' => $haulingCostPerUnit,
            'hauling_cost_total' => $haulingCostPerUnit * $finalPlannerQuantity,
            'gross_profit_per_unit' => $grossProfitPerUnit,
            'net_profit_per_unit' => $netProfitPerUnit,
            'gross_profit_total' => $grossProfitTotal,
            'net_profit_total' => $netProfitTotal,
            'gross_margin_percent' => $grossMarginPercent,
            'net_margin_percent' => $netMarginPercent,
            'necessity_score' => round($necessityScore, 2),
            'profit_score' => round($profitScore, 2),
            'blended_score' => $blendedScore,
            'mode_rank_score' => $finalPriorityScore,
            'final_priority_score' => $finalPriorityScore,
            'doctrine_fit_impact' => $doctrineFitImpact,
            'blocked_fit_impact' => $blockedFitImpact,
            'deterministic_blocked_fits' => $blockedFitImpact,
            'bottleneck_fit_count' => $bottleneckFitCount,
            'reason_code' => '',
            'reason_text' => '',
            'reason_theme' => '',
            'is_doctrine_linked' => $doctrineFitImpact > 0 || !empty($global['is_doctrine_item']),
            'is_doctrine_critical' => $isDoctrineCritical,
            'hull_class' => (string) ($demand['hull_class'] ?? 'subcap'),
            'hull_class_label' => (string) ($demand['hull_class_label'] ?? 'Subcap'),
            'valid_doctrine_count' => max(0, (int) ($demand['valid_doctrine_count'] ?? 0)),
            'valid_fits_count' => max(0, (int) ($demand['valid_fits_count'] ?? 0)),
            'target_ready_fits' => $targetReadyFits,
            'activity_pressure_modifier' => $activityPressureModifier,
            'exact_deficit_fit_count' => max(0, (int) ($demand['exact_deficit_fit_count'] ?? 0)),
            'missing_in_alliance' => (bool) ($market['missing_in_alliance'] ?? false),
            'weak_alliance_stock' => (bool) ($market['weak_alliance_stock'] ?? false),
            'opportunity_score' => (int) ($market['opportunity_score'] ?? 0),
            'risk_score' => (int) ($market['risk_score'] ?? 0),
            'volume_score' => (int) ($market['volume_score'] ?? 0),
            'volume_efficiency' => $volumeEfficiency,
            'isk_efficiency' => $iskEfficiency,
            'linked_fit_names' => array_values((array) ($demand['valid_fit_names'] ?? [])),
            'linked_group_names' => array_values((array) ($demand['valid_doctrine_names'] ?? [])),
            'affected_fits' => array_values((array) ($demand['affected_fits'] ?? [])),
            'pricing_completeness' => $buyPrice !== null && $sellPrice !== null ? 'complete' : 'partial',
            'hub_price_observed_at' => $market['reference_last_observed_at'] ?? ($hubHistoryByType[$typeId]['observed_at'] ?? null),
            'alliance_price_observed_at' => $market['alliance_last_observed_at'] ?? ($allianceHistoryByType[$typeId]['observed_at'] ?? null),
            'stock_observed_at' => $market['alliance_last_observed_at'] ?? null,
        ];
        $reason = buy_all_reason_meta($candidate);
        $candidate['reason_code'] = $reason['code'];
        $candidate['reason_text'] = $reason['text'];
        $candidate['reason_theme'] = $reason['theme'];

        $filters = $request['filters'];
        if ($filters['doctrine_linked_only'] && empty($candidate['is_doctrine_linked'])) {
            continue;
        }
        if ($filters['exclude_incomplete_pricing'] && $candidate['pricing_completeness'] !== 'complete' && !$candidate['is_doctrine_critical']) {
            continue;
        }
        if ($filters['positive_net_margin_only']) {
            $hasPositiveMargin = $candidate['net_margin_percent'] !== null && (float) $candidate['net_margin_percent'] > 0.0;
            if (!$hasPositiveMargin && !($filters['allow_low_margin_doctrine_critical'] && $candidate['is_doctrine_critical'])) {
                continue;
            }
        }
        if (!$filters['allow_low_margin_doctrine_critical'] && $candidate['net_margin_percent'] !== null && (float) $candidate['net_margin_percent'] <= 0.0 && $candidate['is_doctrine_critical']) {
            continue;
        }
        if ($filters['exclude_oversized_low_efficiency'] && $candidate['total_volume'] > 100000.0 && (($candidate['volume_efficiency'] ?? null) === null || (float) ($candidate['volume_efficiency'] ?? 0.0) <= 0.0) && !$candidate['is_doctrine_critical']) {
            continue;
        }
        if ((float) ($candidate['mode_rank_score'] ?? 0.0) < (float) $filters['min_priority_threshold']) {
            continue;
        }
        if ($candidate['net_margin_percent'] !== null && (float) ($candidate['net_margin_percent'] ?? 0.0) < (float) $filters['min_net_margin_threshold'] && !$candidate['is_doctrine_critical']) {
            continue;
        }
        if ($candidate['net_profit_total'] !== null && (float) ($candidate['net_profit_total'] ?? 0.0) < (float) $filters['min_net_profit_threshold'] && !$candidate['is_doctrine_critical']) {
            continue;
        }
        if ($candidate['net_profit_total'] === null && $request['mode'] === 'opportunity' && !$candidate['is_doctrine_critical']) {
            continue;
        }

        $rankedItems[] = $candidate;
    }

    usort($rankedItems, static fn (array $a, array $b): int => buy_all_compare_items($a, $b, (string) ($request['sort'] ?? 'blended_score'), (string) ($request['mode'] ?? 'blended')));
    foreach ($rankedItems as $index => &$item) {
        $item['rank_position'] = $index + 1;
    }
    unset($item);

    $packed = buy_all_pack_pages($rankedItems);
    $pages = $packed['pages'];
    $pageCount = count($pages);
    $activePage = $pageCount > 0 ? min($request['page'], $pageCount) : 1;
    $summary = [
        'generated_at' => gmdate(DATE_ATOM),
        'mode' => $request['mode'],
        'mode_label' => (string) ($modeConfig['label'] ?? ucfirst(str_replace('_', ' ', $request['mode']))),
        'page_count' => $pageCount,
        'candidate_count' => count($rankedItems),
        'total_item_types' => count($rankedItems),
        'total_units' => array_sum(array_map(static fn (array $row): int => (int) ($row['quantity'] ?? 0), $rankedItems)),
        'total_volume' => array_sum(array_map(static fn (array $row): float => (float) ($row['total_volume'] ?? 0.0), $rankedItems)),
        'total_buy_cost' => array_sum(array_map(static fn (array $row): float => (float) ($row['buy_price'] !== null ? ((float) $row['buy_price'] * (int) ($row['quantity'] ?? 0)) : 0.0), $rankedItems)),
        'total_expected_sell_value' => array_sum(array_map(static fn (array $row): float => (float) ($row['sell_price'] !== null ? ((float) $row['sell_price'] * (int) ($row['quantity'] ?? 0)) : 0.0), $rankedItems)),
        'total_hauling_cost' => array_sum(array_map(static fn (array $row): float => (float) ($row['hauling_cost_total'] ?? 0.0), $rankedItems)),
        'total_gross_profit' => array_sum(array_map(static fn (array $row): float => (float) ($row['gross_profit_total'] ?? 0.0), $rankedItems)),
        'total_net_profit' => array_sum(array_map(static fn (array $row): float => (float) ($row['net_profit_total'] ?? 0.0), $rankedItems)),
        'doctrine_critical_count' => count(array_filter($rankedItems, static fn (array $row): bool => !empty($row['is_doctrine_critical']))),
        'partial_pricing_count' => count(array_filter($rankedItems, static fn (array $row): bool => (string) ($row['pricing_completeness'] ?? 'partial') !== 'complete')),
        'positive_net_margin_count' => count(array_filter($rankedItems, static fn (array $row): bool => isset($row['net_margin_percent']) && (float) ($row['net_margin_percent'] ?? 0.0) > 0.0)),
        'top_reason_theme' => (string) (($rankedItems[0]['reason_theme'] ?? 'Mixed signals')),
    ];

    $hubFreshness = supplycore_page_freshness_view_model((array) ($marketOutcomes['_freshness'] ?? []));
    $doctrineFreshness = supplycore_page_freshness_view_model((array) ($doctrineSnapshot['_freshness'] ?? []));
    $stockFreshness = $hubFreshness;
    if ($marketRows !== []) {
        $timestamps = array_values(array_filter(array_map(static fn (array $row): ?string => isset($row['alliance_last_observed_at']) ? (string) $row['alliance_last_observed_at'] : null, $marketRows)));
        rsort($timestamps);
        $latestStock = $timestamps[0] ?? null;
        $stockFreshness = [
            'state' => $latestStock !== null && (time() - (strtotime($latestStock) ?: 0)) <= supplycore_summary_stale_after_seconds() ? 'fresh' : 'stale',
            'label' => $latestStock !== null && (time() - (strtotime($latestStock) ?: 0)) <= supplycore_summary_stale_after_seconds() ? 'Fresh' : 'Stale',
            'computed_at' => supplycore_format_datetime($latestStock),
            'computed_relative' => supplycore_relative_datetime($latestStock),
            'tone' => $latestStock !== null && (time() - (strtotime($latestStock) ?: 0)) <= supplycore_summary_stale_after_seconds() ? 'border-emerald-400/20 bg-emerald-500/10 text-emerald-100' : 'border-amber-400/20 bg-amber-500/10 text-amber-100',
            'message' => 'Alliance stock freshness for the current planner inputs.',
            'reason' => '',
        ];
    }

    return [
        'request' => $request,
        'mode_options' => $modeDefinitions,
        'sort_options' => buy_all_sort_options(),
        'summary' => $summary,
        'items' => $rankedItems,
        'pages' => $pages,
        'active_page' => $activePage,
        'active_page_data' => $pages[$activePage - 1] ?? null,
        'excluded_items' => $packed['excluded_items'] ?? [],
        'freshness' => [
            'hub_pricing' => $hubFreshness,
            'alliance_pricing' => $stockFreshness,
            'stock' => $stockFreshness,
            'doctrine' => $doctrineFreshness,
            'generated_at' => supplycore_format_datetime($summary['generated_at']),
            'generated_relative' => supplycore_relative_datetime($summary['generated_at']),
        ],
        'price_basis' => [
            'buy' => 'Hub buy basis uses hub best sell first, then hub best buy, then hub historical close/average fallback.',
            'sell' => 'Alliance sell basis uses alliance best sell first, then alliance historical close, then alliance historical average fallback.',
        ],
        'hauling' => [
            'cost_per_m3' => buy_all_hauling_cost_per_m3(),
            'page_volume_limit' => buy_all_page_volume_limit(),
            'page_item_type_limit' => buy_all_page_item_type_limit(),
        ],
    ];
}

function buy_all_dashboard_summary(): array
{
    $planner = buy_all_planner_data(['mode' => 'blended', 'page' => 1]);
    $summary = is_array($planner['summary'] ?? null) ? $planner['summary'] : [];
    $recommendedMode = 'blended';
    if ((int) ($summary['doctrine_critical_count'] ?? 0) > 0) {
        $recommendedMode = 'doctrine_critical';
    } elseif ((float) ($summary['total_net_profit'] ?? 0.0) > 0.0 && (int) ($summary['positive_net_margin_count'] ?? 0) >= 6) {
        $recommendedMode = 'opportunity';
    }
    $modes = buy_all_mode_definitions();

    return [
        'recommended_mode' => $recommendedMode,
        'recommended_mode_label' => (string) (($modes[$recommendedMode]['label'] ?? ucfirst($recommendedMode))),
        'pages' => (int) ($summary['page_count'] ?? 0),
        'total_planned_volume' => (float) ($summary['total_volume'] ?? 0.0),
        'expected_net_profit' => (float) ($summary['total_net_profit'] ?? 0.0),
        'doctrine_critical_count' => (int) ($summary['doctrine_critical_count'] ?? 0),
        'top_reason_theme' => (string) ($summary['top_reason_theme'] ?? 'Mixed signals'),
        'planner_href' => '/buy-all?mode=' . urlencode($recommendedMode) . '&page=1',
        'blended_href' => '/buy-all?mode=blended&page=1',
        'summary' => $summary,
    ];
}

function activity_priority_level_from_score(float $score): string
{
    if ($score >= 78.0) {
        return 'highly active';
    }
    if ($score >= 56.0) {
        return 'active';
    }
    if ($score >= 32.0) {
        return 'moderate';
    }

    return 'low';
}

function activity_priority_item_band(float $score): string
{
    if ($score >= 82.0) {
        return 'critical';
    }
    if ($score >= 66.0) {
        return 'high';
    }
    if ($score >= 44.0) {
        return 'elevated';
    }

    return 'watch';
}

function activity_priority_level_tone(string $level): string
{
    return match ($level) {
        'highly active', 'critical' => 'border-rose-400/20 bg-rose-500/10 text-rose-100',
        'active', 'high' => 'border-orange-400/20 bg-orange-500/10 text-orange-100',
        'moderate', 'elevated' => 'border-amber-400/20 bg-amber-500/10 text-amber-100',
        default => 'border-slate-400/15 bg-slate-500/10 text-slate-200',
    };
}

function activity_priority_repeated_usage_weight(float $window24h, float $window3d, float $window7d): float
{
    $activeWindows = 0;
    foreach ([$window24h, $window3d, $window7d] as $value) {
        if ($value > 0) {
            $activeWindows++;
        }
    }

    $carryForward = max(0.0, $window3d - $window24h) + max(0.0, $window7d - $window3d);

    return round(min(16.0, ($activeWindows * 3.5) + ($carryForward * 2.2)), 2);
}

function activity_priority_recency_weight(float $window24h, float $window3d, float $window7d): float
{
    if ($window24h > 0) {
        return min(18.0, 10.0 + ($window24h * 2.2));
    }
    if ($window3d > 0) {
        return min(12.0, 6.0 + ($window3d * 1.1));
    }
    if ($window7d > 0) {
        return min(6.0, 2.5 + ($window7d * 0.4));
    }

    return 0.0;
}

function activity_priority_pressure_bonus(string $pressureState): float
{
    return match ($pressureState) {
        'urgent_resupply' => 8.0,
        'resupply_soon' => 6.0,
        'elevated' => 3.0,
        default => 0.0,
    };
}

function activity_priority_item_history_index(array $typeIds): array
{
    $normalizedTypeIds = array_values(array_unique(array_filter(array_map('intval', $typeIds), static fn (int $typeId): bool => $typeId > 0)));
    if ($normalizedTypeIds === []) {
        return [];
    }

    $allianceStructureId = configured_structure_destination_id_for_esi_sync();
    $hubRef = market_hub_setting_reference();
    $hubSourceId = sync_source_id_from_hub_ref($hubRef);

    try {
        if ($allianceStructureId > 0) {
            return doctrine_local_history_index(
                db_market_orders_history_stock_health_series(
                    'alliance_structure',
                    $allianceStructureId,
                    gmdate('Y-m-d', strtotime('-14 days')),
                    gmdate('Y-m-d'),
                    $normalizedTypeIds
                )
            );
        }

        if ($hubSourceId > 0) {
            return doctrine_local_history_index(
                db_market_hub_local_history_daily_window_by_type_ids(
                    market_hub_local_history_source(),
                    $hubSourceId,
                    $normalizedTypeIds,
                    14
                )
            );
        }
    } catch (Throwable) {
        return [];
    }

    return [];
}

function activity_priority_fit_item_windows(array $items, array $itemLossByType): array
{
    $moduleLosses24h = 0;
    $moduleLosses3d = 0;
    $moduleLosses7d = 0;
    $equivalent24h = 0.0;
    $equivalent3d = 0.0;
    $equivalent7d = 0.0;

    foreach ($items as $item) {
        $typeId = max(0, (int) ($item['type_id'] ?? 0));
        $requiredQty = max(1, (int) ($item['quantity'] ?? 1));
        if ($typeId <= 0) {
            continue;
        }

        $loss = $itemLossByType[$typeId] ?? [];
        $qty24h = max(0, (int) ($loss['quantity_24h'] ?? 0));
        $qty3d = max(0, (int) ($loss['quantity_3d'] ?? 0));
        $qty7d = max(0, (int) ($loss['quantity_7d'] ?? 0));

        $moduleLosses24h += $qty24h;
        $moduleLosses3d += $qty3d;
        $moduleLosses7d += $qty7d;
        $equivalent24h = max($equivalent24h, $qty24h / $requiredQty);
        $equivalent3d = max($equivalent3d, $qty3d / $requiredQty);
        $equivalent7d = max($equivalent7d, $qty7d / $requiredQty);
    }

    return [
        'module_losses_24h' => $moduleLosses24h,
        'module_losses_3d' => $moduleLosses3d,
        'module_losses_7d' => $moduleLosses7d,
        'fit_equivalent_losses_24h' => round($equivalent24h, 2),
        'fit_equivalent_losses_3d' => round($equivalent3d, 2),
        'fit_equivalent_losses_7d' => round($equivalent7d, 2),
    ];
}

function activity_priority_doctrine_explanation(array $row): string
{
    $parts = [];
    if ((int) ($row['hull_losses_24h'] ?? 0) > 0 || (int) ($row['hull_losses_7d'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['hull_losses_24h'] ?? 0)) . ' hull losses in 24h and ' . doctrine_format_quantity((int) ($row['hull_losses_7d'] ?? 0)) . ' in 7d';
    }
    if ((float) ($row['fit_equivalent_losses_7d'] ?? 0.0) > 0) {
        $parts[] = number_format((float) ($row['fit_equivalent_losses_7d'] ?? 0.0), 1) . ' fit-equivalent module losses over 7d';
    }
    if ((int) ($row['readiness_gap_count'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['readiness_gap_count'] ?? 0)) . ' fit gaps still open locally';
    }
    if (((string) ($row['resupply_pressure_state'] ?? 'stable')) !== 'stable') {
        $parts[] = 'resupply pressure is ' . strtolower((string) ($row['resupply_pressure'] ?? 'elevated'));
    }

    return ucfirst(implode(' · ', array_slice($parts, 0, 4))) . ($parts === [] ? 'No recent tracked loss pressure is pushing this doctrine higher right now.' : '.');
}

function activity_priority_item_explanation(array $row): string
{
    $parts = [];
    if ((bool) ($row['is_doctrine_linked'] ?? false)) {
        $parts[] = 'valid for ' . doctrine_format_quantity((int) ($row['valid_fits_count'] ?? $row['linked_doctrine_count'] ?? 0)) . ' fits across ' . doctrine_format_quantity((int) ($row['valid_doctrine_count'] ?? 0)) . ' doctrines';
    }
    if ((int) ($row['linked_active_doctrine_count'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['linked_active_doctrine_count'] ?? 0)) . ' linked doctrines are active now';
    }
    if ((int) ($row['deterministic_blocked_fits'] ?? 0) > 0) {
        $parts[] = 'deterministically blocks ' . doctrine_format_quantity((int) ($row['deterministic_blocked_fits'] ?? 0)) . ' target fits';
    } elseif ((int) ($row['exact_deficit_quantity'] ?? 0) > 0) {
        $parts[] = 'exact doctrine deficit is ' . doctrine_format_quantity((int) ($row['exact_deficit_quantity'] ?? 0)) . ' units';
    }
    if ((int) ($row['recent_loss_qty_24h'] ?? 0) > 0 || (int) ($row['recent_loss_qty_7d'] ?? 0) > 0) {
        $parts[] = doctrine_format_quantity((int) ($row['recent_loss_qty_24h'] ?? 0)) . ' units lost in 24h and ' . doctrine_format_quantity((int) ($row['recent_loss_qty_7d'] ?? 0)) . ' in 7d';
    }
    if ((int) ($row['local_sell_volume'] ?? 0) <= 0) {
        $parts[] = 'no local sell stock currently listed';
    } elseif ((string) ($row['depletion_state'] ?? 'stable') === 'draining') {
        $parts[] = 'local stock is draining versus the prior window';
    }
    if ((float) ($row['activity_pressure_modifier'] ?? 1.0) > 1.05) {
        $parts[] = 'activity modifier is ' . number_format((float) ($row['activity_pressure_modifier'] ?? 1.0), 2) . 'x for this hull family';
    }

    return ucfirst(implode(' · ', array_slice($parts, 0, 5))) . ($parts === [] ? 'Signals are steady, so the item remains on watch rather than elevated.' : '.');
}

function activity_priority_movement_label(int $rankDelta, float $scoreDelta): string
{
    if ($rankDelta >= 5 || $scoreDelta >= 12.0) {
        return 'Rising fast';
    }
    if ($rankDelta > 0 || $scoreDelta > 4.0) {
        return 'Moving up';
    }
    if ($rankDelta <= -5 || $scoreDelta <= -12.0) {
        return 'Cooling down';
    }
    if ($rankDelta < 0 || $scoreDelta < -4.0) {
        return 'Softening';
    }

    return 'Holding';
}

function activity_priority_summary_build(string $reason = 'manual'): array
{
    $doctrineSnapshot = doctrine_snapshot_cache_payload();
    if ($doctrineSnapshot === null) {
        $doctrineSnapshot = doctrine_refresh_intelligence($reason . ':bootstrap');
    }

    $marketOutcomes = market_comparison_outcomes();
    $marketRows = array_values((array) ($marketOutcomes['rows'] ?? []));
    $marketByTypeId = [];
    foreach ($marketRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId > 0) {
            $marketByTypeId[$typeId] = $row;
        }
    }

    $fits = array_values((array) ($doctrineSnapshot['fits'] ?? []));
    $groups = array_values((array) ($doctrineSnapshot['groups'] ?? []));
    $fitIds = array_values(array_filter(array_map(static fn (array $fit): int => (int) ($fit['id'] ?? 0), $fits), static fn (int $fitId): bool => $fitId > 0));

    $itemsByFitId = [];
    $doctrineTypeIds = [];
    try {
        foreach (db_doctrine_fit_items_by_fit_ids($fitIds) as $item) {
            $fitId = (int) ($item['doctrine_fit_id'] ?? 0);
            $typeId = (int) ($item['type_id'] ?? 0);
            if ($fitId <= 0 || $typeId <= 0 || !item_scope_is_type_id_in_scope($typeId)) {
                continue;
            }

            $itemsByFitId[$fitId][] = $item;
            $doctrineTypeIds[] = $typeId;
        }
    } catch (Throwable) {
        $itemsByFitId = [];
    }

    $enabledTypeIds = array_values(array_unique(array_merge(array_keys($marketByTypeId), $doctrineTypeIds)));
    $itemLossRows = [];
    $hullLossRows = [];
    try {
        $itemLossRows = db_killmail_tracked_recent_item_activity_windows($enabledTypeIds, 24 * 7);
    } catch (Throwable) {
        $itemLossRows = [];
    }
    try {
        $hullLossRows = db_killmail_tracked_recent_hull_activity_windows(
            array_values(array_filter(array_map(static fn (array $fit): int => (int) ($fit['ship_type_id'] ?? 0), $fits), static fn (int $typeId): bool => $typeId > 0)),
            24 * 7
        );
    } catch (Throwable) {
        $hullLossRows = [];
    }

    $itemLossByType = doctrine_item_loss_index($itemLossRows);
    foreach ($itemLossRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId <= 0) {
            continue;
        }
        $itemLossByType[$typeId]['quantity_3d'] = max(0, (int) ($row['quantity_3d'] ?? 0));
        $itemLossByType[$typeId]['losses_3d'] = max(0, (int) ($row['losses_3d'] ?? 0));
    }
    $hullLossByType = doctrine_hull_loss_index($hullLossRows);
    foreach ($hullLossRows as $row) {
        $typeId = (int) ($row['type_id'] ?? 0);
        if ($typeId <= 0) {
            continue;
        }
        $hullLossByType[$typeId]['losses_3d'] = max(0, (int) ($row['losses_3d'] ?? 0));
    }

    $historyByTypeId = activity_priority_item_history_index($enabledTypeIds);
    $depletionByType = doctrine_item_depletion_index($historyByTypeId);

    $previousFitSnapshots = [];
    foreach (db_doctrine_activity_latest_snapshots('fit', $fitIds) as $row) {
        $previousFitSnapshots[(int) ($row['entity_id'] ?? 0)] = $row;
    }

    $fitRows = [];
    foreach ($fits as $fit) {
        $fitId = (int) ($fit['id'] ?? 0);
        $supply = is_array($fit['supply'] ?? null) ? $fit['supply'] : [];
        $shipTypeId = (int) ($fit['ship_type_id'] ?? 0);
        $hull = $hullLossByType[$shipTypeId] ?? [];
        $itemWindows = activity_priority_fit_item_windows($itemsByFitId[$fitId] ?? [], $itemLossByType);

        $hullPressure = min(38.0, ((int) ($hull['losses_24h'] ?? 0) * 16.0) + max(0, ((int) ($hull['losses_3d'] ?? 0) - (int) ($hull['losses_24h'] ?? 0)) * 5.5) + max(0, ((int) ($hull['losses_7d'] ?? 0) - (int) ($hull['losses_3d'] ?? 0)) * 3.0));
        $modulePressure = min(24.0, ((float) ($itemWindows['fit_equivalent_losses_24h'] ?? 0.0) * 8.5) + max(0.0, ((float) ($itemWindows['fit_equivalent_losses_3d'] ?? 0.0) - (float) ($itemWindows['fit_equivalent_losses_24h'] ?? 0.0)) * 4.0) + max(0.0, ((float) ($itemWindows['fit_equivalent_losses_7d'] ?? 0.0) - (float) ($itemWindows['fit_equivalent_losses_3d'] ?? 0.0)) * 2.4));
        $recencyWeight = activity_priority_recency_weight(
            max((float) ($hull['losses_24h'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_24h'] ?? 0.0)),
            max((float) ($hull['losses_3d'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_3d'] ?? 0.0)),
            max((float) ($hull['losses_7d'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_7d'] ?? 0.0))
        );
        $repeatedUsage = activity_priority_repeated_usage_weight(
            max((float) ($hull['losses_24h'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_24h'] ?? 0.0)),
            max((float) ($hull['losses_3d'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_3d'] ?? 0.0)),
            max((float) ($hull['losses_7d'] ?? 0), (float) ($itemWindows['fit_equivalent_losses_7d'] ?? 0.0))
        );
